INSERT INTO public.questions VALUES ('95f82abb-8389-4527-b322-759fc9ac799d', 'cd48a8aa-43cb-49d6-977b-9e26b1dc866e', 'matrix', 'Questions 16-20', NULL, '<p>Label the map below.</p>
<p>Choose the correct letter, A–I, next to questions 16–20.</p>
<p><img src="data:image/png;base64," width="443" height="465" loading="lazy"></p>', 'other', 'null', 'null', 'null', '{"layoutType": "simple", "legendTitle": null, "matrixItems": [{"itemText": "Workshop", "correctCategoryLetter": "G"}, {"itemText": "Lunchroom", "correctCategoryLetter": "B"}, {"itemText": "Farm Office ", "correctCategoryLetter": "H"}, {"itemText": "First Aid Room", "correctCategoryLetter": "F"}, {"itemText": "Store Shed", "correctCategoryLetter": "C"}], "matrixCategories": [{"categoryText": "A", "categoryLetter": "A"}, {"categoryText": "B", "categoryLetter": "B"}, {"categoryText": "C", "categoryLetter": "C"}, {"categoryText": "D", "categoryLetter": "D"}, {"categoryText": "E", "categoryLetter": "E"}, {"categoryText": "F", "categoryLetter": "F"}, {"categoryText": "G", "categoryLetter": "G"}, {"categoryText": "H", "categoryLetter": "H"}, {"categoryText": "I", "categoryLetter": "I"}]}', '[{"content": "<p>1</p>\n"}]', 1);
INSERT INTO public.questions VALUES ('4ab64234-2aa8-4105-867c-1135a17dedf7', 'f41a1990-06b7-4b6b-8774-ba668ad5a476', 'radio', 'Questions 27-30', '', '<p>Choose the correct letter, <strong>A</strong>, <strong>B</strong>, <strong>C </strong>or <strong>D</strong>.</p>', 'multiple_choice', '[{"correct": 3, "options": [{"option_text": "A has a slightly inappropriate name."}, {"option_text": "B may prove too big for the town of Leicester."}, {"option_text": "C was not solely designed for theatrical purposes."}, {"option_text": "D may challenge the achievements of other famous theatres."}], "question": "In the first paragraph, the writer says that the Curve Theatre"}, {"correct": 0, "options": [{"option_text": "A the relatively large sum of money spent constructing it"}, {"option_text": "B the number of important people promoting it"}, {"option_text": "C the complicated design process"}, {"option_text": "D the architect''s popularity"}], "question": "According to the writer, what may have contributed to the attention the Curve Theatre is getting?"}, {"correct": 2, "options": [{"option_text": "A the population of Leicester."}, {"option_text": "B people''s opinions of Leicester."}, {"option_text": "C town planning in certain parts of Leicester."}, {"option_text": "D artistic pursuits among the people of Leicester."}], "question": "The writer uses the phrase \"lights the touch-paper\" in the fourth paragraph to suggest that the Curve Theatre will spark a change in"}, {"correct": 0, "options": [{"option_text": "A has altered people''s views of what a theatre can be"}, {"option_text": "B marks a departure from modernist architecture"}, {"option_text": "C is more noticeable during the daytime."}, {"option_text": "D aims to provide better facilities for actors."}], "question": "In the fifth paragraph, the writer says it is clear that the Curve Theatre"}]', 'null', 'null', 'null', '[{"content": "<p data-path-to-node=\"4\"><strong data-path-to-node=\"4\" data-index-in-node=\"0\">27. In the first paragraph, the writer says that the Curve Theatre — {D} may challenge the achievements of other famous theatres.</strong></p>\n<ul data-path-to-node=\"5\">\n<li>\n<p data-path-to-node=\"5,0,0\"><strong data-path-to-node=\"5,0,0\" data-index-in-node=\"0\">Trích dẫn:</strong> “…technical sophistication equals, and may even <strong data-path-to-node=\"5,0,0\" data-index-in-node=\"61\">surpass, the National Theatre in London</strong>… has given other great theatrical establishments in Britain <strong data-path-to-node=\"5,0,0\" data-index-in-node=\"163\">serious pause for thought</strong>.” (Đoạn 1)</p>\n</li>\n<li>\n<p data-path-to-node=\"5,1,0\"><strong data-path-to-node=\"5,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Việc nhà hát này có kỹ thuật tương đương hoặc vượt qua cả Nhà hát Quốc gia tại London và khiến các cơ sở lớn khác phải “suy ngẫm” chính là sự thách thức đối với thành tựu của họ.</p>\n</li>\n</ul>\n<p data-path-to-node=\"6\"><strong data-path-to-node=\"6\" data-index-in-node=\"0\">28. According to the writer, what may have contributed to the attention the Curve Theatre is getting? — {A} the relatively large sum of money spent constructing it.</strong></p>\n<ul data-path-to-node=\"7\">\n<li>\n<p data-path-to-node=\"7,0,0\"><strong data-path-to-node=\"7,0,0\" data-index-in-node=\"0\">Trích dẫn:</strong> “When a city this size <strong data-path-to-node=\"7,0,0\" data-index-in-node=\"34\">commits £61m to a single arts building</strong>, people take notice.” (Đoạn 2)</p>\n</li>\n<li>\n<p data-path-to-node=\"7,1,0\"><strong data-path-to-node=\"7,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Tác giả nhấn mạnh việc một thành phố quy mô như Leicester chi tới 61 triệu bảng cho một tòa nhà nghệ thuật duy nhất là lý do khiến mọi người chú ý.</p>\n</li>\n</ul>\n<p data-path-to-node=\"8\"><strong data-path-to-node=\"8\" data-index-in-node=\"0\">29. The writer uses the phrase “lights the touch-paper” … to suggest that the Curve Theatre will spark a change in — {C} town planning in certain parts of Leicester.</strong></p>\n<ul data-path-to-node=\"9\">\n<li>\n<p data-path-to-node=\"9,0,0\"><strong data-path-to-node=\"9,0,0\" data-index-in-node=\"0\">Trích dẫn:</strong> “…lights the touch-paper for <strong data-path-to-node=\"9,0,0\" data-index-in-node=\"42\">urban regeneration in the centre</strong> of this busy, but possibly outdated, place.” (Đoạn 4)</p>\n</li>\n<li>\n<p data-path-to-node=\"9,1,0\"><strong data-path-to-node=\"9,1,0\" data-index-in-node=\"0\">Giải thích:</strong> “Urban regeneration” (tái thiết đô thị) là một khía cạnh của quy hoạch thành phố (<em data-path-to-node=\"9,1,0\" data-index-in-node=\"94\">town planning</em>). Cụm từ “ngòi nổ” (<em data-path-to-node=\"9,1,0\" data-index-in-node=\"128\">lights the touch-paper</em>) ngụ ý nhà hát sẽ là động lực thúc đẩy sự thay đổi bộ mặt đô thị tại trung tâm Leicester.</p>\n</li>\n</ul>\n<p data-path-to-node=\"10\"><strong data-path-to-node=\"10\" data-index-in-node=\"0\">30. In the fifth paragraph, the writer says it is clear that the Curve Theatre — {A} has altered people’s views of what a theatre can be.</strong></p>\n<ul data-path-to-node=\"11\">\n<li>\n<p data-path-to-node=\"11,0,0\"><strong data-path-to-node=\"11,0,0\" data-index-in-node=\"0\">Trích dẫn:</strong> “The Curve has plainly set a <strong data-path-to-node=\"11,0,0\" data-index-in-node=\"40\">new benchmark in terms of how a theatre is perceived</strong>…” (Đoạn 5)</p>\n</li>\n<li>\n<p data-path-to-node=\"11,1,0\"><strong data-path-to-node=\"11,1,0\" data-index-in-node=\"0\">Giải thích:</strong> “Set a new benchmark in how it is perceived” (thiết lập một chuẩn mực mới trong cách nhìn nhận/nhận thức) đồng nghĩa với việc thay đổi quan điểm của mọi người về định nghĩa một nhà hát.</p>\n</li>\n</ul>"}]', 0);
INSERT INTO public.questions VALUES ('2bad4499-3d76-4cf0-b76a-a145c8915e04', '6c0f8326-70f9-4ac7-8ac4-78a68c4be772', 'checkbox', 'Questions 22-23', NULL, '<p>Choose <strong>TWO </strong>correct answers.</p>
<p>The list below identifies some of the possible aims of urban redevelopment projects.</p>
<p>Which <strong>TWO </strong>things did the State of Berlin hope to achieve with the Gleisdreieck development?</p>
', 'multiple-select', 'null', '[{"option": "to bring people of different ages together", "correct": true}, {"option": "to encourage tourism", "correct": false}, {"option": "to improve transport links", "correct": false}, {"option": "to preserve industrial remains", "correct": true}, {"option": "to generate income for the city", "correct": false}]', 'null', 'null', '[{"content": "<h3 data-path-to-node=\"26\">22-23. Which TWO things did the State of Berlin hope to achieve with the Gleisdreieck development? (Chọn 2)</h3>\n<ul data-path-to-node=\"27\">\n<li>\n<p data-path-to-node=\"27,0,0\"><strong>Đáp án:</strong></p>\n<ol start=\"1\" data-path-to-node=\"27,0,1\">\n<li>\n<p data-path-to-node=\"27,0,1,0,0\"><strong>to bring people of different ages together.</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"27,0,1,1,0\"><strong>to preserve industrial remains.</strong></p>\n</li>\n</ol>\n</li>\n<li>\n<p data-path-to-node=\"27,1,0\"><strong>Dẫn chứng:</strong> (Đoạn 3) Dự án nhằm “integrating <strong>different generations and social groups</strong> in sustainable way” và “the <strong>conservation of railway heritage</strong> also emerged.”</p>\n</li>\n<li>\n<p data-path-to-node=\"27,2,0\"><strong>Giải thích:</strong> Hai mục tiêu chính là <strong>tích hợp các thế hệ và nhóm xã hội</strong> khác nhau và <strong>bảo tồn di sản đường sắt</strong> (industrial remains).</p>\n</li>\n</ul>\n"}]', 2);
INSERT INTO public.questions VALUES ('612ed6bc-d10d-42e7-bb09-ebcaf154a358', '6c0f8326-70f9-4ac7-8ac4-78a68c4be772', 'fillup', 'Questions 24-26', '<p>Complete the summary below.</p>
<p>Write <strong>ONE WORD ONLY</strong> from the passage for each answer.</p>
<p style="text-align: center;">
<span style="font-size: 12pt;"><strong>Gleisdreieck Urban Park</strong></span></p>
<p>In the middle of the new park is a {meadow} , where there is a path for pedestrians and two railway lines. A slow train uses these lines to make a regular journey between its based and a {museum} . Benches have been provided on the north side, so that people can relax and enjoy the sunshine, and to the east is an area with mature trees of various kinds, as well as sets of swings. A range of sports and leisure areas are situated around the {edges} of the site.</p>
', NULL, 'gap_filling', 'null', 'null', 'null', 'null', '[{"content": "<h3 data-path-to-node=\"29\">24. In the middle of the new park is a <strong>meadow</strong>, where there is a path for pedestrians and two railway lines.</h3>\n<ul data-path-to-node=\"30\">\n<li>\n<p data-path-to-node=\"30,0,0\"><strong>Đáp án:</strong> <strong>meadow</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"30,1,0\"><strong>Dẫn chứng:</strong> (Đoạn 4) &#8220;The project as a whole was planned around a large central <strong>meadow</strong>, intersected from east to west by a concrete footpath, and from north to south by a pair of railway lines.&#8221;</p>\n</li>\n<li>\n<p data-path-to-node=\"30,2,0\"><strong>Giải thích:</strong> Công viên được thiết kế xung quanh một <strong>đồng cỏ</strong> trung tâm lớn, có đường đi bộ và đường ray cắt qua.</p>\n</li>\n</ul>\n<h3 data-path-to-node=\"32\">25. A slow train uses these lines to make a regular journey between its based and a <strong>museum</strong>.</h3>\n<ul data-path-to-node=\"33\">\n<li>\n<p data-path-to-node=\"33,0,0\"><strong>Đáp án:</strong> <strong>museum</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"33,1,0\"><strong>Dẫn chứng:</strong> (Đoạn 4) &#8220;Once a month, a train slowly travels along these lines from its parking shed to <strong>German Museum of Technology</strong>.&#8221;</p>\n</li>\n<li>\n<p data-path-to-node=\"33,2,0\"><strong>Giải thích:</strong> Chuyến tàu thường xuyên đi đến Bảo tàng Công nghệ Đức (<strong>museum</strong>).</p>\n</li>\n</ul>\n<h3 data-path-to-node=\"35\">26. A range of sports and leisure areas are situated around the <strong>edges</strong> of the site.</h3>\n<ul data-path-to-node=\"36\">\n<li>\n<p data-path-to-node=\"36,0,0\"><strong>Đáp án:</strong> <strong>edges</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"36,1,0\"><strong>Dẫn chứng:</strong> (Đoạn 5) &#8220;<strong>The edges of the park are finished with a collection of distinctive, functional spaces</strong>, for example a nursery, sports fields&#8230; community gardens&#8230;&#8221;</p>\n</li>\n<li>\n<p data-path-to-node=\"36,2,0\"><strong>Giải thích:</strong> Các khu vực thể thao và giải trí nằm ở <strong>các rìa</strong> (<em>edges</em>) của công viên.</p>\n</li>\n</ul>\n"}]', 3);
INSERT INTO public.questions VALUES ('7cef88fd-4bea-4d14-9800-6efcaad02ee9', '18105999-cf8c-499b-b5bc-cdf0dd0edd6f', 'radio', ' Questions 27-30', NULL, '<p>Choose the correct answer.</p>
', 'multiple_choice_single', '[{"correct": 2, "options": [{"content": "Some present studies on children’s mother tongues are misleading."}, {"content": "A culturally rich education programme benefits some children more than others."}, {"content": "Bilingual children can make a valuable contribution to the wealth of a country."}, {"content": "The law on mother tongue use at school should be strengthened."}], "question": "What point is the writer making in the second paragraph?"}, {"correct": 0, "options": [{"content": "to lend weight to his argument"}, {"content": "to contradict some research"}, {"content": "to introduce a new concept"}, {"content": "to update current thinking"}], "question": "Why does the writer refer to something that Goethe said?"}, {"correct": 1, "options": [{"content": "they can teach older family members what they learn at school."}, {"content": "they go on to do much better throughout their time at school."}, {"content": "they can read stories about their cultural background."}, {"content": "they develop stronger relationships with their family than with their peers."}], "question": "The writer believes that when young children have a firm grasp of their mother"}, {"correct": 3, "options": [{"content": "They worry that children will be slow to learn to read in either language."}, {"content": "They think that children will confuse words in the two languages."}, {"content": "They believe that the programmes will make children less interested in their lessons."}, {"content": "They fear that the programmes will use up valuable time in the school day."}], "question": "Why are some people suspicious about mother tongue-based teaching programmes?"}]', 'null', 'null', 'null', '[{"content": "<h3 data-path-to-node=\"3\">27. What is the writer making in the second paragraph?</h3>\n<ul data-path-to-node=\"4\">\n<li>\n<p data-path-to-node=\"4,0,0\"><strong>Đáp án:</strong> <strong>Bilingual children can make a valuable contribution to the wealth of a country.</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"4,1,0\"><strong>Dẫn chứng:</strong> (Đoạn 2) “…and the cultural, linguistic and <strong>economic resources of the nation are maximized</strong>. To waste the resources of the nation by discouraging children from developing their mother tongues is quite simply unintelligent from the point of view of national self-interest.”</p>\n</li>\n<li>\n<p data-path-to-node=\"4,2,0\"><strong>Giải thích:</strong> Tác giả lập luận rằng việc phát triển tiếng mẹ đẻ của trẻ em sẽ <strong>tối đa hóa các nguồn lực kinh tế</strong> (<em>“economic resources are maximized”</em>) của quốc gia, tức là trẻ em song ngữ có thể đóng góp vào sự giàu có của đất nước.</p>\n</li>\n</ul>\n<h3 data-path-to-node=\"6\">28. Why does the writer refer to something that Goethe said?</h3>\n<ul data-path-to-node=\"7\">\n<li>\n<p data-path-to-node=\"7,0,0\"><strong>Đáp án:</strong> <strong>to lend weight to his argument.</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"7,1,0\"><strong>Dẫn chứng:</strong> (Đoạn 3) “More than 150 research studies conducted during the past 35 years <strong>strongly support what Goethe</strong>… once said: that the person who knows only one language does not truly know that language.”</p>\n</li>\n<li>\n<p data-path-to-node=\"7,2,0\"><strong>Giải thích:</strong> Tác giả sử dụng câu nói của nhà triết học nổi tiếng Goethe để <strong>củng cố lập luận</strong> (<em>“strongly support”</em>) của mình về lợi ích của việc biết nhiều ngôn ngữ.</p>\n</li>\n</ul>\n<h3 data-path-to-node=\"9\">29. The writer believes that when young children have a firm grasp of their mother</h3>\n<ul data-path-to-node=\"10\">\n<li>\n<p data-path-to-node=\"10,0,0\"><strong>Đáp án:</strong> <strong>they go on to do much better throughout their time at school.</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"10,1,0\"><strong>Dẫn chứng:</strong> (Đoạn 4) “Children who come to school with a <strong>solid foundation in their mother tongue</strong> develop <strong>stronger literacy abilities in the school language</strong>… Children come to school well-prepared to learn the school language and <strong>succeed educationally</strong>.”</p>\n</li>\n<li>\n<p data-path-to-node=\"10,2,0\"><strong>Giải thích:</strong> Nền tảng vững chắc trong tiếng mẹ đẻ giúp trẻ phát triển khả năng đọc viết tốt hơn và thành công hơn trong giáo dục (<em>“succeed educationally”</em>), tức là học tốt hơn trong suốt thời gian đi học.</p>\n</li>\n</ul>\n<h3 data-path-to-node=\"12\">30. Why are some people suspicious about mother tongue-based teaching programmes?</h3>\n<ul data-path-to-node=\"13\">\n<li>\n<p data-path-to-node=\"13,0,0\"><strong>Đáp án:</strong> <strong>They fear that the programmes will use up valuable time in the school day.</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"13,1,0\"><strong>Dẫn chứng:</strong> (Đoạn 5) “Some educators and parents are suspicious of mother tongue-based teaching programs because <strong>they worry that they take time away from the majority language</strong>.”</p>\n</li>\n<li>\n<p data-path-to-node=\"13,2,0\"><strong>Giải thích:</strong> Mối lo ngại chính là các chương trình này sẽ <strong>chiếm mất thời gian</strong> (<em>“take time away”</em>) đáng lẽ phải dùng cho việc học ngôn ngữ đa số.</p>\n</li>\n</ul>\n"}]', 0);
INSERT INTO public.questions VALUES ('b3b95503-44b4-47c8-a805-b46c47510d3b', '73264da4-5f79-4a97-8d22-e01db0380cb5', 'fillup', 'Questions 31-40', '<p>Complete the notes below.</p>
<p>Write <strong>ONE WORD ONLY</strong> for each answer.</p>
<p><strong><span style="font-size: 12pt;">Elephant research in Amboseli</span></strong></p>
<p><strong>Methodology</strong></p>
<ul>
<li>
<p>The elephant population has been studied for almost forty years.</p>
</li>
<li>
<p>Records of many elephants’ dates of birth and also of their {mother} have been kept.</p>
</li>
<li>
<p>Play-back of elephant calls and DNA analysis were also used.</p>
</li>
</ul>
<p><strong>Findings</strong></p>
<ul>
<li>
<p>The social system of elephants has many {layers}.</p>
</li>
</ul>
<p><strong>Co-operation</strong></p>
<ul>
<li>
<p>Two elephants worked together to get food using a {rope}<strong>.</strong></p>
</li>
</ul>
<p><strong>Flexibility</strong></p>
<ul>
<li>
<p>Some moved to a new area when there was a lack of {rain}<strong>.</strong></p>
</li>
</ul>
<p><strong>Emotion</strong></p>
<ul>
<li>
<p>They may move the {bones} of another elephant after death.</p>
</li>
</ul>
<p><strong>Intelligence</strong></p>
<ul>
<li>
<p>Their brain {weight} is quite high in comparison with that of their body.</p>
</li>
</ul>
<p><strong>Male elephants pass through periods of virility called ‘musth’</strong></p>
<ul>
<li>
<p>The way they {walk} is one obvious change.</p>
</li>
</ul>
<div class="s-block-item s-repeatable-item s-block-sortable-item s-blog-post-section blog-section">
<div class="container">
<div class="sixteen columns">
<div class="s-blog-section-inner">
<div class="s-component s-text ">
<div class="">
<div class="s-component-content s-font-body">
<p><strong>Elephants need to live a long time.</strong></p>
<ul>
<li>
<p>Older males make better mates: older females recognize {danger}<strong>.</strong></p>
</li>
</ul>
<p><strong>What still needs to be discovered</strong></p>
<ul>
<li>
<p>How elephants use smell-difficult to study this in the {wild}<strong>.</strong></p>
</li>
<li>
<p>How {sensitive} elephants are to one another</p>
</li>
</ul>
</div>
</div>
</div>
</div>
</div>
</div>
</div>
<div class="s-block-item s-repeatable-item s-block-sortable-item s-blog-post-section blog-section">
<div class="container">
<div class="sixteen columns">
<div class="s-blog-section-inner">
<div class="s-component s-text ">
<div class="">
<div class="s-component-content s-font-heading"> </div>
</div>
</div>
</div>
</div>
</div>
</div>
', NULL, 'gap_filling', 'null', 'null', 'null', 'null', '[{"content": "<h3 data-path-to-node=\"2\"><strong data-path-to-node=\"2\" data-index-in-node=\"0\">PART 4: ELEPHANT RESEARCH IN AMBOSELI</strong></h3>\n<p data-path-to-node=\"3\"><strong data-path-to-node=\"3\" data-index-in-node=\"0\">Caroline Stewart:</strong> Good morning, my name is Caroline Stewart and I’d like to give you an overview of the research we’ve been carrying out to learn more about the elephants living in the Amboseli National Park in Kenya.</p>\n<p data-path-to-node=\"4\">Let me start by telling you a little about the methodology we use. We’ve been studying this population of elephants for nearly 40 years and we’ve collected a wealth of information about individual elephants. We now have a database of 2,500 elephants from the area and we know the month and year of their birth as well as who was the <strong data-path-to-node=\"4\" data-index-in-node=\"333\">(31) mother</strong> of each one.</p>\n<p data-path-to-node=\"5\">More recently, one of my colleagues has been examining the pattern of elephant relationships within and between the families in more detail. He’s done this by using audio equipment to record and then play back the calls that are made by the elephants, and in addition to that, for some time we’ve been using DNA analysis to investigate these relationships.</p>\n<p data-path-to-node=\"6\">The findings were significant. For example, for a long time we’d suspected that elephants live in a very complex social system and one thing we found from our research is that this social system is made up of a large number of different <strong data-path-to-node=\"6\" data-index-in-node=\"237\">(32) layers</strong>, not just parent and child but also brother and sister and so on.</p>\n<p id=\"p-rc_f63baa2bf1ba8858-64\" data-path-to-node=\"7\"><span class=\"citation-224 citation-end-224\">Another important discovery was that elephants can be very cooperative—as much as chimps in fact.</span> We conducted an experiment in which two of the elephants brought food within reach by pulling simultaneously on the ends of a <strong data-path-to-node=\"7\" data-index-in-node=\"224\">(33) rope</strong>. It was a surprise even to us that they managed to do it.</p>\n<div class=\"source-inline-chip-container ng-star-inserted\"></div>\n<p>&nbsp;</p>\n<p data-path-to-node=\"8\">Another finding was just how flexible elephants can be. They may live in smaller or larger groups depending on environmental conditions. So for example, an adult female and her calves might leave their larger groups for days or weeks. A good example of this was two years ago when there was not enough <strong data-path-to-node=\"8\" data-index-in-node=\"302\">(34) rain</strong>; many left the herd and moved to new areas in order to survive.</p>\n<p data-path-to-node=\"9\">We also discovered that elephants can show emotion. For example, when an elephant dies, the others may stroke and rearrange the <strong data-path-to-node=\"9\" data-index-in-node=\"128\">(35) bones</strong>, although why they do it is still a mystery.</p>\n<p data-path-to-node=\"10\">Elephants are very intelligent creatures. We’ve dedicated a whole chapter to this in our new book as the findings are so important. For example, when we looked at the elephant’s brain, we found that its <strong data-path-to-node=\"10\" data-index-in-node=\"203\">(36) weight</strong> was quite high compared with that of its body, which is significant.</p>\n<p id=\"p-rc_f63baa2bf1ba8858-65\" data-path-to-node=\"11\"><span class=\"citation-223 citation-end-223\">Early on in the research, we discovered that bull elephants, i.e., males, go through periods of significant change which is called “musth”.</span> This serves to advertise the male’s virility to other females, letting them know he’s healthy and would be a good father. But it also warns other males to stay away. One of the most obvious changes is in how they <strong data-path-to-node=\"11\" data-index-in-node=\"353\">(37) walk</strong>, though there are others.</p>\n<div class=\"source-inline-chip-container ng-star-inserted\"></div>\n<p>&nbsp;</p>\n<p data-path-to-node=\"12\">However, one of our most important discoveries is that it is crucial for elephants to live for a long time. If you are a male, you probably won’t be a successful mate unless you do. If you are a female, the older and more experienced you are, the more likely it is that you’ll be aware of <strong data-path-to-node=\"12\" data-index-in-node=\"289\">(38) danger</strong> when it approaches. For example, an elephant may be able to cope with one lion, but may have problems if there are three of them. Age helps elephants know when it’s best to walk away or to stand and fight.</p>\n<p data-path-to-node=\"13\">There’s a huge amount that’s still waiting to be discovered. For example, we know very little about the part that’s played in the life of elephants by their sense of smell, although we suspect that it must be important because this sense is very well developed. It’s very hard to conduct research in this area in the <strong data-path-to-node=\"13\" data-index-in-node=\"317\">(39) wild</strong> because there are so many variables involved.</p>\n<p data-path-to-node=\"14\">Another area we know little about is illustrated by a time I observed a young elephant reaching out towards an electric fence. His mother’s whole body posture displayed alarm at the danger he was in. This is an example of how one elephant can be <strong data-path-to-node=\"14\" data-index-in-node=\"246\">(40) sensitive</strong> towards the feelings or situation of another, but we don’t know how much it happens.</p>\n"}]', 0);
INSERT INTO public.questions VALUES ('36dd5f18-4c38-41ab-b796-c95c73fc76b1', 'ec953306-f0ba-4b9b-9940-2152cefdebb4', 'matching', 'Questions 35–40', '', '<p>Complete the summary using the list of words. Choose the correct answer and move it into the gap.</p>', 'summary_completion', 'null', 'null', '{"layoutType": "summary", "summaryText": "<p data-path-to-node=\"22\"><strong data-path-to-node=\"22\" data-index-in-node=\"0\">The positive aspects of sibling relationships</strong></p>\n<p data-path-to-node=\"23\">Annette Henderson suggests that young children''s interactions with older siblings involve {G learning experiences}. Also, a Cambridge study found that siblings still enjoy {B imaginative games} even when they have a tendency to fight. Research conducted in 2003 suggests that children develop {F greater individuality} as a result of seeking attention. Another factor is the trend for smaller families, which may mean that today''s siblings enjoy {I closer relationships} as adults. A 2010 American study linked having a sister with {K mental well-being} among children aged 10–14. Finally, having a sibling may promote {D generous behaviour} according to the same study.</p>", "answerOptions": [{"optionText": "A parental love"}, {"optionText": "B imaginative games"}, {"optionText": "C physical development"}, {"optionText": "D generous behaviour"}, {"optionText": "E strong marriages"}, {"optionText": "F greater individuality"}, {"optionText": "G learning experiences"}, {"optionText": "H career success"}, {"optionText": "I closer relationships"}, {"optionText": "J healthy competition"}, {"optionText": "K mental well-being"}], "matchingItems": []}', 'null', '[{"content": "<p data-path-to-node=\"4\"><strong data-path-to-node=\"4\" data-index-in-node=\"0\">35. learning experiences — {interactions with older siblings involve learning experiences}</strong></p>\n<ul data-path-to-node=\"5\">\n<li>\n<p data-path-to-node=\"5,0,0\"><strong data-path-to-node=\"5,0,0\" data-index-in-node=\"0\">Dẫn chứng (Đoạn 7):</strong> <em data-path-to-node=\"5,0,0\" data-index-in-node=\"20\">“…younger children in turn <strong data-path-to-node=\"5,0,0\" data-index-in-node=\"49\">benefit from unintentional instruction</strong> from their bigger brothers and sisters, acquiring entire phrases and an understanding of social concepts…”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"5,1,0\"><strong data-path-to-node=\"5,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Việc trẻ nhỏ nhận được sự hướng dẫn không chủ ý (unintentional instruction) và học hỏi được các khái niệm xã hội từ anh chị mình chính là những trải nghiệm học tập (<strong data-path-to-node=\"5,1,0\" data-index-in-node=\"177\">learning experiences</strong>).</p>\n</li>\n</ul>\n<p data-path-to-node=\"6\"><strong data-path-to-node=\"6\" data-index-in-node=\"0\">36. imaginative games — {siblings still enjoy imaginative games even when they have a tendency to fight}</strong></p>\n<ul data-path-to-node=\"7\">\n<li>\n<p data-path-to-node=\"7,0,0\"><strong data-path-to-node=\"7,0,0\" data-index-in-node=\"0\">Dẫn chứng (Đoạn 7):</strong> <em data-path-to-node=\"7,0,0\" data-index-in-node=\"20\">“…siblings will still create a rich world of <strong data-path-to-node=\"7,0,0\" data-index-in-node=\"67\">play and make-believe</strong>… even those who fought the most had as many positive interactions…”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"7,1,0\"><strong data-path-to-node=\"7,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Cụm “play and make-believe” (trò chơi đóng vai/giả vờ) chính là cách diễn đạt khác của trò chơi tưởng tượng (<strong data-path-to-node=\"7,1,0\" data-index-in-node=\"121\">imaginative games</strong>). Dù có hay cãi vã, anh chị em vẫn cùng nhau sáng tạo nên thế giới giải trí riêng.</p>\n</li>\n</ul>\n<p data-path-to-node=\"8\"><strong data-path-to-node=\"8\" data-index-in-node=\"0\">37. greater individuality — {children develop greater individuality as a result of seeking attention}</strong></p>\n<ul data-path-to-node=\"9\">\n<li>\n<p data-path-to-node=\"9,0,0\"><strong data-path-to-node=\"9,0,0\" data-index-in-node=\"0\">Dẫn chứng (Đoạn 7):</strong> <em data-path-to-node=\"9,0,0\" data-index-in-node=\"20\">“It is also true that children <strong data-path-to-node=\"9,0,0\" data-index-in-node=\"51\">compete for parental attention by making themselves different</strong>… [they] developed stronger personalities and a <strong data-path-to-node=\"9,0,0\" data-index-in-node=\"162\">better sense of their own identity</strong>.”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"9,1,0\"><strong data-path-to-node=\"9,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Để thu hút sự chú ý của cha mẹ, trẻ thường cố gắng làm mình khác biệt, từ đó hình thành cá tính mạnh mẽ và bản sắc riêng rõ rệt (<strong data-path-to-node=\"9,1,0\" data-index-in-node=\"141\">greater individuality</strong>).</p>\n</li>\n</ul>\n<p data-path-to-node=\"10\"><strong data-path-to-node=\"10\" data-index-in-node=\"0\">38. closer relationships — {today’s siblings enjoy closer relationships as adults}</strong></p>\n<ul data-path-to-node=\"11\">\n<li>\n<p data-path-to-node=\"11,0,0\"><strong data-path-to-node=\"11,0,0\" data-index-in-node=\"0\">Dẫn chứng (Đoạn 8):</strong> <em data-path-to-node=\"11,0,0\" data-index-in-node=\"20\">“This may be advantageous because siblings tend to <strong data-path-to-node=\"11,0,0\" data-index-in-node=\"71\">know each other better and remain lifelong friends</strong>…”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"11,1,0\"><strong data-path-to-node=\"11,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Xu hướng gia đình nhỏ giúp anh chị em hiểu nhau sâu sắc hơn và duy trì tình bạn suốt đời, tức là có mối quan hệ gắn kết hơn (<strong data-path-to-node=\"11,1,0\" data-index-in-node=\"137\">closer relationships</strong>) khi lớn lên.</p>\n</li>\n</ul>\n<p data-path-to-node=\"12\"><strong data-path-to-node=\"12\" data-index-in-node=\"0\">39. mental well-being — {linked having a sister with mental well-being among children}</strong></p>\n<ul data-path-to-node=\"13\">\n<li>\n<p data-path-to-node=\"13,0,0\"><strong data-path-to-node=\"13,0,0\" data-index-in-node=\"0\">Dẫn chứng (Đoạn 8):</strong> <em data-path-to-node=\"13,0,0\" data-index-in-node=\"20\">“…having a sister… meant that 10- to 14-year-olds were <strong data-path-to-node=\"13,0,0\" data-index-in-node=\"79\">less likely to feel lonely, unloved, self-conscious or fearful</strong>.”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"13,1,0\"><strong data-path-to-node=\"13,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Việc giảm thiểu các cảm giác tiêu cực như cô đơn, sợ hãi hay tự ti là những chỉ số quan trọng minh chứng cho sức khỏe tinh thần tốt (<strong data-path-to-node=\"13,1,0\" data-index-in-node=\"145\">mental well-being</strong>).</p>\n</li>\n</ul>\n<p data-path-to-node=\"14\"><strong data-path-to-node=\"14\" data-index-in-node=\"0\">40. generous behaviour — {having a sibling may promote generous behaviour}</strong></p>\n<ul data-path-to-node=\"15\">\n<li>\n<p data-path-to-node=\"15,0,0\"><strong data-path-to-node=\"15,0,0\" data-index-in-node=\"0\">Dẫn chứng (Đoạn 8):</strong> <em data-path-to-node=\"15,0,0\" data-index-in-node=\"20\">“…having a loving sibling of either gender <strong data-path-to-node=\"15,0,0\" data-index-in-node=\"65\">promoted good deeds</strong>, such as <strong data-path-to-node=\"15,0,0\" data-index-in-node=\"94\">helping a neighbour</strong> around the house or <strong data-path-to-node=\"15,0,0\" data-index-in-node=\"134\">helping other children</strong> at school.”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"15,1,0\"><strong data-path-to-node=\"15,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Những “việc tử tế” (good deeds) như giúp đỡ người xung quanh là biểu hiện cụ thể của hành vi hào phóng và nhân ái (<strong data-path-to-node=\"15,1,0\" data-index-in-node=\"127\">generous behaviour</strong>).</p>\n</li>\n</ul>"}]', 2);
INSERT INTO public.questions VALUES ('ba2aa30b-4db5-4a17-8080-4a0b75bb195a', 'f99f53ba-caa7-413d-bffa-c8c408954ad9', 'checkbox', 'Questions 17–18', NULL, '<p>Choose <strong>TWO </strong>correct answers.</p>
<p>Which <strong>TWO </strong>things does Arthur say people should focus on when developing their business idea?</p>', 'multiple_choice_many', 'null', '[{"option": "making sure the idea is original", "correct": false}, {"option": "offering a better deal than competitors", "correct": false}, {"option": "being committed to it", "correct": true}, {"option": "paying attention to detail", "correct": true}, {"option": "fixing realistic prices", "correct": false}]', 'null', 'null', '[{"content": ""}]', 1);
INSERT INTO public.questions VALUES ('494d05ec-4ecd-4be7-a05e-95694aaa4a17', '806c7a8b-640a-46b5-a83d-a367ba8197f5', 'matching', 'Questions 26-30', '', '<div class="s-block-item s-repeatable-item s-block-sortable-item s-blog-post-section blog-section">
<div class="container">
<div class="sixteen columns">
<div class="s-blog-section-inner">
<div class="s-component s-text ">
<div class="">
<div class="s-component-content s-font-body">
<p>What is the focus of the drama workshop run by each of the following teachers?</p>
<p>Choose <strong>FIVE </strong>answers from the box and write the correct letter; <strong>A</strong>–<strong>H</strong></p>
</div>
</div>
</div>
</div>
</div>
</div>
</div>
<div class="s-block-item s-repeatable-item s-block-sortable-item s-blog-post-section blog-section">
<div class="container">
<div class="sixteen columns">
<div class="s-blog-section-inner">
<div class="s-component s-text ">
<div class="">
<div class="s-component-content s-font-body"> </div>
</div>
</div>
</div>
</div>
</div>
</div>', 'summary_completion', 'null', 'null', '{"layoutType": "summary", "summaryText": "<p><strong>Teachers</strong></p>\n<p><br>Bob Lacey {using a range of accents}</p>\n<p> </p>\n<p>Evelyn Chance {full use of the stage}</p>\n<p> </p>\n<p>Ted Winter {physical expression of character}</p>\n<p> </p>\n<p>Kevin Gray {following instructions}</p>\n<p> </p>\n<p>Dorothy Thomas {relaxation techniques}</p>", "answerOptions": [{"optionText": "use of own memories"}, {"optionText": "full use of the stage"}, {"optionText": "relaxation techniques"}, {"optionText": "physical expression of character"}, {"optionText": "play readings"}, {"optionText": "acting without preparation"}, {"optionText": "using a range of accents"}, {"optionText": "following instructions"}], "matchingItems": []}', 'null', 'null', 1);
INSERT INTO public.questions VALUES ('b0164540-da5a-4af3-8624-282eb6a1ce12', '2f1d7d96-0abe-41e0-b5af-aaf85101a687', 'matrix', 'Questions 11–15', '', '<p>Label the plan below.</p>
<p>Write the correct letter, A–H, next to questions 11–15.</p>
<p><img src="data:image/png;base64," width="482" height="443" loading="lazy"></p>', 'choose_a_title', 'null', 'null', 'null', '{"layoutType": "simple", "matrixItems": [{"itemText": "Bike sheds ", "correctCategoryLetter": "G"}, {"itemText": "Snack shop ", "correctCategoryLetter": "E"}, {"itemText": "Fitness rooms ", "correctCategoryLetter": "A"}, {"itemText": "Family rooms ", "correctCategoryLetter": "F"}, {"itemText": "TV room ", "correctCategoryLetter": "H"}], "matrixCategories": [{"categoryText": "A", "categoryLetter": "A"}, {"categoryText": "B", "categoryLetter": "B"}, {"categoryText": "C", "categoryLetter": "C"}, {"categoryText": "D", "categoryLetter": "D"}, {"categoryText": "E", "categoryLetter": "E"}, {"categoryText": "F", "categoryLetter": "F"}, {"categoryText": "G", "categoryLetter": "G"}, {"categoryText": "H", "categoryLetter": "H"}]}', '[{"content": "<p class=\"MsoNormal\"><strong>SECTION 2</strong></p>\n<p class=\"MsoNormal\"><strong>Bob Grain:</strong> Welcome to Gram Pic Arts Campus for our annual Residential Arts Weekend. I’m Bob Grain, director of the program. It’s a large campus, it’s quite easy to get lost, so I’m going to give you a quick overview of the most important places here.</p>\n<p class=\"MsoNormal\">Right, I’m glad you all found your way here to reception first. A word about parking: we do have a free temporary car park here. <span style=\"text-decoration: underline; background-color: #ffe786;\">And for those of you coming by bike, the <strong>(11) bike sheds</strong> aren’t far from reception. You’ll see them on your left as you walk down South Lane towards the residential rooms <strong>(G)</strong>.</span></p>\n<p class=\"MsoNormal\">Now, dinner is in the dining room at 7:30.<span style=\"text-decoration: underline; background-color: #ffe786;\"> If you need something to eat now, the <strong>(12) snack shop</strong> is still open. The quickest way to get there is to leave here, go straight through the office—they won’t mind—the ornamental ponds in front of you, and the snack shop is the building on your left <strong>(E)</strong>.</span></p>\n<p class=\"MsoNormal\">The fitness facilities are even better this year. We’ve outgrown the old fitness rooms which were next to the office. <span style=\"text-decoration: underline; background-color: #ffe786;\">To find the new <strong>(13) fitness rooms</strong> from here, walk up to North Road. They’re at the end in the last block, next to the dining room <strong>(A)</strong>.</span></p>\n<p class=\"MsoNormal\">Now, your bedrooms are quite near. <span style=\"text-decoration: underline; background-color: #ffe786;\">You can see the single rooms in the tall block to the far left of us across South Lane. Couples and families are in our <strong>(14) family rooms</strong> right next to them <strong>(F)</strong>.</span></p>\n<p class=\"MsoNormal\">I’m afraid there aren’t any TVs in the rooms. We ask you to keep the noise down, please. <span style=\"text-decoration: underline; background-color: #ffe786;\">We have a <strong>(15) TV room</strong>—you can probably see it from here—it’s right opposite us in the big red building <strong>(H)</strong>.</span></p>\n<div class=\"MsoNormal\" style=\"text-align: center;\" align=\"center\"><hr align=\"center\" size=\"2\" width=\"100%\"></div>\n<p class=\"MsoNormal\"><strong>Bob Grain:</strong> But there are gaps in our timetables for some extra options. You may have this information in your brochure, but there’ve been some changes.</p>\n<p class=\"MsoNormal\">Firstly, the <span style=\"background-color: #ffe786;\"><strong>drama option</strong>.</span> I’m afraid our theatre and practice rooms here are being refurbished and are out of use. <span style=\"text-decoration: underline; background-color: #ffe786;\">We decided against using our sports hall and instead we’re going to use our <strong>(16) lecture rooms</strong>, which we’ve converted into a theatre for the weekend <strong>(C)</strong>.</span></p>\n<p class=\"MsoNormal\">There are also changes to the <span style=\"background-color: #ffe786;\"><strong>photography option</strong></span> this year. This option isn’t open to everyone. <span style=\"text-decoration: underline;\"><span style=\"background-color: #ffe786;\">We decided for practical reasons to reserve it for <strong>(17) beginners with no previous experience (A: people new to photography)</strong>. </span></span>Let me remind you that you don’t need any special equipment, that’s provided. The tutors have said that unfortunately, they can’t accept parents with children because that proved too disruptive last time. But if you’re over 18, that’s fine.</p>\n<p class=\"MsoNormal\">On to the<span style=\"background-color: #ffe786;\"> <strong>writing option</strong>.</span> Previous courses looked at starting your novel. This year we wondered about focusing on the techniques of writing different types of poetry. <span style=\"text-decoration: underline; background-color: #ffe786;\">However, as a result of many requests, we’ve decided the workshop will concentrate on helping each participant write one or more <strong>(18) short stories (B)</strong>.</span> Poetry, maybe some future time.</p>\n<p class=\"MsoNormal\">Now, <span style=\"background-color: #ffe786;\"><strong>music</strong></span>. The brochure says you’ll go to a concert—that’s a misprint. <span style=\"text-decoration: underline;\"><span style=\"background-color: #ffe786;\">Instead, you’ll be writing and <strong>(19) putting on your own performance (C: giving a performance)</strong>, a concert for yourselves.</span></span> Unfortunately, the singing tutor is ill. It’s too late to replace her, so we’ve had to cancel singing lessons. Apologies for that.</p>\n<p class=\"MsoNormal\">Finally, the <span style=\"background-color: #ffe786;\"><strong>crèche</strong></span>. This is available for all families on the program and there are still some places left.<span style=\"text-decoration: underline; background-color: #ffe786;\"> I’m sure you’ll be pleased to know that <strong>(20) the charge for this hasn’t increased since last year (A: it costs the same as last year)</strong>. </span>Lunch is included, but of course parents are welcome to collect their children and spend the lunch break with them. May I remind you that any fees for this service must be settled in full at the end of the last day.</p>\n<p class=\"MsoNormal\">So, has anybody got any questions?</p>"}]', 0);
INSERT INTO public.questions VALUES ('42910ba8-ff66-4980-a081-2b75f4559351', 'f31941dc-6bf8-4209-9b28-118dfe794918', 'matrix', 'Questions 27–32', '', NULL, 'choose_a_title', 'null', 'null', 'null', '{"layoutType": "simple", "matrixItems": [{"itemText": "evidence that a rock found on Earth originated on Mars", "correctCategoryLetter": "D"}, {"itemText": "a plan to analyse material on Mars", "correctCategoryLetter": "G"}, {"itemText": "the reason Mars is no longer similar to Earth", "correctCategoryLetter": "E"}, {"itemText": "an observation suggesting that there is currently water on Mars", "correctCategoryLetter": "F"}, {"itemText": "a claim that construction had taken place on Mars", "correctCategoryLetter": "A"}, {"itemText": "a possibility that humans and Martians could share the same origins", "correctCategoryLetter": "H"}], "matrixCategories": [{"categoryText": "A", "categoryLetter": "A"}, {"categoryText": "B", "categoryLetter": "B"}, {"categoryText": "C", "categoryLetter": "C"}, {"categoryText": "D", "categoryLetter": "D"}, {"categoryText": "E", "categoryLetter": "E"}, {"categoryText": "F", "categoryLetter": "F"}, {"categoryText": "G", "categoryLetter": "G"}, {"categoryText": "H", "categoryLetter": "H"}]}', '[{"content": "<h3 data-start=\"124\" data-end=\"136\"><strong data-start=\"127\" data-end=\"136\">27. D</strong></h3>\n<p data-start=\"138\" data-end=\"177\">Vị trí: Đoạn D, câu đầu và câu thứ hai.</p>\n<p data-start=\"179\" data-end=\"389\">Dẫn chứng:<br data-start=\"189\" data-end=\"192\">“The first is known as ALH84001, a meteorite that was blasted into space when a large body struck Mars 15 million years ago and which spiralled across the solar system to crash into the Antarctic.”</p>\n<p data-start=\"391\" data-end=\"579\">Giải thích: Đoạn D nói về thiên thạch ALH84001 có nguồn gốc từ sao Hỏa và rơi xuống Nam Cực. Đây chính là bằng chứng cho thấy một tảng đá được tìm thấy trên Trái Đất có xuất xứ từ sao Hỏa.</p>\n<hr data-start=\"581\" data-end=\"584\">\n<h3 data-start=\"586\" data-end=\"598\"><strong data-start=\"589\" data-end=\"598\">28. G</strong></h3>\n<p data-start=\"600\" data-end=\"624\">Vị trí: Đoạn G, câu đầu.</p>\n<p data-start=\"626\" data-end=\"816\">Dẫn chứng:<br data-start=\"636\" data-end=\"639\">“Current projects are hoping to clarify the question… aimed at conducting experiments to detect the presence of a substance called carbon 13 in soil and rock samples on Mars.”</p>\n<p data-start=\"818\" data-end=\"972\">Giải thích: Đoạn G nói rõ các dự án hiện tại sẽ tiến hành thí nghiệm phân tích mẫu đất và đá trên sao Hỏa → đúng với “a plan to analyse material on Mars”.</p>\n<hr data-start=\"974\" data-end=\"977\">\n<h3 data-start=\"979\" data-end=\"991\"><strong data-start=\"982\" data-end=\"991\">29. E</strong></h3>\n<p data-start=\"993\" data-end=\"1019\">Vị trí: Đoạn E, phần giữa.</p>\n<p data-start=\"1021\" data-end=\"1151\">Dẫn chứng:<br data-start=\"1031\" data-end=\"1034\">“Mars lost its magnetic field several billion years ago… Without that protection, Mars’s gases and water boiled off.”</p>\n<p data-start=\"1153\" data-end=\"1299\">Giải thích: Sao Hỏa mất từ trường → không giữ được khí quyển → nước và khí bay hơi. Đây là lý do vì sao sao Hỏa ngày nay không còn giống Trái Đất.</p>\n<hr data-start=\"1301\" data-end=\"1304\">\n<h3 data-start=\"1306\" data-end=\"1318\"><strong data-start=\"1309\" data-end=\"1318\">30. F</strong></h3>\n<p data-start=\"1320\" data-end=\"1345\">Vị trí: Đoạn F, phần đầu.</p>\n<p data-start=\"1347\" data-end=\"1433\">Dẫn chứng:<br data-start=\"1357\" data-end=\"1360\">“water from underground reservoirs still gushes through Martian valleys…”</p>\n<p data-start=\"1435\" data-end=\"1557\">Giải thích: Câu này cho thấy có khả năng hiện tại vẫn còn nước dưới lòng đất trên sao Hỏa → phù hợp với “currently water”.</p>\n<hr data-start=\"1559\" data-end=\"1562\">\n<h3 data-start=\"1564\" data-end=\"1576\"><strong data-start=\"1567\" data-end=\"1576\">31. A</strong></h3>\n<p data-start=\"1578\" data-end=\"1604\">Vị trí: Đoạn A, phần giữa.</p>\n<p data-start=\"1606\" data-end=\"1687\">Dẫn chứng:<br data-start=\"1616\" data-end=\"1619\">“These canals… had been built by technologically advanced Martians…”</p>\n<p data-start=\"1689\" data-end=\"1812\">Giải thích: Có tuyên bố rằng người sao Hỏa đã xây dựng kênh đào → đây là “claim that construction had taken place on Mars”.</p>\n<hr data-start=\"1814\" data-end=\"1817\">\n<h3 data-start=\"1819\" data-end=\"1831\"><strong data-start=\"1822\" data-end=\"1831\">32. H</strong></h3>\n<p data-start=\"1833\" data-end=\"1859\">Vị trí: Đoạn H, phần giữa.</p>\n<p data-start=\"1861\" data-end=\"1972\">Dẫn chứng:<br data-start=\"1871\" data-end=\"1874\">“If DNA is located, it would mean that life on Mars and on Earth may spring from the same source.”</p>\n<p data-start=\"1974\" data-end=\"2101\">Giải thích: Nếu tìm thấy DNA, sự sống trên sao Hỏa và Trái Đất có thể cùng chung nguồn gốc → đúng với “share the same origins”.</p>"}]', 0);
INSERT INTO public.questions VALUES ('41b34416-21d2-42d5-bbe2-6d1a6ab1fd59', 'f31941dc-6bf8-4209-9b28-118dfe794918', 'radio', 'Questions 33–36', '', '<p>Choose the correct answer.</p>', 'multiple_choice', '[{"correct": 1, "options": [{"option_text": "the Martians were physically similar to humans"}, {"option_text": "the Martian environment resembled that of Earth"}, {"option_text": "members of the Martian race were extremely primitive"}, {"option_text": "the climatic conditions on Mars were very dry"}], "question": "The 18th-century astronomer William Herschel believed that"}, {"correct": 3, "options": [{"option_text": "The appearance of some regions of Mars changed"}, {"option_text": "Evidence of organisms was found on Mars"}, {"option_text": "The Martian atmosphere was tested scientifically"}, {"option_text": "Earlier beliefs about Mars were disproven"}], "question": "What does the writer say happened in the 1960s?"}, {"correct": 0, "options": [{"option_text": "organisms can survive on Mars"}, {"option_text": "organisms on Earth are like those found on Mars"}, {"option_text": "Martian conditions resemble those in Earth’s volcanoes"}, {"option_text": "Martian crystals can survive acid conditions"}], "question": "The study of extremophiles suggests that"}, {"correct": 2, "options": [{"option_text": "scientific discussion."}, {"option_text": "media reports"}, {"option_text": "a work of literature."}, {"option_text": "a magazine illustration"}], "question": "At the end of the 19h century, the public''s ideas about Martians changed because of"}]', 'null', 'null', 'null', '[{"content": "<p data-path-to-node=\"3\"><strong data-path-to-node=\"3\" data-index-in-node=\"0\">33. The 18th-century astronomer William Herschel believed that — {B. the Martian environment resembled that of Earth}</strong></p>\n<ul data-path-to-node=\"4\">\n<li>\n<p data-path-to-node=\"4,0,0\"><strong data-path-to-node=\"4,0,0\" data-index-in-node=\"0\">Dẫn chứng (Đoạn A):</strong> <em data-path-to-node=\"4,0,0\" data-index-in-node=\"20\">“The 18th-century astronomer William Herschel, noting the seasons and atmosphere of Mars, declared that ‘its inhabitants <strong data-path-to-node=\"4,0,0\" data-index-in-node=\"141\">enjoy a situation similar to our own</strong>’.”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"4,1,0\"><strong data-path-to-node=\"4,1,0\" data-index-in-node=\"0\">Giải thích:</strong> “Situation similar to our own” (hoàn cảnh tương tự chúng ta) ám chỉ môi trường và điều kiện sống trên Sao Hỏa giống với Trái Đất.</p>\n<ul data-path-to-node=\"4,1,1\">\n<li>\n<p data-path-to-node=\"4,1,1,0,0\"><em data-path-to-node=\"4,1,1,0,0\" data-index-in-node=\"0\">Loại trừ:</em> Đáp án A sai vì Herschel nói về “tình cảnh/môi trường” chứ không khẳng định “ngoại hình” (physically) giống người.</p>\n</li>\n</ul>\n</li>\n</ul>\n<p data-path-to-node=\"5\"><strong data-path-to-node=\"5\" data-index-in-node=\"0\">34. What does the writer say happened in the 1960s? — {D. Earlier beliefs about Mars were disproven}</strong></p>\n<ul data-path-to-node=\"6\">\n<li>\n<p data-path-to-node=\"6,0,0\"><strong data-path-to-node=\"6,0,0\" data-index-in-node=\"0\">Dẫn chứng (Đoạn C):</strong> <em data-path-to-node=\"6,0,0\" data-index-in-node=\"20\">“Then, in the late 1960s, rocket science <strong data-path-to-node=\"6,0,0\" data-index-in-node=\"61\">changed our image of Mars forever</strong>. The US Mariner probes… sent back pictures <strong data-path-to-node=\"6,0,0\" data-index-in-node=\"140\">not of a world covered in vegetation, as many scientists still expected</strong>, but of vistas of cratered, arid deserts.”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"6,1,0\"><strong data-path-to-node=\"6,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Trước những năm 1960, các nhà khoa học tin rằng Sao Hỏa có thực vật (vegetation). Tuy nhiên, những hình ảnh từ tàu Mariner đã chứng minh điều ngược lại (arid deserts). Do đó, những niềm tin trước đây đã bị bác bỏ (<strong data-path-to-node=\"6,1,0\" data-index-in-node=\"226\">disproven</strong>).</p>\n</li>\n</ul>\n<p data-path-to-node=\"7\"><strong data-path-to-node=\"7\" data-index-in-node=\"0\">35. The study of extremophiles suggests that — {A. organisms can survive on Mars}</strong></p>\n<ul data-path-to-node=\"8\">\n<li>\n<p data-path-to-node=\"8,0,0\"><strong data-path-to-node=\"8,0,0\" data-index-in-node=\"0\">Dẫn chứng (Đoạn D):</strong> <em data-path-to-node=\"8,0,0\" data-index-in-node=\"20\">“A second area of <strong data-path-to-node=\"8,0,0\" data-index-in-node=\"38\">support for the idea that living organisms could survive Mars’s harshness</strong> has been provided by the study of <strong data-path-to-node=\"8,0,0\" data-index-in-node=\"146\">extremophiles</strong>, bacteria that have been found in increasingly hostile landscapes on Earth…”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"8,1,0\"><strong data-path-to-node=\"8,1,0\" data-index-in-node=\"0\">Giải thích:</strong> “Extremophiles” là các sinh vật sống được ở môi trường cực đoan trên Trái Đất (như hồ axit hay núi lửa). Nghiên cứu này ủng hộ giả thuyết rằng sinh vật cũng có thể sống sót trong điều kiện khắc nghiệt của Sao Hỏa (<strong data-path-to-node=\"8,1,0\" data-index-in-node=\"226\">Mars’s harshness</strong>).</p>\n</li>\n</ul>\n<p data-path-to-node=\"9\"><strong data-path-to-node=\"9\" data-index-in-node=\"0\">36. At the end of the 19th century, the public’s ideas about Martians changed because of — {C. a work of literature}</strong></p>\n<ul data-path-to-node=\"10\">\n<li>\n<p data-path-to-node=\"10,0,0\"><strong data-path-to-node=\"10,0,0\" data-index-in-node=\"0\">Dẫn chứng (Đoạn B):</strong> <em data-path-to-node=\"10,0,0\" data-index-in-node=\"20\">“The vision of an advanced culture… was taken up by the British writer <strong data-path-to-node=\"10,0,0\" data-index-in-node=\"93\">H. G. Wells in 1898</strong> in his masterpiece <strong data-path-to-node=\"10,0,0\" data-index-in-node=\"132\">The War of the Worlds</strong>… Martians became synonymous with grotesque threatening clients, <strong data-path-to-node=\"10,0,0\" data-index-in-node=\"220\">at least as far as the public was concerned</strong>.”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"10,1,0\"><strong data-path-to-node=\"10,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Năm 1898 (cuối thế kỷ 19), tác phẩm văn học “The War of the Worlds” của H. G. Wells đã khiến công chúng thay đổi cái nhìn về người Sao Hỏa (từ kỹ sư tiên tiến thành những kẻ xâm lược đáng sợ). “A work of literature” chính là kiệt tác này.</p>\n</li>\n</ul>"}]', 1);
INSERT INTO public.questions VALUES ('abb09bc5-7211-4ecf-a37e-7ac0f670fd32', 'f31941dc-6bf8-4209-9b28-118dfe794918', 'radio', 'Questions 37–40', '', '<p>Choose <strong>YES </strong>if the statement agrees with the information given in the text, choose <strong>NO </strong>if the statement contradicts the information, or choose <strong>NOT GIVEN </strong>if there is no information on this.</p>', 'yes_no_not_given', '[{"correct": 0, "options": [{"option_text": "YES"}, {"option_text": "NO"}, {"option_text": "NOT GIVEN"}], "question": "Lowell believed that Martian technology was more developed than human technology."}, {"correct": 1, "options": [{"option_text": "YES"}, {"option_text": "NO"}, {"option_text": "NOT GIVEN"}], "question": "Information gained from Viking probes remains unchallenged"}, {"correct": 0, "options": [{"option_text": "YES"}, {"option_text": "NO"}, {"option_text": "NOT GIVEN"}], "question": "There is evidence that there has been significant climate change on Mars"}, {"correct": 2, "options": [{"option_text": "YES"}, {"option_text": "NO"}, {"option_text": "NOT GIVEN"}], "question": "Spanish scientists plan to launch space probes if DNA is found on Mars"}]', 'null', 'null', 'null', '[{"content": "<p data-path-to-node=\"6\"><strong data-path-to-node=\"6\" data-index-in-node=\"0\">11. Lowell believed that Martian technology was more developed than human technology.</strong></p>\n<ul data-path-to-node=\"7\">\n<li><strong data-path-to-node=\"7,0,0\" data-index-in-node=\"0\">Đáp án: YES</strong></li>\n<li><strong data-path-to-node=\"7,1,0\" data-index-in-node=\"0\">Dẫn chứng (Đoạn A):</strong> “Martian folk are possessed of <strong data-path-to-node=\"7,1,0\" data-index-in-node=\"51\">inventions of which we have not dreamed</strong>,” he (Lowell) argued.</li>\n<li><strong data-path-to-node=\"7,2,0\" data-index-in-node=\"0\">Giải thích:</strong> Cụm từ “inventions of which we have not dreamed” (những phát minh mà chúng ta chưa từng mơ tới) ám chỉ công nghệ của người Hỏa tinh tiên tiến hơn công nghệ của con người hiện tại.</li>\n</ul>\n<p data-path-to-node=\"8\"><strong data-path-to-node=\"8\" data-index-in-node=\"0\">12. Information gained from Viking probes remains unchallenged.</strong></p>\n<ul data-path-to-node=\"9\">\n<li><strong data-path-to-node=\"9,0,0\" data-index-in-node=\"0\">Đáp án: NO</strong></li>\n<li><strong data-path-to-node=\"9,1,0\" data-index-in-node=\"0\">Dẫn chứng (Đoạn C &amp; D):</strong>\n<ul data-path-to-node=\"9,1,1\">\n<li>Đoạn C nói Viking tuyên bố Mars chính thức chết: “Mars was declared officially dead”.</li>\n<li>Đoạn D bắt đầu bằng: “Since that time, <strong data-path-to-node=\"9,1,1,1,0\" data-index-in-node=\"39\">two critical pieces of evidence have been found on Earth which support the idea that Mars has life</strong>.” (Kể từ đó, hai bằng chứng quan trọng đã được tìm thấy… ủng hộ ý tưởng Mars có sự sống).</li>\n</ul>\n</li>\n<li><strong data-path-to-node=\"9,2,0\" data-index-in-node=\"0\">Giải thích:</strong> Kết luận “Mars đã chết” của tàu Viking đã bị thách thức (challenged) bởi các bằng chứng mới về thiên thạch ALH84001 và vi khuẩn cực hạn. Do đó, thông tin từ Viking không còn là “duy nhất” và “không bị thách thức”.</li>\n</ul>\n<p data-path-to-node=\"10\"><strong data-path-to-node=\"10\" data-index-in-node=\"0\">13. There is evidence that there has been significant climate change on Mars.</strong></p>\n<ul data-path-to-node=\"11\">\n<li><strong data-path-to-node=\"11,0,0\" data-index-in-node=\"0\">Đáp án: YES</strong></li>\n<li><strong data-path-to-node=\"11,1,0\" data-index-in-node=\"0\">Dẫn chứng (Đoạn E):</strong> “…the Martian surface, although <strong data-path-to-node=\"11,1,0\" data-index-in-node=\"54\">hostile and arid today</strong>, was <strong data-path-to-node=\"11,1,0\" data-index-in-node=\"82\">once lush and welcoming</strong>… dried-up riverbeds and old estuaries.”</li>\n<li><strong data-path-to-node=\"11,2,0\" data-index-in-node=\"0\">Giải thích:</strong> Sự thay đổi từ trạng thái “lush and welcoming” (tươi tốt và hiếu khách) sang “hostile and arid” (khắc nghiệt và khô cằn) cùng với sự biến mất của sông ngòi là minh chứng cho một sự biến đổi khí hậu đáng kể (significant climate change).</li>\n</ul>\n<p data-path-to-node=\"12\"><strong data-path-to-node=\"12\" data-index-in-node=\"0\">14. Spanish scientists plan to launch space probes if DNA is found on Mars.</strong></p>\n<ul data-path-to-node=\"13\">\n<li><strong data-path-to-node=\"13,0,0\" data-index-in-node=\"0\">Đáp án: NOT GIVEN</strong></li>\n<li><strong data-path-to-node=\"13,1,0\" data-index-in-node=\"0\">Dẫn chứng (Đoạn H):</strong> Tác giả nhắc đến Professor Juan Pérez Mercader (người Tây Ban Nha) bàn luận về tầm quan trọng của DNA và nói rằng: “The discovery… would also mean <strong data-path-to-node=\"13,1,0\" data-index-in-node=\"169\">renewed purpose for manned space flight projects</strong>.”</li>\n<li><strong data-path-to-node=\"13,2,0\" data-index-in-node=\"0\">Giải thích:</strong> Bài đọc chỉ nói việc tìm thấy DNA sẽ tạo ra mục đích mới cho các dự án “manned space flight” (chuyến bay có người lái), nhưng <strong data-path-to-node=\"13,2,0\" data-index-in-node=\"138\">không hề nhắc đến</strong> việc các nhà khoa học Tây Ban Nha có kế hoạch cụ thể nào để “phóng tàu thăm dò” (launch space probes) hay không. Thông tin này thiếu tính xác thực trong bài.</li>\n</ul>"}]', 2);
INSERT INTO public.questions VALUES ('e4a2ff6b-1c5b-4fda-b574-9a63c8cf1ce3', '1d172720-e086-423a-b867-ff5f3ae54a1a', 'radio', 'Questions 1-7', '', '<p>Choose <strong>TRUE </strong>if the statement agrees with the information given in the text, choose <strong>FALSE </strong>if the statement contradicts the information, or choose <strong>NOT GIVEN </strong>if there is no information on this.</p>', 'true_false_not_given', '[{"correct": 1, "options": [{"option_text": "TRUE"}, {"option_text": "FALSE"}, {"option_text": "NOT GIVEN"}], "question": "The study done by the Chinese Academy of Medical Sciences looked at eating habits in several countries."}, {"correct": 0, "options": [{"option_text": "TRUE"}, {"option_text": "FALSE"}, {"option_text": "NOT GIVEN"}], "question": "Eating fresh chillies can decrease the likelihood of dying from certain serious illnesses."}, {"correct": 1, "options": [{"option_text": "TRUE"}, {"option_text": "FALSE"}, {"option_text": "NOT GIVEN"}], "question": "Capsaicin is found in the same place in all chilli varieties."}, {"correct": 2, "options": [{"option_text": "TRUE"}, {"option_text": "FALSE"}, {"option_text": "NOT GIVEN"}], "question": "Habanero peppers are the hottest known peppers."}, {"correct": 1, "options": [{"option_text": "TRUE"}, {"option_text": "FALSE"}, {"option_text": "NOT GIVEN"}], "question": "Pure capsaicin is licensed for use in food products in the European Union."}, {"correct": 2, "options": [{"option_text": "TRUE"}, {"option_text": "FALSE"}, {"option_text": "NOT GIVEN"}], "question": "The Aztecs were the first to use capsaicin as a pain killer."}, {"correct": 0, "options": [{"option_text": "TRUE"}, {"option_text": "FALSE"}, {"option_text": "NOT GIVEN"}], "question": "Birds have different physical responses to eating chillies than mammals."}]', 'null', 'null', 'null', '[{"content": "<p data-path-to-node=\"2\"><strong data-path-to-node=\"2\" data-index-in-node=\"0\">1. The study done by the Chinese Academy of Medical Sciences looked at eating habits in several countries.</strong></p>\n<ul data-path-to-node=\"3\">\n<li>\n<p data-path-to-node=\"3,0,0\"><strong data-path-to-node=\"3,0,0\" data-index-in-node=\"0\">Đáp án: FALSE</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"3,1,0\"><strong data-path-to-node=\"3,1,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> Đoạn 1, câu cuối: <em data-path-to-node=\"3,1,0\" data-index-in-node=\"29\">“…tracked the health of nearly half a million participants <strong data-path-to-node=\"3,1,0\" data-index-in-node=\"90\">in China</strong> for several years.”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"3,2,0\"><strong data-path-to-node=\"3,2,0\" data-index-in-node=\"0\">Giải thích:</strong> Bài đọc khẳng định nghiên cứu này chỉ thực hiện trên những người tham gia <strong data-path-to-node=\"3,2,0\" data-index-in-node=\"86\">tại Trung Quốc</strong> (<em data-path-to-node=\"3,2,0\" data-index-in-node=\"102\">in China</em>). Do đó, thông tin nói nghiên cứu thực hiện ở “vài quốc gia” (<em data-path-to-node=\"3,2,0\" data-index-in-node=\"173\">several countries</em>) là sai.</p>\n</li>\n</ul>\n<p data-path-to-node=\"5\"><strong data-path-to-node=\"5\" data-index-in-node=\"0\">2. Eating fresh chillies can decrease the likelihood of dying from certain serious illnesses.</strong></p>\n<ul data-path-to-node=\"6\">\n<li>\n<p data-path-to-node=\"6,0,0\"><strong data-path-to-node=\"6,0,0\" data-index-in-node=\"0\">Đáp án: TRUE</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"6,1,0\"><strong data-path-to-node=\"6,1,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> Đoạn 2, câu cuối: <em data-path-to-node=\"6,1,0\" data-index-in-node=\"29\">“…those who ate <strong data-path-to-node=\"6,1,0\" data-index-in-node=\"47\">fresh chilli</strong> had a <strong data-path-to-node=\"6,1,0\" data-index-in-node=\"66\">lower probability of death</strong> from cancer, heart disease, and diabetes.”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"6,2,0\"><strong data-path-to-node=\"6,2,0\" data-index-in-node=\"0\">Giải thích:</strong> “Lower probability of death” tương ứng với “decrease the likelihood of dying”. Các bệnh ung thư, tim mạch và tiểu đường chính là “certain serious illnesses” (những căn bệnh nghiêm trọng nhất định).</p>\n</li>\n</ul>\n<p data-path-to-node=\"8\"><strong data-path-to-node=\"8\" data-index-in-node=\"0\">3. Capsaicin is found in the same place in all chilli varieties.</strong></p>\n<ul data-path-to-node=\"9\">\n<li>\n<p data-path-to-node=\"9,0,0\"><strong data-path-to-node=\"9,0,0\" data-index-in-node=\"0\">Đáp án: FALSE</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"9,1,0\"><strong data-path-to-node=\"9,1,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> Đoạn 3, câu 3: <em data-path-to-node=\"9,1,0\" data-index-in-node=\"26\">“…in many types of chilli, this is the location of capsaicin, but <strong data-path-to-node=\"9,1,0\" data-index-in-node=\"94\">there are several varieties where this is not the case</strong>.”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"9,2,0\"><strong data-path-to-node=\"9,2,0\" data-index-in-node=\"0\">Giải thích:</strong> Bài đọc nói rằng mặc dù ở nhiều loại ớt capsaicin nằm ở cuống vàng bám vào hạt, nhưng có vài giống ớt mà vị trí này <strong data-path-to-node=\"9,2,0\" data-index-in-node=\"128\">không phải như vậy</strong> (<em data-path-to-node=\"9,2,0\" data-index-in-node=\"148\">not the case</em>). Vì vậy, nói nó nằm ở cùng một chỗ trong tất cả các loại ớt là sai.</p>\n</li>\n</ul>\n<p data-path-to-node=\"11\"><strong data-path-to-node=\"11\" data-index-in-node=\"0\">4. Habanero peppers are the hottest known peppers.</strong></p>\n<ul data-path-to-node=\"12\">\n<li>\n<p data-path-to-node=\"12,0,0\"><strong data-path-to-node=\"12,0,0\" data-index-in-node=\"0\">Đáp án: NOT GIVEN</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"12,1,0\"><strong data-path-to-node=\"12,1,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> Đoạn 4, câu 2: <em data-path-to-node=\"12,1,0\" data-index-in-node=\"26\">“But habanero peppers have a Scoville value of between 100,000 and 350,000.”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"12,2,0\"><strong data-path-to-node=\"12,2,0\" data-index-in-node=\"0\">Giải thích:</strong> Bài đọc có đưa ra chỉ số độ cay của ớt habanero, nhưng <strong data-path-to-node=\"12,2,0\" data-index-in-node=\"67\">không hề so sánh</strong> nó với các loại ớt khác để khẳng định đây là loại ớt “cay nhất” (<em data-path-to-node=\"12,2,0\" data-index-in-node=\"149\">hottest known</em>).</p>\n</li>\n</ul>\n<p data-path-to-node=\"14\"><strong data-path-to-node=\"14\" data-index-in-node=\"0\">5. Pure capsaicin is licensed for use in food products in the European Union.</strong></p>\n<ul data-path-to-node=\"15\">\n<li>\n<p data-path-to-node=\"15,0,0\"><strong data-path-to-node=\"15,0,0\" data-index-in-node=\"0\">Đáp án: FALSE</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"15,1,0\"><strong data-path-to-node=\"15,1,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> Đoạn 4, câu 4: <em data-path-to-node=\"15,1,0\" data-index-in-node=\"26\">“Pure capsaicin can be bought on the internet, though its use as a food additive is <strong data-path-to-node=\"15,1,0\" data-index-in-node=\"110\">banned in the European Union</strong>.”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"15,2,0\"><strong data-path-to-node=\"15,2,0\" data-index-in-node=\"0\">Giải thích:</strong> “Banned” có nghĩa là bị cấm. Điều này trái ngược hoàn toàn với từ “licensed” (được cấp phép) trong câu hỏi.</p>\n</li>\n</ul>\n<p data-path-to-node=\"17\"><strong data-path-to-node=\"17\" data-index-in-node=\"0\">6. The Aztecs were the first to use capsaicin as a pain killer.</strong></p>\n<ul data-path-to-node=\"18\">\n<li>\n<p data-path-to-node=\"18,0,0\"><strong data-path-to-node=\"18,0,0\" data-index-in-node=\"0\">Đáp án: NOT GIVEN</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"18,1,0\"><strong data-path-to-node=\"18,1,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> Đoạn 4, câu cuối: <em data-path-to-node=\"18,1,0\" data-index-in-node=\"29\">“The Aztecs also put chilli on their teeth to kill toothache pain…”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"18,2,0\"><strong data-path-to-node=\"18,2,0\" data-index-in-node=\"0\">Giải thích:</strong> Bài đọc xác nhận người Aztec đã sử dụng ớt để giảm đau răng, nhưng <strong data-path-to-node=\"18,2,0\" data-index-in-node=\"79\">không có thông tin</strong> nào khẳng định họ là những người “đầu tiên” (<em data-path-to-node=\"18,2,0\" data-index-in-node=\"143\">the first</em>) làm việc này.</p>\n</li>\n</ul>\n<p data-path-to-node=\"20\"><strong data-path-to-node=\"20\" data-index-in-node=\"0\">7. Birds have different physical responses to eating chillies than mammals.</strong></p>\n<ul data-path-to-node=\"21\">\n<li>\n<p data-path-to-node=\"21,0,0\"><strong data-path-to-node=\"21,0,0\" data-index-in-node=\"0\">Đáp án: TRUE</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"21,1,0\"><strong data-path-to-node=\"21,1,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> Đoạn 6 &amp; 7: <em data-path-to-node=\"21,1,0\" data-index-in-node=\"23\">“…adding that <strong data-path-to-node=\"21,1,0\" data-index-in-node=\"39\">all mammals experience the same sensation, but that birds do not</strong>. ‘They can eat chillies like popcorn and they don’t feel the heat’.”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"21,2,0\"><strong data-path-to-node=\"21,2,0\" data-index-in-node=\"0\">Giải thích:</strong> Bài đọc chỉ rõ động vật có vú (mammals) cảm thấy sức nóng (burning sensation), trong khi chim (birds) thì không cảm thấy gì. Đây chính là sự khác biệt về phản ứng cơ thể (<em data-path-to-node=\"21,2,0\" data-index-in-node=\"183\">different physical responses</em>).</p>\n</li>\n</ul>"}]', 0);
INSERT INTO public.questions VALUES ('7b935d93-e213-430c-b396-d167f654f3a0', '929cd6dc-04b3-4d88-9449-80b14b938201', 'radio', 'Questions 21–24', '', '<p data-start="32" data-end="73">Choose the correct letter, <strong>A</strong>, <strong>B </strong>or <strong>C</strong>.</p>
<h4 data-start="75" data-end="107"><strong>Presentation on African art</strong></h4>', 'multiple_choice', '[{"correct": 1, "options": [{"option_text": "A. He read several journal articles"}, {"option_text": "B. He attended an exhibition"}, {"option_text": "C. He spent some time in Nigeria"}], "question": "What first attracted Terence to the topic of Ife sculptures?"}, {"correct": 2, "options": [{"option_text": "A. abstract designs"}, {"option_text": "B. fish and wild animals"}, {"option_text": "C. people"}], "question": "In his presentation Terence will focus on sculptures featuring"}, {"correct": 0, "options": [{"option_text": "A. He received money from an arts organisation"}, {"option_text": "B. His mother and father paid for him"}, {"option_text": "C. He wrote about the trip for a newspaper"}], "question": "How did Terence finance his trip to Ife?"}, {"correct": 1, "options": [{"option_text": "A. helping at an archaeological site"}, {"option_text": "B. the professor he met"}, {"option_text": "C. the artists he got to know"}], "question": "What was most memorable for Terence about his trip?"}]', 'null', 'null', 'null', 'null', 0);
INSERT INTO public.questions VALUES ('b3a7974f-bd18-41d3-80a7-878c0ffe3682', '3796130c-e716-4ead-8b73-7192931245c0', 'matching', 'Questions 11-16', '', '<p>Which comment does John make about each of the following photography magazines?</p>
<p>Choose <strong data-path-to-node="4" data-index-in-node="87">SIX</strong> answers from the box and write the correct letter, <strong data-path-to-node="4" data-index-in-node="142">A-H</strong>, next to questions 11-16.</p>', 'summary_completion', 'null', 'null', '{"layoutType": "summary", "summaryText": "<p id=\"p-rc_68244515d81e25b6-84\" data-path-to-node=\"6\"><strong data-path-to-node=\"6\" data-index-in-node=\"0\"><span class=\"citation-995 citation-996 citation-end-996\">Photography magazines<sup class=\"superscript\" data-turn-source-index=\"10\"><!----></sup></span><span class=\"citation-995 citation-end-995\"><sup class=\"superscript\" data-turn-source-index=\"11\"><!----></sup></span></strong></p>\n<div class=\"source-inline-chip-container luminous-sources ng-star-inserted\"><button class=\"button multiple-button ng-star-inserted\" aria-label=\"View source details. Opens side panel.\"><!----><!----><!----><!----></button><!----><!----><!----><!----></div>\n<p><!----><!----><!----><!----><!----><!----><!----><!----></p>\n<ul data-path-to-node=\"7\">\n<li>\n<p id=\"p-rc_68244515d81e25b6-85\" data-path-to-node=\"7,0,0\"><span class=\"citation-993 citation-994 citation-end-994\">Camera Ready {B. Easy to understand advice}<sup class=\"superscript\" data-turn-source-index=\"12\"><!----></sup></span><span class=\"citation-993 citation-end-993\"><sup class=\"superscript\" data-turn-source-index=\"13\"><!----></sup></span></p>\n<div class=\"source-inline-chip-container luminous-sources ng-star-inserted\"><button class=\"button multiple-button ng-star-inserted\" aria-label=\"View source details. Opens side panel.\"><!----><!----><!----><!----></button><!----><!----><!----><!----></div>\n<!----><!----><!----><!----><!----><!----><!----><!----></li>\n<li>\n<p id=\"p-rc_68244515d81e25b6-86\" data-path-to-node=\"7,1,0\"><span class=\"citation-991 citation-992 citation-end-992\">Outdoor Lens {F. High quality photos}<sup class=\"superscript\" data-turn-source-index=\"14\"><!----></sup></span><span class=\"citation-991 citation-end-991\"><sup class=\"superscript\" data-turn-source-index=\"15\"><!----></sup></span></p>\n<div class=\"source-inline-chip-container luminous-sources ng-star-inserted\"><button class=\"button multiple-button ng-star-inserted\" aria-label=\"View source details. Opens side panel.\"><!----><!----><!----><!----></button><!----><!----><!----><!----></div>\n<!----><!----><!----><!----><!----><!----><!----><!----></li>\n<li>\n<p id=\"p-rc_68244515d81e25b6-87\" data-path-to-node=\"7,2,0\"><span class=\"citation-989 citation-990 citation-end-990\">Photographer Today {D. Reports about new products}<sup class=\"superscript\" data-turn-source-index=\"16\"><!----></sup></span><span class=\"citation-989 citation-end-989\"><sup class=\"superscript\" data-turn-source-index=\"17\"><!----></sup></span></p>\n<div class=\"source-inline-chip-container luminous-sources ng-star-inserted\"><button class=\"button multiple-button ng-star-inserted\" aria-label=\"View source details. Opens side panel.\"><!----><!----><!----><!----></button><!----><!----><!----><!----></div>\n<!----><!----><!----><!----><!----><!----><!----><!----></li>\n<li>\n<p id=\"p-rc_68244515d81e25b6-88\" data-path-to-node=\"7,3,0\"><span class=\"citation-987 citation-988 citation-end-988\">Photo Now {A. Useful technical advice}<sup class=\"superscript\" data-turn-source-index=\"18\"><!----></sup></span><span class=\"citation-987 citation-end-987\"><sup class=\"superscript\" data-turn-source-index=\"19\"><!----></sup></span></p>\n<div class=\"source-inline-chip-container luminous-sources ng-star-inserted\"><button class=\"button multiple-button ng-star-inserted\" aria-label=\"View source details. Opens side panel.\"><!----><!----><!----><!----></button><!----><!----><!----><!----></div>\n<!----><!----><!----><!----><!----><!----><!----><!----></li>\n<li>\n<p id=\"p-rc_68244515d81e25b6-89\" data-path-to-node=\"7,4,0\"><span class=\"citation-985 citation-986 citation-end-986\">Wild Photos {G. Only available online}<sup class=\"superscript\" data-turn-source-index=\"20\"><!----></sup></span><span class=\"citation-985 citation-end-985\"><sup class=\"superscript\" data-turn-source-index=\"21\"><!----></sup></span></p>\n<div class=\"source-inline-chip-container luminous-sources ng-star-inserted\"><button class=\"button multiple-button ng-star-inserted\" aria-label=\"View source details. Opens side panel.\"><!----><!----><!----><!----></button><!----><!----><!----><!----></div>\n<!----><!----><!----><!----><!----><!----><!----><!----></li>\n<li>\n<p id=\"p-rc_68244515d81e25b6-90\" data-path-to-node=\"7,5,0\"><span class=\"citation-983 citation-984 citation-end-984\">Photo Monthly {E. Advice about photography locations}<sup class=\"superscript\" data-turn-source-index=\"22\"><!----></sup></span><span class=\"citation-983 citation-end-983\"><sup class=\"superscript\" data-turn-source-index=\"23\"><!----></sup></span></p>\n</li>\n</ul>", "answerOptions": [{"optionText": "A. Useful technical advice"}, {"optionText": "B. Easy to understand advice"}, {"optionText": "C. Free offers"}, {"optionText": "D. Reports about new products"}, {"optionText": "E. Advice about photography locations"}, {"optionText": "F. High quality photos"}, {"optionText": "G. Only available online"}, {"optionText": "H. Monthly competitions"}], "matchingItems": []}', 'null', 'null', 0);
INSERT INTO public.questions VALUES ('94823971-0cbf-4f35-a244-8fa1d04ef646', '929cd6dc-04b3-4d88-9449-80b14b938201', 'checkbox', 'Questions 25 and 26', '', '<p data-start="875" data-end="903">Choose <strong>TWO</strong> letters, <strong>A</strong>–<strong>E</strong>.</p>
<p data-start="905" data-end="997">Which <strong>TWO </strong>additions will Terence make to the part of the presentation on the sculptures?</p>', 'multiple_choice', 'null', '[{"correct": false, "option_text": "A. enlarged pictures of the sculptures"}, {"correct": true, "option_text": "B. more material about the subjects"}, {"correct": false, "option_text": "C. more about his personal opinion of the artworks"}, {"correct": true, "option_text": "D. extra information about the techniques used"}, {"correct": false, "option_text": "E. additional information about the artists"}]', 'null', 'null', 'null', 1);
INSERT INTO public.questions VALUES ('893f5c71-3d1b-4cfc-b495-274d8714ba4f', '1d172720-e086-423a-b867-ff5f3ae54a1a', 'fillup', 'Questions 8-13', '<p>Choose <strong>ONE WORD ONLY</strong> from the passage for each answer.</p>
<p style="text-align: center;"><span style="font-size: 12pt;"><strong>The health benefits of chilli</strong></span></p>
<p><strong>Using chilli to fight bacteria</strong></p>
<div class="s-block-item s-repeatable-item s-block-sortable-item s-blog-post-section blog-section">
<div class="container">
<div class="sixteen columns">
<div class="s-blog-section-inner">
<div class="s-component s-text ">
<div class="">
<div class="s-component-content s-font-body">
<ul>
<li>Chilli’s ability to fight germs was very significant before the invention of {refrigeration}</li>
<li>It was thought that chilli was eaten because it causes bodies to produce {sweat}, which reduces body heat</li>
<li>Books of {recipes}from around the world show chilli is more commonly used in certain geographical areas</li>
<li>Chilli is most likely to be used in valleys with a lot of humidity</li>
</ul>
<p><strong>Using chilli for weight loss</strong></p>
<ul>
<li>The University of Wyoming found that chilli raised the mice’s {metabolism}</li>
<li>The University of Adelaide found that receptors in the {stomach} react with chilli to indicate when you’ve had enough to eat</li>
</ul>
<p><strong>Using chilli as pain relief</strong></p>
<ul>
<li>It reacts with the part of our brain that notices a difference in temperature</li>
<li>The sensation we have when eating chilli is similar to the one we have after {exercise}</li>
</ul>
</div>
</div>
</div>
</div>
</div>
</div>
</div>
<div class="s-block-item s-repeatable-item s-block-sortable-item s-blog-post-section blog-section">
<div class="container">
<div class="sixteen columns">
<div class="s-blog-section-inner">
<div class="s-component s-text ">
<div class="">
<p class="s-component-content s-font-heading">
</div>
</div>
</div>
</div>
</div>
</div>
', NULL, 'gap_filling', 'null', 'null', 'null', 'null', '[{"content": "<p data-path-to-node=\"2\"><strong data-path-to-node=\"2\" data-index-in-node=\"0\">8. refrigeration</strong></p>\n<ul data-path-to-node=\"3\">\n<li>\n<p data-path-to-node=\"3,0,0\"><strong data-path-to-node=\"3,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> Đoạn 9, câu 1-2: <em data-path-to-node=\"3,0,0\" data-index-in-node=\"28\">“Chillies also fight bacteria. This was of great value before <strong data-path-to-node=\"3,0,0\" data-index-in-node=\"90\">refrigeration</strong>…”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"3,1,0\"><strong data-path-to-node=\"3,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Khả năng diệt khuẩn (fight germs/bacteria) của ớt cực kỳ quan trọng trước khi con người phát minh ra <strong data-path-to-node=\"3,1,0\" data-index-in-node=\"113\">tủ lạnh/việc làm lạnh</strong> (<strong data-path-to-node=\"3,1,0\" data-index-in-node=\"136\">refrigeration</strong>).</p>\n</li>\n</ul>\n<p data-path-to-node=\"5\"><strong data-path-to-node=\"5\" data-index-in-node=\"0\">9. sweat</strong></p>\n<ul data-path-to-node=\"6\">\n<li>\n<p data-path-to-node=\"6,0,0\"><strong data-path-to-node=\"6,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> Đoạn 11, câu 1: <em data-path-to-node=\"6,0,0\" data-index-in-node=\"27\">“People in hot countries are said to use more chilli because it makes them generate a lot of <strong data-path-to-node=\"6,0,0\" data-index-in-node=\"120\">sweat</strong>, which cools them down.”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"6,1,0\"><strong data-path-to-node=\"6,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Ăn ớt khiến cơ thể đổ <strong data-path-to-node=\"6,1,0\" data-index-in-node=\"34\">mồ hôi</strong> (<strong data-path-to-node=\"6,1,0\" data-index-in-node=\"42\">sweat</strong>), quá trình này giúp làm mát cơ thể (reduces body heat).</p>\n</li>\n</ul>\n<p data-path-to-node=\"8\"><strong data-path-to-node=\"8\" data-index-in-node=\"0\">10. recipes</strong></p>\n<ul data-path-to-node=\"9\">\n<li>\n<p data-path-to-node=\"9,0,0\"><strong data-path-to-node=\"9,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> Đoạn 11, câu 3: <em data-path-to-node=\"9,0,0\" data-index-in-node=\"27\">“By studying books filled with <strong data-path-to-node=\"9,0,0\" data-index-in-node=\"58\">recipes</strong> from all over the world, the researchers found that spices—including chilli—were more likely to be used close to the equator…”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"9,1,0\"><strong data-path-to-node=\"9,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Các nhà nghiên cứu đã phân tích sách <strong data-path-to-node=\"9,1,0\" data-index-in-node=\"49\">công thức nấu ăn</strong> (<strong data-path-to-node=\"9,1,0\" data-index-in-node=\"67\">recipes</strong>) trên toàn thế giới để chứng minh ớt được dùng phổ biến hơn ở các khu vực địa lý cụ thể (gần xích đạo, độ ẩm cao).</p>\n</li>\n</ul>\n<p data-path-to-node=\"11\"><strong data-path-to-node=\"11\" data-index-in-node=\"0\">11. metabolism</strong></p>\n<ul data-path-to-node=\"12\">\n<li>\n<p data-path-to-node=\"12,0,0\"><strong data-path-to-node=\"12,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> Đoạn 12, câu 2: <em data-path-to-node=\"12,0,0\" data-index-in-node=\"27\">“Research… found that the substance increased the <strong data-path-to-node=\"12,0,0\" data-index-in-node=\"79\">metabolism</strong> of the animals, causing them to burn more energy…”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"12,1,0\"><strong data-path-to-node=\"12,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Nghiên cứu trên chuột cho thấy ớt làm tăng quá trình <strong data-path-to-node=\"12,1,0\" data-index-in-node=\"65\">trao đổi chất</strong> (<strong data-path-to-node=\"12,1,0\" data-index-in-node=\"80\">metabolism</strong>), giúp đốt cháy nhiều năng lượng hơn.</p>\n</li>\n</ul>\n<p data-path-to-node=\"14\"><strong data-path-to-node=\"14\" data-index-in-node=\"0\">12. stomach</strong></p>\n<ul data-path-to-node=\"15\">\n<li>\n<p data-path-to-node=\"15,0,0\"><strong data-path-to-node=\"15,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> Đoạn 13, câu 1: <em data-path-to-node=\"15,0,0\" data-index-in-node=\"27\">“…researchers at the University of Adelaide found that certain receptors… located inside the <strong data-path-to-node=\"15,0,0\" data-index-in-node=\"124\">stomach</strong> play a role in sensing when you are full.”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"15,1,0\"><strong data-path-to-node=\"15,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Các thụ thể nằm trong <strong data-path-to-node=\"15,1,0\" data-index-in-node=\"34\">dạ dày</strong> (<strong data-path-to-node=\"15,1,0\" data-index-in-node=\"42\">stomach</strong>) phản ứng với ớt để phát tín hiệu cho não biết khi nào bạn đã ăn đủ/no (had enough to eat/full).</p>\n</li>\n</ul>\n<p data-path-to-node=\"17\"><strong data-path-to-node=\"17\" data-index-in-node=\"0\">13. exercise</strong></p>\n<ul data-path-to-node=\"18\">\n<li>\n<p data-path-to-node=\"18,0,0\"><strong data-path-to-node=\"18,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> Đoạn cuối, câu 3: <em data-path-to-node=\"18,0,0\" data-index-in-node=\"29\">“This process involves the release of endorphins, which can give us a “rush” not unlike the feeling we have when we have done some <strong data-path-to-node=\"18,0,0\" data-index-in-node=\"160\">exercise</strong>.”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"18,1,0\"><strong data-path-to-node=\"18,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Cảm giác hưng phấn (rush) khi ăn ớt rất giống với cảm giác sau khi tập <strong data-path-to-node=\"18,1,0\" data-index-in-node=\"83\">thể dục</strong> (<strong data-path-to-node=\"18,1,0\" data-index-in-node=\"92\">exercise</strong>) nhờ quá trình giải phóng endorphin.</p>\n</li>\n</ul>\n"}]', 1);
INSERT INTO public.questions VALUES ('71ae584e-2dfe-4a62-bb1a-3be554324289', '31e2014f-e2f4-4fda-bd57-7fc90434527c', 'checkbox', 'Questions 29-30', '', '<p data-start="1671" data-end="1697">Choose <strong>TWO </strong>letters, <strong>A</strong>–<strong>E</strong>.</p>
<p data-start="1699" data-end="1788">Which <strong>TWO </strong>features of his research in Nigeria will Terence discuss in his presentation?</p>', 'multiple_choice', 'null', '[{"correct": false, "option_text": "A. the influence of the sculptures on western artists"}, {"correct": true, "option_text": "B. the uncertainty over who made the sculptures"}, {"correct": false, "option_text": "C. the sources of the materials used for the sculptures"}, {"correct": true, "option_text": "D. the problems he faced in collecting information"}, {"correct": false, "option_text": "E. the original discovery of the sculptures"}]', 'null', 'null', 'null', 3);
INSERT INTO public.questions VALUES ('b71b707e-af3b-4f1b-8d9e-ce7d743377c4', '367db5e7-59ca-49b8-ac61-814fea8c5965', 'matrix', 'Questions 14–20', '', '<p data-start="142" data-end="195">Which paragraph contains the following information?</p>
<p data-start="197" data-end="264">Write the correct letter <strong>A</strong>–<strong>G</strong></p>', 'choose_a_title', 'null', 'null', 'null', '{"layoutType": "simple", "legendTitle": "", "matrixItems": [{"itemText": "an opinion on why the Romans reduced the amount of concrete they made for use in seawater", "correctCategoryLetter": "D"}, {"itemText": "a list of the contents of both Portland and Roman cement", "correctCategoryLetter": "B"}, {"itemText": "an argument for finding substitutes for a limited resource that is used in making cement", "correctCategoryLetter": "F"}, {"itemText": "information about the structure from which the scientists took their Roman concrete samples", "correctCategoryLetter": "A"}, {"itemText": "a comparison of the environmental impacts of making modern and Roman concrete", "correctCategoryLetter": "E"}, {"itemText": "a comparison of the durability of Roman concrete with concrete produced today", "correctCategoryLetter": "G"}, {"itemText": "details of how the Romans used seawater to make concrete", "correctCategoryLetter": "C"}], "matrixCategories": [{"categoryText": "A", "categoryLetter": "A"}, {"categoryText": "B", "categoryLetter": "B"}, {"categoryText": "C", "categoryLetter": "C"}, {"categoryText": "D", "categoryLetter": "D"}, {"categoryText": "E", "categoryLetter": "E"}, {"categoryText": "F", "categoryLetter": "F"}, {"categoryText": "G", "categoryLetter": "G"}]}', '[{"content": "<p data-path-to-node=\"3\"><strong data-path-to-node=\"3\" data-index-in-node=\"0\">14. An opinion on why the Romans reduced the amount of concrete they made… — {D}</strong></p>\n<ul data-path-to-node=\"4\">\n<li>\n<p data-path-to-node=\"4,0,0\"><strong data-path-to-node=\"4,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> <em data-path-to-node=\"4,0,0\" data-index-in-node=\"11\">“‘As the Roman Empire declined, and shipping declined, the need for the seawater concrete declined,’ said Jackson.”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"4,1,0\"><strong data-path-to-node=\"4,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Marie Jackson đưa ra ý kiến rằng khi đế chế và ngành hàng hải suy yếu, nhu cầu sử dụng bê tông nước mặn cũng giảm theo.</p>\n</li>\n</ul>\n<p data-path-to-node=\"5\"><strong data-path-to-node=\"5\" data-index-in-node=\"0\">15. A list of the contents of both Portland and Roman cement — {B}</strong></p>\n<ul data-path-to-node=\"6\">\n<li>\n<p data-path-to-node=\"6,0,0\"><strong data-path-to-node=\"6,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> <em data-path-to-node=\"6,0,0\" data-index-in-node=\"11\">“Portland cement is a compound of <strong data-path-to-node=\"6,0,0\" data-index-in-node=\"45\">calcium, silicates, and hydrates (C-S-H)</strong>… Roman cement contains <strong data-path-to-node=\"6,0,0\" data-index-in-node=\"111\">aluminum</strong>, which is not found in Portland cement, and <strong data-path-to-node=\"6,0,0\" data-index-in-node=\"164\">less silicon</strong>…”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"6,1,0\"><strong data-path-to-node=\"6,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Đoạn B liệt kê các thành phần hóa học cấu tạo nên cả hai loại xi măng để so sánh.</p>\n</li>\n</ul>\n<p data-path-to-node=\"7\"><strong data-path-to-node=\"7\" data-index-in-node=\"0\">16. An argument for finding substitutes for a limited resource… — {F}</strong></p>\n<ul data-path-to-node=\"8\">\n<li>\n<p data-path-to-node=\"8,0,0\"><strong data-path-to-node=\"8,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> <em data-path-to-node=\"8,0,0\" data-index-in-node=\"11\">“‘<strong data-path-to-node=\"8,0,0\" data-index-in-node=\"13\">There is not enough fly ash</strong> in this world to replace half of the Portland cement… Many countries don’t have fly ash, so the idea is to <strong data-path-to-node=\"8,0,0\" data-index-in-node=\"150\">find alternative local materials</strong>…’”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"8,1,0\"><strong data-path-to-node=\"8,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Vì tro bay (fly ash) là nguồn tài nguyên có hạn và không phải quốc gia nào cũng có, tác giả lập luận cần tìm vật liệu thay thế (như tro núi lửa).</p>\n</li>\n</ul>\n<p data-path-to-node=\"9\"><strong data-path-to-node=\"9\" data-index-in-node=\"0\">17. Information about the structure from which the scientists took their samples — {A}</strong></p>\n<ul data-path-to-node=\"10\">\n<li>\n<p data-path-to-node=\"10,0,0\"><strong data-path-to-node=\"10,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> <em data-path-to-node=\"10,0,0\" data-index-in-node=\"11\">“…samples taken from a concrete <strong data-path-to-node=\"10,0,0\" data-index-in-node=\"45\">Roman breakwater</strong>… built out into the sea to protect coasts and harbors… in <strong data-path-to-node=\"10,0,0\" data-index-in-node=\"124\">Pozzuoli Bay near Naples</strong> in Italy…”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"10,1,0\"><strong data-path-to-node=\"10,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Đoạn A mô tả cấu trúc mà các nhà khoa học lấy mẫu là một đê chắn sóng (breakwater) tại vịnh Pozzuoli.</p>\n</li>\n</ul>\n<p data-path-to-node=\"11\"><strong data-path-to-node=\"11\" data-index-in-node=\"0\">18. A comparison of the environmental impacts of making modern and Roman concrete — {E}</strong></p>\n<ul data-path-to-node=\"12\">\n<li>\n<p data-path-to-node=\"12,0,0\"><strong data-path-to-node=\"12,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> <em data-path-to-node=\"12,0,0\" data-index-in-node=\"11\">“Producing Roman concrete also left a <strong data-path-to-node=\"12,0,0\" data-index-in-node=\"49\">smaller carbon footprint</strong> than its modern counterpart. …manufacturing Portland cement accounts for <strong data-path-to-node=\"12,0,0\" data-index-in-node=\"149\">seven percent of the carbon dioxide</strong>…”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"12,1,0\"><strong data-path-to-node=\"12,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Đoạn E so sánh lượng khí thải carbon và tác động môi trường của hai quá trình sản xuất.</p>\n</li>\n</ul>\n<p data-path-to-node=\"13\"><strong data-path-to-node=\"13\" data-index-in-node=\"0\">19. A comparison of the durability of Roman concrete with concrete produced today — {G}</strong></p>\n<ul data-path-to-node=\"14\">\n<li>\n<p data-path-to-node=\"14,0,0\"><strong data-path-to-node=\"14,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> <em data-path-to-node=\"14,0,0\" data-index-in-node=\"11\">“In the middle 20th century, concrete structures were designed to last <strong data-path-to-node=\"14,0,0\" data-index-in-node=\"82\">50 years</strong>… Now we design buildings to last <strong data-path-to-node=\"14,0,0\" data-index-in-node=\"126\">100 to 120 years</strong>. Yet Roman harbor installations have survived <strong data-path-to-node=\"14,0,0\" data-index-in-node=\"189\">2,000 years</strong>…”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"14,1,0\"><strong data-path-to-node=\"14,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Đoạn G so sánh tuổi thọ (độ bền) của bê tông hiện đại (50-120 năm) với bê tông La Mã (2.000 năm).</p>\n</li>\n</ul>\n<p data-path-to-node=\"15\"><strong data-path-to-node=\"15\" data-index-in-node=\"0\">20. Details of how the Romans used seawater to make concrete — {C}</strong></p>\n<ul data-path-to-node=\"16\">\n<li>\n<p data-path-to-node=\"16,0,0\"><strong data-path-to-node=\"16,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> <em data-path-to-node=\"16,0,0\" data-index-in-node=\"11\">“…immersed in <strong data-path-to-node=\"16,0,0\" data-index-in-node=\"27\">seawater</strong>. The seawater instantly triggered a hot chemical reaction. The lime was <strong data-path-to-node=\"16,0,0\" data-index-in-node=\"108\">hydrated by the seawater</strong>…”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"16,1,0\"><strong data-path-to-node=\"16,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Đoạn C mô tả quy trình kỹ thuật: nước biển kích hoạt phản ứng hóa học với vôi và tro núi lửa để kết dính hỗn hợp.</p>\n</li>\n</ul>"}]', 0);
INSERT INTO public.questions VALUES ('d2b0597a-ff8f-4030-b167-fff7185bfb24', '18105999-cf8c-499b-b5bc-cdf0dd0edd6f', 'matching', 'Questions 31-35', NULL, '<p>Complete the summary using the list of words, A-J, below.</p>
', 'matching_features', 'null', 'null', '{"layoutType": "summary", "summaryText": "<p style=\"text-align: center;\"><strong>Bilingual children</strong></p>\r\n<p>It has often been noted that bilingual children acquire the {I ability} to converse in the majority language remarkably quickly. The fact that the mother tongue can disappear at a similar {D rate} is less well understood. This phenomenon depends to a certain extent on the proportion of people with the same linguistic background that have settled in a particular {J area}. If this is limited, children are likely to lose the active use of their mother tongue, and thus no longer employ it even with {F family} although they may still understand it. It follows that teenage children in these circumstances experience a sense of {C dislocation} in relation to all aspects of their lives.</p>", "answerOptions": [{"optionText": "A teachers"}, {"optionText": "B school"}, {"optionText": "C dislocation"}, {"optionText": "D rate"}, {"optionText": "E time"}, {"optionText": "F family"}, {"optionText": "G communication"}, {"optionText": "H type"}, {"optionText": "I ability"}, {"optionText": "J area"}], "matchingItems": null}', 'null', '[{"content": "<h3 data-path-to-node=\"18\">31. It has often been noted that bilingual children acquire the  <strong>I. ability</strong> to converse in the majority language remarkably quickly.</h3>\n<ul data-path-to-node=\"19\">\n<li>\n<p data-path-to-node=\"19,0,0\"><strong>Đáp án:</strong> <strong>I (ability)</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"19,1,0\"><strong>Dẫn chứng:</strong> (Đoạn 7) “Many people marvel at how quickly bilingual children seem to ‘pick up’ conversational skills in the majority language at school…”</p>\n</li>\n<li>\n<p data-path-to-node=\"19,2,0\"><strong>Giải thích:</strong> Trẻ song ngữ tiếp thu <strong>khả năng</strong> (<em>ability</em>) giao tiếp bằng ngôn ngữ đa số rất nhanh.</p>\n</li>\n</ul>\n<h3 data-path-to-node=\"21\">32. The fact that the mother tongue can disappear at a similar  <strong>D. rate</strong> is less well understood.</h3>\n<ul data-path-to-node=\"22\">\n<li>\n<p data-path-to-node=\"22,0,0\"><strong>Đáp án:</strong> <strong>D (rate)</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"22,1,0\"><strong>Dẫn chứng:</strong> (Đoạn 7) “The <strong>extent and rapidity of language loss</strong> will vary according to the concentration of families from a particular linguistic group…”</p>\n</li>\n<li>\n<p data-path-to-node=\"22,2,0\"><strong>Giải thích:</strong> Sự mất mát ngôn ngữ diễn ra với <strong>tốc độ</strong> (<em>rate</em>) đáng lo ngại, nhưng ít được nhận thức rõ.</p>\n</li>\n</ul>\n<h3 data-path-to-node=\"24\">33. This phenomenon depends to a certain extent on the proportion of people with the same linguistic background that have settled in a particular  <strong>J. area</strong>.</h3>\n<ul data-path-to-node=\"25\">\n<li>\n<p data-path-to-node=\"25,0,0\"><strong>Đáp án:</strong> <strong>J (area)</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"25,1,0\"><strong>Dẫn chứng:</strong> (Đoạn 7) “The extent and rapidity of language loss will vary according to the <strong>concentration of families from a particular linguistic group in the neighborhood</strong>.”</p>\n</li>\n<li>\n<p data-path-to-node=\"25,2,0\"><strong>Giải thích:</strong> Sự mất mát ngôn ngữ phụ thuộc vào sự tập trung của cộng đồng ngôn ngữ trong một <strong>khu vực</strong> (<em>area</em> / <em>neighborhood</em>) cụ thể.</p>\n</li>\n</ul>\n<h3 data-path-to-node=\"27\">34. If this is limited, children are likely to lose the active use of their mother tongue, and thus no longer employ it even with  <strong>F. family</strong> although they may still understand it.</h3>\n<ul data-path-to-node=\"28\">\n<li>\n<p data-path-to-node=\"28,0,0\"><strong>Đáp án:</strong> <strong>F (family)</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"28,1,0\"><strong>Dẫn chứng:</strong> (Đoạn 7) “…they will use the majority language in speaking with their peers and siblings and in responding to their <strong>parents</strong>.”</p>\n</li>\n<li>\n<p data-path-to-node=\"28,2,0\"><strong>Giải thích:</strong> Nếu cộng đồng bị phân tán, trẻ em sẽ dùng ngôn ngữ đa số ngay cả khi nói chuyện với bố mẹ (<em>parents</em> / <strong>family</strong>).</p>\n</li>\n</ul>\n<h3 data-path-to-node=\"30\">35. It follows that teenage children in these circumstances experience a sense of  <strong>C. dislocation</strong> in relation to all aspects of their lives.</h3>\n<ul data-path-to-node=\"31\">\n<li>\n<p data-path-to-node=\"31,0,0\"><strong>Đáp án:</strong> <strong>C (dislocation)</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"31,1,0\"><strong>Dẫn chứng:</strong> (Đoạn 7) “By the time children become adolescents, the linguistic division between parents and children has become an emotional chasm. <strong>Pupils frequently become alienated from the cultures of both home and school</strong>, with predictable results.”</p>\n</li>\n<li>\n<p data-path-to-node=\"31,2,0\"><strong>Giải thích:</strong> Sự phân chia ngôn ngữ dẫn đến sự xa lánh (<em>alienated</em>) khỏi cả văn hóa gia đình và trường học, gây ra cảm giác lạc lõng (<em>dislocation</em>).</p>\n</li>\n</ul>\n"}]', 1);
INSERT INTO public.questions VALUES ('54e44872-811c-4e45-aebb-4e8c9e7b96f7', '18105999-cf8c-499b-b5bc-cdf0dd0edd6f', 'radio', 'Questions 36-40', NULL, '<p>Choose <strong>YES</strong> if the statement agrees with the claims of the writer, choose <strong>NO</strong> if the statement contradicts the claims of the writer, or <strong>NOT GIVEN</strong> if it is impossible to say what the writer thinks about this.</p>
', 'multiple_choice_single', '[{"correct": 0, "options": [{"content": "YES"}, {"content": "NO"}, {"content": "NOT GIVEN"}], "question": "Less than half the children who attend kindergarten in Toronto have English as their mother tongue."}, {"correct": 1, "options": [{"content": "YES"}, {"content": "NO"}, {"content": "NOT GIVEN"}], "question": "Research proves that learning the host country language at school can have an adverse effect on a child’s mother tongue."}, {"correct": 2, "options": [{"content": "YES"}, {"content": "NO"}, {"content": "NOT GIVEN"}], "question": "The Foyer programme is to be adopted by the French education system."}, {"correct": 2, "options": [{"content": "YES"}, {"content": "NO"}, {"content": "NOT GIVEN"}], "question": "Bilingual children are taught to tell the time earlier than monolingual children."}, {"correct": 0, "options": [{"content": "YES"}, {"content": "NO"}, {"content": "NOT GIVEN"}], "question": " Bilingual children can eventually apply reading comprehension strategies acquired in one language when reading in the other."}]', 'null', 'null', 'null', '[{"content": "<h3 data-path-to-node=\"36\">36. Less than half the children who attend kindergarten in Toronto have English as their mother tongue.</h3>\n<ul data-path-to-node=\"37\">\n<li>\n<p data-path-to-node=\"37,0,0\"><strong>Đáp án:</strong> <strong>YES</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"37,1,0\"><strong>Dẫn chứng:</strong> (Đoạn 1) “…in the city of Toronto in Canada, <strong>58% of kindergarten pupils come from homes where English is not the language of communication</strong>.”</p>\n</li>\n<li>\n<p data-path-to-node=\"37,2,0\"><strong>Giải thích:</strong> 58% trẻ em không nói tiếng Anh là tiếng mẹ đẻ, nghĩa là <strong>nhiều hơn một nửa</strong> (less than half là sai), do đó phát biểu “Less than half…” là SAI so với thông tin thực tế. Tuy nhiên, trong ma trận trả lời, nếu câu này được đánh dấu <strong>YES</strong> (đồng ý với phát biểu) thì có thể có lỗi trong đáp án gốc, nhưng nếu xét theo nội dung, <strong>58% không phải tiếng Anh</strong> là đúng, suy ra <strong>ít hơn 50%</strong> (42%) có tiếng Anh là tiếng mẹ đẻ. Ta dựa theo nội dung, 58% không phải tiếng Anh, tức là ít hơn 50% có tiếng Anh là tiếng mẹ đẻ, nên câu này <strong>HỢP LÝ</strong> (YES).</p>\n</li>\n</ul>\n<h3 data-path-to-node=\"39\">37. Research proves that learning the host country language at school can have an adverse effect on a child’s mother tongue.</h3>\n<ul data-path-to-node=\"40\">\n<li>\n<p data-path-to-node=\"40,0,0\"><strong>Đáp án:</strong> <strong>NO</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"40,1,0\"><strong>Dẫn chứng:</strong> (Đoạn 5) “One of the most strongly established findings of educational research… is that well-implemented bilingual programs can promote literacy and subject-matter knowledge in a minority language <strong>without any negative effects on children’s development in the majority language</strong>.”</p>\n</li>\n<li>\n<p data-path-to-node=\"40,2,0\"><strong>Giải thích:</strong> Nghiên cứu chứng minh rằng các chương trình song ngữ <strong>không có tác động tiêu cực</strong> (<em>without any negative effects</em>) đến sự phát triển ngôn ngữ đa số. (Mặc dù đoạn 7 nói trẻ em có thể mất khả năng chủ động sử dụng tiếng mẹ đẻ, nhưng nghiên cứu về chương trình song ngữ trong đoạn 5 lại không chỉ ra tác dụng bất lợi. Ta dựa vào kết quả nghiên cứu trong đoạn 5).</p>\n</li>\n</ul>\n<h3 data-path-to-node=\"42\">38. The Foyer programme is to be adopted by the French education system.</h3>\n<ul data-path-to-node=\"43\">\n<li>\n<p data-path-to-node=\"43,0,0\"><strong>Đáp án:</strong> <strong>NOT GIVEN</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"43,1,0\"><strong>Dẫn chứng:</strong> (Đoạn 5) “Within Europe, the Foyer program in Belgium, which develops children’s speaking and literacy abilities in three languages… <strong>most clearly illustrates the benefits</strong> of bilingual and trilingual education.”</p>\n</li>\n<li>\n<p data-path-to-node=\"43,2,0\"><strong>Giải thích:</strong> Chương trình Foyer được sử dụng như một <strong>ví dụ</strong> minh họa lợi ích, nhưng <strong>không có thông tin</strong> về việc hệ thống giáo dục Pháp có kế hoạch áp dụng nó hay không.</p>\n</li>\n</ul>\n<h3 data-path-to-node=\"45\">39. Bilingual children are taught to tell the time earlier than monolingual children.</h3>\n<ul data-path-to-node=\"46\">\n<li>\n<p data-path-to-node=\"46,0,0\"><strong>Đáp án:</strong> <strong>NOT GIVEN</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"46,1,0\"><strong>Dẫn chứng:</strong> (Đoạn 6) “Pupils who know how to tell the time in their mother tongue understand the concept of telling time. In order to tell time in the majority language <strong>they do not need to re-learn the concept</strong>.”</p>\n</li>\n<li>\n<p data-path-to-node=\"46,2,0\"><strong>Giải thích:</strong> Bài đọc nói rằng trẻ em song ngữ không cần học lại khái niệm (concept) khi chuyển sang ngôn ngữ thứ hai, nhưng <strong>không so sánh</strong> chúng được dạy học sớm hơn hay muộn hơn trẻ đơn ngữ.</p>\n</li>\n</ul>\n<h3 data-path-to-node=\"48\">40. Bilingual children can eventually apply reading comprehension strategies acquired in one language when reading in the other.</h3>\n<ul data-path-to-node=\"49\">\n<li>\n<p data-path-to-node=\"49,0,0\"><strong>Đáp án:</strong> <strong>YES</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"49,1,0\"><strong>Dẫn chứng:</strong> (Đoạn 4) “<strong>Children’s knowledge and skills transfer across languages from the mother tongue to the school language.</strong>” và (Đoạn 6) “…there is <strong>transfer across languages in other skills, such as knowing how to distinguish the main idea from the supporting details of a written passage or story</strong>…”</p>\n</li>\n<li>\n<p data-path-to-node=\"49,2,0\"><strong>Giải thích:</strong> Kiến thức và kỹ năng <strong>chuyển giao qua các ngôn ngữ</strong> (<em>transfer across languages</em>), bao gồm cả các kỹ năng nhận biết ý chính (<em>distinguish the main idea</em>) trong văn bản (<em>written passage</em>).</p>\n</li>\n</ul>\n"}]', 2);
INSERT INTO public.questions VALUES ('4a9052ca-5f61-449d-8ffe-1bd0eecdcb57', '2f1d7d96-0abe-41e0-b5af-aaf85101a687', 'radio', 'Questions 16–20', '', '<p data-start="50" data-end="112">Choose the correct letter <strong data-start="98" data-end="111">A, B or C</strong>.</p>', 'multiple_choice', '[{"correct": 2, "options": [{"option_text": "in the theatre"}, {"option_text": "in the sports hall"}, {"option_text": "in the lecture rooms"}], "question": "The drama option takes place"}, {"correct": 0, "options": [{"option_text": "people new to photography."}, {"option_text": "people with special equipment."}, {"option_text": "parents and children."}], "question": "The photography option is reserved for"}, {"correct": 1, "options": [{"option_text": "poetry techniques."}, {"option_text": "short stories."}, {"option_text": "starting a novel."}], "question": "The writing option will focus on"}, {"correct": 2, "options": [{"option_text": "singing classes."}, {"option_text": "going to a concert."}, {"option_text": "giving a performance."}], "question": "The music option involves"}, {"correct": 0, "options": [{"option_text": "the costs the same as last year."}, {"option_text": "lunch costs extra."}, {"option_text": "parents must pay in advance."}], "question": "What information is given about the creche?"}]', 'null', 'null', 'null', 'null', 1);
INSERT INTO public.questions VALUES ('178185e7-c3cc-41ef-92c7-b1435f3f0bc9', '00366bc3-0eea-4499-8f1c-8f87fe104182', 'fillup', 'Question 1 - 10', '<div class="s-block-item s-repeatable-item s-block-sortable-item s-blog-post-section blog-section">
<div class="container">
<div class="sixteen columns">
<div class="s-blog-section-inner">
<div class="s-component s-text ">
<div class="">
<div class="s-component-content s-font-body">
<div class="s-block-item s-repeatable-item s-block-sortable-item s-blog-post-section blog-section">
<div class="container">
<div class="sixteen columns">
<div class="s-blog-section-inner">
<div class="s-component s-text ">
<div class="">
<p class="s-component-content s-font-body">Complete the table below.</p>
<p class="s-component-content s-font-body">Write <strong>NO MORE THAN TWO WORDS AND/OR A NUMBER</strong> for each answer</p>
<p class="s-component-content s-font-body"><span style="font-size: 14pt;"><strong>Rented Properties Information About a House</strong></span></p>
</div>
</div>
</div>
</div>
</div>
</div>
<div class="s-block-item s-repeatable-item s-block-sortable-item s-blog-post-section blog-section">
<div class="container">
<div class="sixteen columns">
<div class="s-blog-section-inner">
<div class="s-component s-text ">
<div class="">
<div class="s-component-content s-font-body"> </div>
<div class="s-component-content s-font-body"><strong>Available date</strong> {5 May|5th May|May 5|May 5th}</div>
<div class="s-component-content s-font-body"> </div>
<p><strong>Prices</strong>:</p>
<p>• Rent : $ {1700} per month</p>
<p>• Desposlt: $1500</p>
<p>• {credit check|credit cheque} :$15</p>
<div class="s-component-content s-font-body">
<p><strong>Facilities</strong>:</p>
<p>• 3 bedroom and 2 bathrooms</p>
<p>• A remodelled {kitchen|shared kitchen} .</p>
<p>• No {dishwasher}.</p>
<p>• A {garage} with a work area</p>
<p><strong>Utilities</strong></p>
<p>• The landlord will provide landscaping service, but the tenants must {water} the grass</p>
<p>• The tenants should pay $15 for trasing and {recycling} Service.</p>
<p>• The tenants should pay for electricity water and gas bills.</p>
<p><strong>Other information</strong></p>
<p>• There is no central air conditions, but there is a {window} Conditioning unit.</p>
<p>• Name of landlord: Sam {Dressler} .</p>
</div>
</div>
</div>
</div>
</div>
</div>
</div>
</div>
</div>
</div>
</div>
</div>
</div>
</div>', NULL, 'summary_completion', 'null', 'null', 'null', 'null', '[{"content": "<p data-path-to-node=\"2\"><span style=\"font-size: 14pt;\"><strong data-path-to-node=\"2\" data-index-in-node=\"0\">PART 1: HOUSE RENTAL ENQUIRY</strong></span></p>\n<p data-path-to-node=\"3\"><strong data-path-to-node=\"3\" data-index-in-node=\"0\">Landlord:</strong> Hello?</p>\n<p data-path-to-node=\"4\"><strong data-path-to-node=\"4\" data-index-in-node=\"0\">Sam:</strong> Oh, hello. I wanted to enquire about the house you’re going to let out. Is it still available?</p>\n<p data-path-to-node=\"5\"><strong data-path-to-node=\"5\" data-index-in-node=\"0\">Landlord:</strong> Yes. May I ask where you heard about it? Was it in an advert?</p>\n<p data-path-to-node=\"6\"><strong data-path-to-node=\"6\" data-index-in-node=\"0\">Sam:</strong> Right, it was.</p>\n<p data-path-to-node=\"7\"><strong data-path-to-node=\"7\" data-index-in-node=\"0\">Landlord:</strong> OK. What do you want to know?</p>\n<p id=\"p-rc_d0b521f4c47044ad-40\" data-path-to-node=\"8\"><strong data-path-to-node=\"8\" data-index-in-node=\"0\">Sam:</strong> <span class=\"citation-137 citation-end-137\">Well, I’m going to share the house with two friends. We’ve been staying on campus, but we’re going to graduate, so we need to find a house as soon as possible anyway. Could you tell me the exact date when you can move in?</span></p>\n<p data-path-to-node=\"9\"><strong data-path-to-node=\"9\" data-index-in-node=\"0\">Landlord:</strong> Well, the contract with my current tenant is due next week on May the 3rd, and I need a day to clean and check the things in the house. So I think the house will be ready on the <span style=\"background-color: #f1c40f;\"><strong data-path-to-node=\"9\" data-index-in-node=\"188\">(1) 5th of May</strong></span>. Is that okay?</p>\n<p data-path-to-node=\"10\"><strong data-path-to-node=\"10\" data-index-in-node=\"0\">Sam:</strong> Yes, that will be fine. And what we’re most concerned about is the rent. We’d like something around $500 a month for each of us, but we could go up to $600 if we have to, but we can’t go beyond that.</p>\n<p data-path-to-node=\"11\"><strong data-path-to-node=\"11\" data-index-in-node=\"0\">Landlord:</strong> You are lucky. The rent will be <strong data-path-to-node=\"11\" data-index-in-node=\"42\"><span style=\"background-color: #f1c40f;\">(2) 1700</span> </strong>dollars in total, which is within your budget. You’ll need to pay monthly to me by cash or credit card, I don’t mind. And you’ll have to pay me 1500 dollars as a deposit before you move in. Deposit is as insurance in case you break something.</p>\n<p data-path-to-node=\"12\"><strong data-path-to-node=\"12\" data-index-in-node=\"0\">Sam:</strong> Okay, that’s reasonable.</p>\n<p data-path-to-node=\"13\"><strong data-path-to-node=\"13\" data-index-in-node=\"0\">Landlord:</strong> Oh, I nearly forgot one important thing. Is that you’ll be required to provide a <span style=\"background-color: #f1c40f;\"><strong data-path-to-node=\"13\" data-index-in-node=\"91\">(3) credit check</strong> </span>to guarantee your ability to pay the rent every month. This will charge you $15.</p>\n<p data-path-to-node=\"14\"><strong data-path-to-node=\"14\" data-index-in-node=\"0\">Sam:</strong> No problem. How about the facilities?</p>\n<p data-path-to-node=\"15\"><strong data-path-to-node=\"15\" data-index-in-node=\"0\">Landlord:</strong> First, there are three bedrooms combined with two bathrooms. Then there is a shared <span style=\"background-color: #f1c40f;\"><strong data-path-to-node=\"15\" data-index-in-node=\"94\">(4) kitchen</strong></span>, which was refurbished several months ago. By the way, do you cook yourselves?</p>\n<p data-path-to-node=\"16\"><strong data-path-to-node=\"16\" data-index-in-node=\"0\">Sam:</strong> Yeah, we like cooking. Do we have to buy our own cookers?</p>\n<p data-path-to-node=\"17\"><strong data-path-to-node=\"17\" data-index-in-node=\"0\">Landlord:</strong> Basic facilities for cooking are available. But if you want a <span style=\"background-color: #f1c40f;\"><strong data-path-to-node=\"17\" data-index-in-node=\"72\">(5) dishwasher</strong>,</span> I’m sorry, it needs to be added later.</p>\n<p data-path-to-node=\"18\"><strong data-path-to-node=\"18\" data-index-in-node=\"0\">Sam:</strong> I think the basic facilities are enough for us. Is there any place we can park, as one of my friends has a private car?</p>\n<p data-path-to-node=\"19\"><strong data-path-to-node=\"19\" data-index-in-node=\"0\">Landlord:</strong> Yes, there is a <span style=\"background-color: #f1c40f;\"><strong data-path-to-node=\"19\" data-index-in-node=\"26\">(6) garage</strong></span>, which not only provides space for your car but also has a special section where you can do some of your work. It’s very quiet for you to concentrate.</p>\n<p data-path-to-node=\"20\"><strong data-path-to-node=\"20\" data-index-in-node=\"0\">Sam:</strong> It sounds so special.</p>\n<p data-path-to-node=\"22\"><strong data-path-to-node=\"22\" data-index-in-node=\"0\">Landlord:</strong> There are some other utilities I have to tell you. There is a garden in front of the house, in which you will find some interesting plants and beautiful flowers.</p>\n<p data-path-to-node=\"23\"><strong data-path-to-node=\"23\" data-index-in-node=\"0\">Sam:</strong> Do we have to take care of these plants and flowers?</p>\n<p data-path-to-node=\"24\"><strong data-path-to-node=\"24\" data-index-in-node=\"0\">Landlord:</strong> Well, you don’t have to worry about that. There will be a professional gardener to do the landscaping in the garden regularly. But you do need to help <span style=\"background-color: #f1c40f;\"><strong data-path-to-node=\"24\" data-index-in-node=\"161\">(7) water</strong></span> the grass once a week. Is it a problem for you?</p>\n<p data-path-to-node=\"25\"><strong data-path-to-node=\"25\" data-index-in-node=\"0\">Sam:</strong> Of course not, we’d like to do that.</p>\n<p data-path-to-node=\"26\"><strong data-path-to-node=\"26\" data-index-in-node=\"0\">Landlord:</strong> Another thing is in this district, every household is arranged with a cleaner responsible for cleaning up the rubbish and<span style=\"background-color: #f1c40f;\"> <strong data-path-to-node=\"26\" data-index-in-node=\"132\">(8) recycling</strong></span>. But this service will cost you $15 every month.</p>\n<p data-path-to-node=\"27\"><strong data-path-to-node=\"27\" data-index-in-node=\"0\">Sam:</strong> What other bills do we have to pay?</p>\n<p data-path-to-node=\"28\"><strong data-path-to-node=\"28\" data-index-in-node=\"0\">Landlord:</strong> Bills for electricity, water and gas will also be covered by yourselves.</p>\n<p data-path-to-node=\"29\"><strong data-path-to-node=\"29\" data-index-in-node=\"0\">Sam:</strong> OK, one more question. Is air conditioning available in the house?</p>\n<p data-path-to-node=\"30\"><strong data-path-to-node=\"30\" data-index-in-node=\"0\">Landlord:</strong> If you mean central air conditioning, I’m afraid there isn’t at the moment. But each room has a conditioning unit which is installed on the <span style=\"background-color: #f1c40f;\"><strong data-path-to-node=\"30\" data-index-in-node=\"150\">(9) window</strong></span>.</p>\n<p data-path-to-node=\"31\"><strong data-path-to-node=\"31\" data-index-in-node=\"0\">Sam:</strong> That will be fine anyway. I think it’s a good place to live in. Can we go and see the house, please?</p>\n<p data-path-to-node=\"32\"><strong data-path-to-node=\"32\" data-index-in-node=\"0\">Landlord:</strong> Yes, of course. May I have your name and phone number?</p>\n<p data-path-to-node=\"33\"><strong data-path-to-node=\"33\" data-index-in-node=\"0\">Sam:</strong> Yes, I’m Sam <span style=\"background-color: #f1c40f;\"><strong data-path-to-node=\"33\" data-index-in-node=\"18\">(10) Dressler</strong></span>. That’s S-A-M, D-R-E-double S-L-E-R.</p>\n<p data-path-to-node=\"34\"><strong data-path-to-node=\"34\" data-index-in-node=\"0\">Landlord:</strong> Okay, Sam Dressler, I’ve got that down. And my phone number is 6 7 5 3 4 5 7 1.</p>\n<p data-path-to-node=\"35\"><strong data-path-to-node=\"35\" data-index-in-node=\"0\">Sam:</strong> Thank you very much. I’ll contact you after discussing it with my two friends.</p>\n<p data-path-to-node=\"36\"><strong data-path-to-node=\"36\" data-index-in-node=\"0\">Landlord:</strong> No problem. Bye bye.</p>"}]', 0);
INSERT INTO public.questions VALUES ('bdbb1580-2cc3-4ee9-85c7-a291ef0ee501', '3796130c-e716-4ead-8b73-7192931245c0', 'checkbox', 'Questions 17 and 18', '', '<p><span class="citation-979 citation-980">Choose </span><strong data-path-to-node="10" data-index-in-node="7"><span class="citation-979 citation-980">TWO</span></strong><span class="citation-979 citation-980"> letters, </span><strong data-path-to-node="10" data-index-in-node="20"><span class="citation-979 citation-980">A-E</span></strong><span class="citation-979 citation-980 citation-end-980">.<sup class="superscript" data-turn-source-index="26"><!----></sup></span><span class="citation-979 citation-end-979"><sup class="superscript" data-turn-source-index="27"><!----></sup></span></p>
<p><span class="citation-977 citation-978">Which </span><strong data-path-to-node="10" data-index-in-node="31"><span class="citation-977 citation-978">TWO</span></strong><span class="citation-977 citation-978 citation-end-978"> useful features of the Photo Safari tour does John mention?<sup class="superscript" data-turn-source-index="28"><!----></sup></span><span class="citation-977 citation-end-977"><sup class="superscript" data-turn-source-index="29"><!----></sup></span></p>', 'multiple_choice', 'null', '[{"correct": false, "option_text": "A the photography classes"}, {"correct": true, "option_text": "B having space to store equipment"}, {"correct": false, "option_text": "C the high standard of accommodation"}, {"correct": true, "option_text": "D the quality of the food"}, {"correct": false, "option_text": "E the airport pick-up service"}]', 'null', 'null', 'null', 1);
INSERT INTO public.questions VALUES ('2cb06696-9337-49fa-a614-01e626a3083c', 'f41a1990-06b7-4b6b-8774-ba668ad5a476', 'matching', 'Questions 31-35', '', '<p>Complete the summary using the list of words, <strong>A</strong>-<strong>H</strong>, below.</p>', 'summary_completion', 'null', 'null', '{"layoutType": "summary", "summaryText": "<p style=\"text-align: center;\"><strong>The Curve Theatre</strong></p>\n<p>The Curve Theatre is an inside-out theatre: much of what goes on inside the theatre is {E. on view}, to the public. This has been achieved through the use of transparent materials for the {D. public} of the exterior and the fact that there are no walls dividing the actor and audience spaces inside. In addition, the bottom part of the main auditorium can be raised to reveal {H. behind-the-scenes} activities to people on the street, while {F. large} vehicle carrying equipment can drive right into the building. For the actors, {G. curtain} performances will begin as soon as they leave their dressing rooms</p>", "answerOptions": [{"optionText": "A. unknown"}, {"optionText": "B. local"}, {"optionText": "C. construction"}, {"optionText": "D. public"}, {"optionText": "E. on view"}, {"optionText": "F. large"}, {"optionText": "G. curtain"}, {"optionText": "H. behind-the-scenes"}], "matchingItems": []}', 'null', '[{"content": "<p data-path-to-node=\"7,0,0\"><strong data-path-to-node=\"7,0,0\" data-index-in-node=\"0\">Câu 31: E. on view</strong></p>\n<ul data-path-to-node=\"7,0,1\">\n<li>\n<p data-path-to-node=\"7,0,1,0,0\"><strong data-path-to-node=\"7,0,1,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> <em data-path-to-node=\"7,0,1,0,0\" data-index-in-node=\"11\">“the usual demarcations between on-stage and backstage… have been <strong data-path-to-node=\"7,0,1,0,0\" data-index-in-node=\"79\">erased</strong>“</em> và <em data-path-to-node=\"7,0,1,0,0\" data-index-in-node=\"90\">“process of performance is itself <strong data-path-to-node=\"7,0,1,0,0\" data-index-in-node=\"124\">revealed</strong>.”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"7,0,1,1,0\"><strong data-path-to-node=\"7,0,1,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Mọi hoạt động bên trong đều được “phơi bày” hoặc “hiển thị” cho công chúng thấy.</p>\n</li>\n</ul>\n<p data-path-to-node=\"7,1,0\"><strong data-path-to-node=\"7,1,0\" data-index-in-node=\"0\">Câu 32: D. public</strong> (Lưu ý: Ngữ cảnh này nói về phần <strong data-path-to-node=\"7,1,0\" data-index-in-node=\"51\">exterior</strong>)</p>\n<ul data-path-to-node=\"7,1,1\">\n<li>\n<p data-path-to-node=\"7,1,1,0,0\"><strong data-path-to-node=\"7,1,1,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> <em data-path-to-node=\"7,1,1,0,0\" data-index-in-node=\"11\">“sweeping lines and four-storey <strong data-path-to-node=\"7,1,1,0,0\" data-index-in-node=\"43\">glass front</strong>“</em></p>\n</li>\n<li>\n<p data-path-to-node=\"7,1,1,1,0\"><strong data-path-to-node=\"7,1,1,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Việc sử dụng vật liệu trong suốt cho mặt tiền công cộng (public exterior/front) giúp xóa nhòa ranh giới.</p>\n</li>\n</ul>\n<p data-path-to-node=\"7,2,0\"><strong data-path-to-node=\"7,2,0\" data-index-in-node=\"0\">Câu 33: H. behind-the-scenes</strong></p>\n<ul data-path-to-node=\"7,2,1\">\n<li>\n<p data-path-to-node=\"7,2,1,0,0\"><strong data-path-to-node=\"7,2,1,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> <em data-path-to-node=\"7,2,1,0,0\" data-index-in-node=\"11\">“…can be raised so that passers-by can see <strong data-path-to-node=\"7,2,1,0,0\" data-index-in-node=\"56\">stagehands at work</strong>.”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"7,2,1,1,0\"><strong data-path-to-node=\"7,2,1,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Việc nhìn thấy nhân viên sân khấu đang làm việc chính là nhìn thấy các hoạt động “hậu trường” (behind-the-scenes).</p>\n</li>\n</ul>\n<p data-path-to-node=\"7,3,0\"><strong data-path-to-node=\"7,3,0\" data-index-in-node=\"0\">Câu 34: F. large</strong></p>\n<ul data-path-to-node=\"7,3,1\">\n<li>\n<p data-path-to-node=\"7,3,1,0,0\"><strong data-path-to-node=\"7,3,1,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> <em data-path-to-node=\"7,3,1,0,0\" data-index-in-node=\"11\">“…the great <strong data-path-to-node=\"7,3,1,0,0\" data-index-in-node=\"25\">pantechnicon transporter</strong> reverses in…”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"7,3,1,1,0\"><strong data-path-to-node=\"7,3,1,1,0\" data-index-in-node=\"0\">Giải thích:</strong> “Pantechnicon transporter” là một loại xe tải vận chuyển rất lớn (large vehicle).</p>\n</li>\n</ul>\n<p data-path-to-node=\"7,4,0\"><strong data-path-to-node=\"7,4,0\" data-index-in-node=\"0\">Câu 35: G. curtain</strong> (Lưu ý: Dẫn chứng về việc không có sự ngăn cách)</p>\n<ul data-path-to-node=\"7,4,1\">\n<li>\n<p data-path-to-node=\"7,4,1,0,0\"><strong data-path-to-node=\"7,4,1,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> <em data-path-to-node=\"7,4,1,0,0\" data-index-in-node=\"11\">“actors walk across a public section… <strong data-path-to-node=\"7,4,1,0,0\" data-index-in-node=\"51\">no permanent formal separation</strong>… theatre without boundaries.”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"7,4,1,1,0\"><strong data-path-to-node=\"7,4,1,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Vì không có ranh giới, buổi diễn như thể bắt đầu ngay khi họ bước ra khỏi phòng thay đồ mà không cần tấm màn (curtain) che chắn truyền thống. (Tuy nhiên, trong một số đề khác, ý này có thể hiểu là các buổi diễn “không chính thức” hoặc “ngẫu hứng”).</p>\n</li>\n</ul>"}]', 1);
INSERT INTO public.questions VALUES ('2f29359e-11ee-45ff-a3b4-39bbae3edb50', 'f41a1990-06b7-4b6b-8774-ba668ad5a476', 'radio', 'Questions 36-40', '', '<p data-path-to-node="37,0,0">Choose<strong data-path-to-node="37,0,0" data-index-in-node="0"> YES</strong> if the statement agrees with the claims of the writer,<strong data-path-to-node="37,1,0" data-index-in-node="0">NO</strong> if the statement contradicts the claims of the writer,<strong data-path-to-node="37,2,0" data-index-in-node="0">NOT GIVEN</strong> if it is impossible to say what the writer thinks about this</p>', 'yes_no_not_given', '[{"correct": 0, "options": [{"option_text": "YES"}, {"option_text": "NO"}, {"option_text": "NOT GIVEN"}], "question": "A range of different theatrical experiences will be possible at the Curve Theatre."}, {"correct": 2, "options": [{"option_text": "YES"}, {"option_text": "NO"}, {"option_text": "NOT GIVEN"}], "question": "The opening of the Curve Theatre will lead to the closure of other theatres in the region."}, {"correct": 0, "options": [{"option_text": "YES"}, {"option_text": "NO"}, {"option_text": "NOT GIVEN"}], "question": "There are other buildings in the world that can be compared to the Curve Theatre."}, {"correct": 1, "options": [{"option_text": "YES"}, {"option_text": "NO"}, {"option_text": "NOT GIVEN"}], "question": "Vinoly''s plans for Battersea have proved popular with the public."}, {"correct": 2, "options": [{"option_text": "YES"}, {"option_text": "NO"}, {"option_text": "NOT GIVEN"}], "question": "The Curve Theatre will suit the style of Paul Kerryson''s productions."}]', 'null', 'null', 'null', '[{"content": "<p data-path-to-node=\"4\"><strong data-path-to-node=\"4\" data-index-in-node=\"0\">36. A range of different theatrical experiences will be possible at the Curve Theatre. — {YES}</strong></p>\n<ul data-path-to-node=\"5\">\n<li>\n<p data-path-to-node=\"5,0,0\"><strong data-path-to-node=\"5,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> <em data-path-to-node=\"5,0,0\" data-index-in-node=\"11\">“…the theatrical potential of the building is considerable, as the various ‘curtains’ of the stage can be <strong data-path-to-node=\"5,0,0\" data-index-in-node=\"119\">manipulated</strong> and stage areas and seating <strong data-path-to-node=\"5,0,0\" data-index-in-node=\"159\">adjusted</strong>.”</em> (Đoạn 9)</p>\n</li>\n<li>\n<p data-path-to-node=\"5,1,0\"><strong data-path-to-node=\"5,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Khả năng điều chỉnh linh hoạt khu vực sân khấu, chỗ ngồi và các tấm màn ngăn cách cho phép nhà hát tạo ra nhiều loại hình trải nghiệm sân khấu khác nhau. Tác giả khẳng định tiềm năng này là rất lớn (<em data-path-to-node=\"5,1,0\" data-index-in-node=\"211\">considerable</em>).</p>\n</li>\n</ul>\n<p data-path-to-node=\"6\"><strong data-path-to-node=\"6\" data-index-in-node=\"0\">37. The opening of the Curve Theatre will lead to the closure of other theatres in the region. — {NOT GIVEN}</strong></p>\n<ul data-path-to-node=\"7\">\n<li>\n<p data-path-to-node=\"7,0,0\"><strong data-path-to-node=\"7,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> Đoạn 3 nhắc đến việc nhà hát Haymarket đã đóng cửa từ năm 2006 (trước khi Curve mở cửa). Đoạn 9 nói Curve sẽ có sức hút lớn trong khu vực (<em data-path-to-node=\"7,0,0\" data-index-in-node=\"150\">regional pre-eminence, and pulling power</em>).</p>\n</li>\n<li>\n<p data-path-to-node=\"7,1,0\"><strong data-path-to-node=\"7,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Mặc dù Curve có sức mạnh cạnh tranh lớn, nhưng tác giả <strong data-path-to-node=\"7,1,0\" data-index-in-node=\"67\">không hề đưa ra khẳng định hay dự đoán</strong> rằng nó sẽ làm cho các nhà hát khác trong vùng phải <strong data-path-to-node=\"7,1,0\" data-index-in-node=\"158\">đóng cửa</strong> (<em data-path-to-node=\"7,1,0\" data-index-in-node=\"168\">closure</em>).</p>\n</li>\n</ul>\n<p data-path-to-node=\"8\"><strong data-path-to-node=\"8\" data-index-in-node=\"0\">38. There are other buildings in the world that can be compared to the Curve Theatre. — {YES}</strong></p>\n<ul data-path-to-node=\"9\">\n<li>\n<p data-path-to-node=\"9,0,0\"><strong data-path-to-node=\"9,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> <em data-path-to-node=\"9,0,0\" data-index-in-node=\"11\">“…it <strong data-path-to-node=\"9,0,0\" data-index-in-node=\"18\">repeats aspects</strong> of the sweeping formal bravado of Vinoly’s <strong data-path-to-node=\"9,0,0\" data-index-in-node=\"77\">Tokyo International Forum</strong> and takes its self-dramatizing cue from the <strong data-path-to-node=\"9,0,0\" data-index-in-node=\"147\">Kimmel Center</strong>… in Philadelphia.”</em> (Đoạn 10)</p>\n</li>\n<li>\n<p data-path-to-node=\"9,1,0\"><strong data-path-to-node=\"9,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Tác giả trực tiếp so sánh Curve với hai tòa nhà khác ở Nhật Bản (Tokyo) và Mỹ (Philadelphia). Do đó, việc nói có những tòa nhà khác có thể so sánh được là hoàn toàn chính xác theo ý kiến tác giả.</p>\n</li>\n</ul>\n<p data-path-to-node=\"10\"><strong data-path-to-node=\"10\" data-index-in-node=\"0\">39. Vinoly’s plans for Battersea have proved popular with the public. — {NO}</strong></p>\n<ul data-path-to-node=\"11\">\n<li>\n<p data-path-to-node=\"11,0,0\"><strong data-path-to-node=\"11,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> <em data-path-to-node=\"11,0,0\" data-index-in-node=\"11\">“…and (<strong data-path-to-node=\"11,0,0\" data-index-in-node=\"20\">if the outraged protests die out</strong>) a vast carbon-neutral scheme next to Battersea power station…”</em> (Đoạn 11)</p>\n</li>\n<li>\n<p data-path-to-node=\"11,1,0\"><strong data-path-to-node=\"11,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Cụm từ “outraged protests” (những cuộc biểu tình đầy phẫn nộ) chứng tỏ kế hoạch này đang bị phản đối dữ dội, trái ngược hoàn toàn với việc nó “được công chúng yêu thích” (<em data-path-to-node=\"11,1,0\" data-index-in-node=\"183\">popular with the public</em>).</p>\n</li>\n</ul>\n<p data-path-to-node=\"12\"><strong data-path-to-node=\"12\" data-index-in-node=\"0\">40. The Curve Theatre will suit the style of Paul Kerryson’s productions. — {NOT GIVEN}</strong></p>\n<ul data-path-to-node=\"13\">\n<li>\n<p data-path-to-node=\"13,0,0\"><strong data-path-to-node=\"13,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> <em data-path-to-node=\"13,0,0\" data-index-in-node=\"11\">“He’s got what he wanted, a theatre without boundaries: <strong data-path-to-node=\"13,0,0\" data-index-in-node=\"67\">what will he do with it?</strong>“</em> (Câu cuối cùng của bài)</p>\n</li>\n<li>\n<p data-path-to-node=\"13,1,0\"><strong data-path-to-node=\"13,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Tác giả cho biết Paul Kerryson đã có được kiểu nhà hát mà ông ấy muốn (không ranh giới), nhưng tác giả kết thúc bằng một câu hỏi bỏ ngỏ: “Ông ấy sẽ làm gì với nó?”. Tác giả <strong data-path-to-node=\"13,1,0\" data-index-in-node=\"185\">không khẳng định</strong> liệu nhà hát này có thực sự phù hợp (<em data-path-to-node=\"13,1,0\" data-index-in-node=\"239\">suit</em>) với phong cách dàn dựng của Paul hay không, mà chỉ coi đó là một thử thách (<em data-path-to-node=\"13,1,0\" data-index-in-node=\"321\">challenge</em>) dành cho vị đạo diễn này.</p>\n</li>\n</ul>"}]', 2);
INSERT INTO public.questions VALUES ('872e40c8-61f4-4ffc-afb7-f4cb38e02b3d', 'e40aeb2d-7c6c-44d0-ad4f-2d8e302dfb9c', 'radio', 'Questions 1–7', NULL, '<p>Choose <strong>TRUE </strong>if the statement agrees with the information given in the text, choose <strong>FALSE </strong>if the statement contradicts the information, or choose <strong>NOT GIVEN</strong> if there is no information on this.</p>', 'multiple-choice', '[{"correct": 1, "options": [{"content": "TRUE"}, {"content": "FALSE"}, {"content": "NOT GIVEN"}], "question": "Before attending college Jacob was capable of recognising people he knew well."}, {"correct": 0, "options": [{"content": "TRUE"}, {"content": "FALSE"}, {"content": "NOT GIVEN"}], "question": "Researchers believe that prosopagnosia may be a growing problem."}, {"correct": 2, "options": [{"content": "TRUE"}, {"content": "FALSE"}, {"content": "NOT GIVEN"}], "question": "It is harder to identify developmental prosapagnosics in babies than in young children."}, {"correct": 0, "options": [{"content": "TRUE"}, {"content": "FALSE"}, {"content": "NOT GIVEN"}], "question": "A German study seems to support the Harvard and UCL research findings."}, {"correct": 1, "options": [{"content": "TRUE"}, {"content": "FALSE"}, {"content": "NOT GIVEN"}], "question": "In general, prosopagnosics are aware that other people can recognize faces more easily than they can."}, {"correct": 0, "options": [{"option_text": "TRUE"}, {"option_text": "FALSE"}, {"option_text": "NOT GIVEN"}], "question": "In most cases, prosopagnosics have developed ways to deal with their problem."}, {"correct": 2, "options": [{"option_text": "TRUE"}, {"option_text": "FALSE"}, {"option_text": "NOT GIVEN"}], "question": "The study of prosopagnosia may help neuroscientists to treat different kinds of brain injury."}]', 'null', 'null', 'null', '[{"content": "<h3 data-path-to-node=\"4\">1. Before attending college Jacob was capable of recognising people he knew well.</h3>\n<ul data-path-to-node=\"5\">\n<li>\n<p data-path-to-node=\"5,0,0\"><strong>Đáp án:</strong> <strong>FALSE</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"5,1,0\"><strong>Dẫn chứng:</strong> (Đoạn 2) “He had had the same trouble all his life. Friends and relatives would greet him and he would have <strong>no idea who they were</strong>.”</p>\n</li>\n<li>\n<p data-path-to-node=\"5,2,0\"><strong>Giải thích:</strong> Jacob đã gặp vấn đề nhận dạng người thân và bạn bè (<em>people he knew well</em>) <strong>suốt đời</strong>, mâu thuẫn với việc có khả năng nhận ra họ.</p>\n</li>\n</ul>\n<h3 data-path-to-node=\"7\">2. Researchers believe that prosopagnosia may be a growing problem.</h3>\n<ul data-path-to-node=\"8\">\n<li>\n<p data-path-to-node=\"8,0,0\"><strong>Đáp án:</strong> <strong>TRUE</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"8,1,0\"><strong>Dẫn chứng:</strong> (Đoạn 3 &amp; 4) Việc khám phá ra <strong>dạng thứ hai</strong> (<em>developmental prosopagnosia</em>) cùng các khảo sát cho thấy tỷ lệ lên tới 2-2.5% (một con số lớn hơn nhiều so với “a few dozen cases” trước đây), cho thấy đây là một <strong>vấn đề lớn hơn/phổ biến hơn</strong> (<em>growing problem</em> về mặt nhận thức) so với suy nghĩ ban đầu.</p>\n</li>\n<li>\n<p data-path-to-node=\"8,2,0\"><strong>Giải thích:</strong> Mặc dù bài đọc không dùng từ “growing”, nhưng ngữ cảnh khám phá ra tỷ lệ cao bất ngờ cho thấy các nhà nghiên cứu nhận thấy đây là một vấn đề có tầm quan trọng <strong>đang gia tăng</strong>.</p>\n</li>\n</ul>\n<h3 data-path-to-node=\"10\">3. It is harder to identify developmental prosopagnosics in babies than in young children.</h3>\n<ul data-path-to-node=\"11\">\n<li>\n<p data-path-to-node=\"11,0,0\"><strong>Đáp án:</strong> <strong>NOT GIVEN</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"11,1,0\"><strong>Dẫn chứng:</strong> Bài đọc đề cập đến chứng bệnh này có thể có từ khi sinh ra (<em>present from birth</em>), nhưng <strong>không so sánh</strong> mức độ khó khăn trong việc xác định chứng bệnh giữa trẻ sơ sinh và trẻ nhỏ.</p>\n</li>\n<li>\n<p data-path-to-node=\"11,2,0\"><strong>Giải thích:</strong> Thiếu thông tin so sánh trực tiếp mức độ khó khăn giữa hai nhóm tuổi.</p>\n</li>\n</ul>\n<h3 data-path-to-node=\"13\">4. A German study seems to support the Harvard and UCL research findings.</h3>\n<ul data-path-to-node=\"14\">\n<li>\n<p data-path-to-node=\"14,0,0\"><strong>Đáp án:</strong> <strong>TRUE</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"14,1,0\"><strong>Dẫn chứng:</strong> (Đoạn 4) Nghiên cứu của Đức đã <strong>“similarly reported”</strong> (báo cáo tương tự) rằng 2.5% học sinh gặp vấn đề nhận dạng khuôn mặt.</p>\n</li>\n<li>\n<p data-path-to-node=\"14,2,0\"><strong>Giải thích:</strong> Việc báo cáo kết quả <strong>tương tự</strong> (<em>similarly reported</em>) cho thấy nghiên cứu của Đức ủng hộ các phát hiện của Harvard và UCL.</p>\n</li>\n</ul>\n<h3 data-path-to-node=\"16\">5. In general, prosopagnosics are aware that other people can recognize faces more easily than they can.</h3>\n<ul data-path-to-node=\"17\">\n<li>\n<p data-path-to-node=\"17,0,0\"><strong>Đáp án:</strong> <strong>FALSE</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"17,1,0\"><strong>Dẫn chứng:</strong> (Đoạn 5) “…they <strong>often don’t realise that other people have better recognition skills than they do</strong>.”</p>\n</li>\n<li>\n<p data-path-to-node=\"17,2,0\"><strong>Giải thích:</strong> Người mắc chứng mù mặt thường <strong>không nhận ra</strong> (<em>don’t realise</em>) rằng người khác có kỹ năng nhận dạng khuôn mặt tốt hơn họ, mâu thuẫn với việc họ “nhận thức được” (<em>aware</em>).</p>\n</li>\n</ul>\n<h3 data-path-to-node=\"19\">6. In most cases, prosopagnosics have developed ways to deal with their problem.</h3>\n<ul data-path-to-node=\"20\">\n<li>\n<p data-path-to-node=\"20,0,0\"><strong>Đáp án:</strong> <strong>TRUE</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"20,1,0\"><strong>Dẫn chứng:</strong> (Đoạn 6) “<strong>the majority of developmental prosopagnosics possess strategies that allow them to get around their difficulty</strong>“</p>\n</li>\n<li>\n<p data-path-to-node=\"20,2,0\"><strong>Giải thích:</strong> Phần lớn người mắc chứng mù mặt (<em>majority</em>) đã phát triển các <strong>chiến lược</strong> (<em>strategies</em> / ways to deal with their problem) để vượt qua khó khăn.</p>\n</li>\n</ul>\n<h3 data-path-to-node=\"22\">7. The study of prosopagnosia may help neuroscientists to treat different kinds of brain injury.</h3>\n<ul data-path-to-node=\"23\">\n<li>\n<p data-path-to-node=\"23,0,0\"><strong>Đáp án:</strong> <strong>NOT GIVEN</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"23,1,0\"><strong>Dẫn chứng:</strong> (Đoạn 6) “…This difference, they believe, could help <strong>solve the problem of how the brain deals with information in general</strong>: not just visual data.”</p>\n</li>\n<li>\n<p data-path-to-node=\"23,2,0\"><strong>Giải thích:</strong> Văn bản khẳng định nghiên cứu này có thể giúp giải quyết vấn đề về cách bộ não xử lý thông tin <strong>nói chung</strong>. Tuy nhiên, nó <strong>không nói rõ</strong> rằng điều này sẽ trực tiếp dẫn đến việc <strong>điều trị</strong> (<em>treat</em>) các loại <strong>chấn thương não khác nhau</strong> (<em>different kinds of brain injury</em>).</p>\n</li>\n</ul>"}]', 0);
INSERT INTO public.questions VALUES ('4be64f4c-2629-46cb-bcf6-eec71f0b90f1', 'e40aeb2d-7c6c-44d0-ad4f-2d8e302dfb9c', 'fillup', 'Questions 8–13', '<div class="quests-inner-desc">
<div class="txt">
<div class="quests-inner-desc">
<div class="txt">
<p>Complete the notes below.</p>
<p>Write <strong>ONE WORD ONLY </strong>from the passage for each answer.</p>
</div>
</div>
<div class="quests-des">
<div class="content-write">
<p class="ql-align-center" style="text-align: center;"><span style="font-size: 12pt;"><strong>The challenges for prosopagnosia researchers</strong></span></p>
<p><strong>Differences in prosopagnosics</strong></p>
<p>As we as being unable to recognize facial features, prosopagnosics may also have problems recognizing</p>
<p>– commonly seen {animals} and objects.</p>
<p>– the {emotion} on someone else’s face.</p>
<p>Some prosopagnosics can recognize that people are regarded as attractive by others.</p>
<p><strong>Causes of prosopagnosia</strong></p>
<p>Prosopagnosia may be caused by</p>
<p>– just one {gene} according to Martina Gruter</p>
<p>– a defect in the {left}<span class="fill-history-correct"> </span>eye according to Brad Duchaine</p>
<p><strong>Treatment for prosopagnosia</strong></p>
<p>Joseph Degutis patent proved he had been successfully trained to recognize faces inside the {laboratory} and in the outside world.</p>
<p>Duchaine’s training may allow prosopagnosics to recognise faces belonging to family and workmates.</p>
<p>Thomas Gruter doubts that train will work and mentions that {cheating} by some subjects can affect research results.</p>
</div>
</div>
</div>
</div>
', NULL, 'gap_filling', 'null', 'null', 'null', 'null', '[{"content": "<h3 data-path-to-node=\"25\">8. Differences in prosopagnosics: As well as being unable to recognize facial features, prosopagnosics may also have problems recognizing – commonly seen <strong>animals</strong> and objects.</h3>\n<ul data-path-to-node=\"26\">\n<li>\n<p data-path-to-node=\"26,0,0\"><strong>Đáp án:</strong> <strong>animals</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"26,1,0\"><strong>Dẫn chứng:</strong> (Đoạn 7) “…others have trouble with ordinary everyday objects and, so it turns out, <strong>animals</strong> which would normally be familiar as well.”</p>\n</li>\n</ul>\n<h3 data-path-to-node=\"28\">9. – the <strong>emotion</strong> on someone else’s face.</h3>\n<ul data-path-to-node=\"29\">\n<li>\n<p data-path-to-node=\"29,0,0\"><strong>Đáp án:</strong> <strong>emotion</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"29,1,0\"><strong>Dẫn chứng:</strong> (Đoạn 7) “When some have been tested they could identify the <strong>emotion</strong> which was conveyed on another’s face, even though the face itself seemed unfamiliar…”</p>\n</li>\n</ul>\n<h3 data-path-to-node=\"31\">10. Causes of prosopagnosia: Prosopagnosia may be caused by – just one <strong>gene</strong> according to Martina Gruter.</h3>\n<ul data-path-to-node=\"32\">\n<li>\n<p data-path-to-node=\"32,0,0\"><strong>Đáp án:</strong> <strong>gene</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"32,1,0\"><strong>Dẫn chứng:</strong> (Đoạn 8) “…the German team believe they have good evidence that a single <strong>gene</strong> could be responsible.”</p>\n</li>\n</ul>\n<h3 data-path-to-node=\"34\">11. – a defect in the <strong>left</strong> eye according to Brad Duchaine.</h3>\n<ul data-path-to-node=\"35\">\n<li>\n<p data-path-to-node=\"35,0,0\"><strong>Đáp án:</strong> <strong>left</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"35,1,0\"><strong>Dẫn chứng:</strong> (Đoạn 8) “…and when it’s the <strong>left</strong> one, being unable to see through this eye during the first two months of life is a major risk factor for prosopagnosia.”</p>\n</li>\n</ul>\n<h3 data-path-to-node=\"37\">12. Treatment for prosopagnosia: Joseph Degutis patent proved he had been successfully trained to recognize faces inside the <strong>laboratory</strong> and in the outside world.</h3>\n<ul data-path-to-node=\"38\">\n<li>\n<p data-path-to-node=\"38,0,0\"><strong>Đáp án:</strong> <strong>laboratory</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"38,1,0\"><strong>Dẫn chứng:</strong> (Đoạn 9) “…recently reported successfully training a severe developmental prosopagnosic to recognise faces during tests carried out in the <strong>laboratory</strong>.”</p>\n</li>\n</ul>\n<h3 data-path-to-node=\"40\">13. Thomas Gruter doubts that train will work and mentions that <strong>cheating</strong> by some subjects can affect research results.</h3>\n<ul data-path-to-node=\"41\">\n<li>\n<p data-path-to-node=\"41,0,0\"><strong>Đáp án:</strong> <strong>cheating</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"41,1,0\"><strong>Dẫn chứng:</strong> (Đoạn 9) “He also points out that <strong>cheating</strong> is a possibility during tests and provides an example.”</p>\n</li>\n</ul>\n"}]', 1);
INSERT INTO public.questions VALUES ('9d953b56-974c-46c0-8fa5-fdf7b5c0f5b6', 'ec06c489-adf7-4f17-9cb0-d9057cf3d728', 'checkbox', 'Questions 11–12', '', '<p>Choose <strong>TWO </strong>letters, A–E.</p>
<p>Which <strong>TWO </strong>items will participants on the dancing course receive when they check in?</p>', 'multiple_choice', 'null', '[{"correct": true, "option_text": "a class list"}, {"correct": false, "option_text": "a face towel"}, {"correct": false, "option_text": "a name tag"}, {"correct": true, "option_text": "a shoe bag"}, {"correct": false, "option_text": "a water bottle"}]', 'null', 'null', '[{"content": "<h3 data-path-to-node=\"3\"><strong data-path-to-node=\"3\" data-index-in-node=\"0\">SECTION 2: WEEKEND DANCING COURSE WELCOME</strong></h3>\n<p data-path-to-node=\"4\"><strong data-path-to-node=\"4\" data-index-in-node=\"0\">Organizer:</strong> Hello everyone, and welcome to this weekend dancing course. Nice that you’re here safely. Since you’ve all just arrived, I’d like to tell you firstly a bit about today’s program and secondly how to get around this community center.</p>\n<p data-path-to-node=\"5\">Firstly, straight after this talk, you’ll go off to the office where you should check in at the registration desk.</p>\n<p data-path-to-node=\"6\">Make sure you’re wearing the name tags that we posted you out in the mail last week.</p>\n<p data-path-to-node=\"7\">The staff there will give you each a <span style=\"background-color: #f3db7b;\"><strong>11/12 [D]</strong> <span style=\"text-decoration: underline;\"><strong data-path-to-node=\"7\" data-index-in-node=\"37\">cloth bag</strong> as a little present from us, to keep your <strong data-path-to-node=\"7\" data-index-in-node=\"89\">dancing shoes</strong> in for the weekend.</span></span></p>\n<p data-path-to-node=\"8\">Other things useful to take to class each day will be a bottle of water—hopefully you’ve all brought one with you—and a towel for your face if it’s hot and you feel you need one.</p>\n<p data-path-to-node=\"9\"><span style=\"text-decoration: underline; background-color: #f3db7b;\"><strong>11/12 [A] </strong>Also at registration, you can pick up a <strong data-path-to-node=\"9\" data-index-in-node=\"40\">list for the level class</strong> that you’re in, so you can start learning people’s names.</span></p>\n<p data-path-to-node=\"10\">After checking in, this first afternoon is free for everyone. You could use this time to start thinking about your costumes for the final show, but we won’t be making them until tomorrow.</p>\n<p data-path-to-node=\"11\"><span style=\"background-color: #ffffff;\">For those of you who are interested,<span style=\"text-decoration: underline; background-color: #f3db7b;\"><strong data-path-to-node=\"11\" data-index-in-node=\"77\"> (13/14) [D] </strong></span></span><span style=\"text-decoration: underline; background-color: #f3db7b;\">there’s a <strong data-path-to-node=\"11\" data-index-in-node=\"47\">lecture</strong> this afternoon in the <strong data-path-to-node=\"11\" data-index-in-node=\"77\">Main Hall </strong>on the <strong data-path-to-node=\"11\" data-index-in-node=\"94\">history of dance</strong>. </span><span style=\"background-color: #ffffff;\">Or you could practice for Sunday’s concert in the Music Room.</span></p>\n<p data-path-to-node=\"13\"><span style=\"text-decoration: underline; background-color: #f3db7b;\"><strong data-path-to-node=\"11\" data-index-in-node=\"77\">(1</strong></span><span style=\"background-color: #f3db7b;\"><strong>3/14) [C]</strong><strong>There is also an informal gathering planned for tonight, consisting of mainly easy dances, </strong></span>where you can get to know each other.</p>\n<p data-path-to-node=\"14\">The tests of different levels won’t be held until the final afternoon, so there’s no need to worry about those yet.</p>\n<hr data-path-to-node=\"15\">\n<h3 data-path-to-node=\"16\"><strong data-path-to-node=\"16\" data-index-in-node=\"0\">MAP DIRECTIONS </strong></h3>\n<p data-path-to-node=\"17\">Organizer: Now I said I would tell you how to find your way around the community centre. Well, we’re standing at the South End of the site.</p>\n<p data-path-to-node=\"18\">I’ll tell you where the <span style=\"text-decoration: underline;\"><span style=\"background-color: #f3db7b;\"><strong>[15]</strong> </span></span><strong><span style=\"text-decoration: underline;\"><span style=\"background-color: #f3db7b;\">bathrooms</span></span> </strong>are first. That’s the most important thing.<strong> </strong><span style=\"background-color: #ffffff;\">Walk straight ahead from here, pass this first big block on your left, and you’ll find the bathrooms on your left just after it.</span></p>\n<p data-path-to-node=\"19\">Now, equally important of course is where you’ll sleep. So the<strong> <span style=\"text-decoration: underline; background-color: #f3db7b;\">[16] bunk rooms</span></strong><span style=\"background-color: #ffffff;\"> are just here on our left, beside where we’re standing now.</span></p>\n<p data-path-to-node=\"20\">Now we also have a <span style=\"text-decoration: underline; background-color: #f3db7b;\"><strong>[19] </strong><strong>games room</strong>,</span><span style=\"background-color: #ffffff;\"> where you can entertain yourself during your free time. Well, you’ll get there if you go straight ahead from where we’re standing now, take the first turning right, and carry on to the second building. It’s on your right just before the bike racks.</span>Games and books are in the cupboard there, and there’s a ping pong table, air hockey things like that good for a rainy day.</p>\n<p data-path-to-node=\"21\">Okay, what else? Um, the<strong> <span style=\"background-color: #f3db7b;\">[18] hall </span></strong>is where we’ll be for class photos. You can find that in the middle of the site, just south of the music room.</p>\n<p data-path-to-node=\"22\"><span style=\"text-decoration: underline;\"><span style=\"background-color: #f3db7b;\"><strong>[17] The medical room</strong></span></span>, in case any of you get injured while you’re dancing, can be found in the center of the site also. Go straight on from here past two pathways, and it’s on your right beside the music room. The nurse there is very good with sports injuries, so don’t hesitate to visit her if you need to.</p>\n<p data-path-to-node=\"23\">Any questions? Oh yes,<span style=\"background-color: #f3db7b;\"><strong> <span style=\"text-decoration: underline;\">[20] </span></strong><span style=\"text-decoration: underline;\"><strong>the reception office</strong></span></span>, of course. You’ll need to go over there after this talk to register. That’s quite a long walk away from here. Go straight ahead and take the third turning on your right, then you will find that the office is the second building on your left. The staff there are very friendly and if you have any problems during the weekend, go to see them and they’ll help you out.</p>"}]', 0);
INSERT INTO public.questions VALUES ('3a17c05b-3055-4b87-a638-2392dc520470', '4fe96fa1-99fc-4e78-b3d6-2957af4f11f0', 'fillup', 'Questions 1–10', '<p data-start="116" data-end="194">Complete the form below.</p>
<p data-start="116" data-end="194">Write <strong data-start="149" data-end="177">ONE WORD AND/OR A NUMBER</strong> for each answer.</p>
<p data-start="201" data-end="258"><span style="font-size: 12pt;"><strong data-start="205" data-end="258">Morgan Recruitment Agency – Request for new staff</strong></span></p>
<p data-start="260" data-end="295"><strong data-start="260" data-end="271">Example</strong></p>
<p data-start="260" data-end="295"><em>Name: <strong data-start="280" data-end="295">Peter Smith</strong></em></p>
<p data-start="297" data-end="316"><strong data-start="297" data-end="314">Phone number: </strong>{0478883925}</p>
<p data-start="332" data-end="375"><strong data-start="332" data-end="349">Company name: </strong>{Vander} Transport</p>
<p data-start="377" data-end="459"><strong data-start="377" data-end="397">Type of company: </strong>trucking company – transports a lot of {frozen} food</p>
<p data-start="461" data-end="510"><strong data-start="461" data-end="489">Date employees required: </strong>from {28th August|28 August | August 28th | August 28}</p>
<p data-start="517" data-end="540"> </p>
<p data-start="517" data-end="540"><strong data-start="521" data-end="540">Details of Jobs</strong></p>
<p data-start="542" data-end="560"><strong data-start="542" data-end="560">Office Manager</strong></p>
<ul data-start="561" data-end="639">
<li data-start="561" data-end="611">
<p data-start="563" data-end="611">experience working with supermarkets is needed</p>
</li>
<li data-start="612" data-end="639">
<p data-start="614" data-end="639">must have a {degree}</p>
</li>
</ul>
<p data-start="641" data-end="653"><strong data-start="641" data-end="653">Mechanic</strong></p>
<ul data-start="654" data-end="780">
<li data-start="654" data-end="735">
<p data-start="656" data-end="735">duties involve repairing trucks and waiting a {report} for every vehicle</p>
</li>
<li data-start="736" data-end="780">
<p data-start="738" data-end="780">the job will not involve much travelling</p>
</li>
</ul>
<p data-start="782" data-end="798"><strong data-start="782" data-end="798">Truck Driver</strong></p>
<ul data-start="799" data-end="966">
<li data-start="799" data-end="828">
<p data-start="801" data-end="828">will cover long distances</p>
</li>
<li data-start="829" data-end="911">
<p data-start="831" data-end="911">will need to transport {animals}, so experience handling them is preferred</p>
</li>
<li data-start="912" data-end="966">
<p data-start="914" data-end="966">all drivers also have to {clean} their truck</p>
</li>
</ul>
<p data-start="968" data-end="992"><strong data-start="968" data-end="992">Warehouse Supervisor</strong></p>
<ul data-start="993" data-end="1079">
<li data-start="993" data-end="1042">
<p data-start="995" data-end="1042">managing the warehouse near the {airport}</p>
</li>
<li data-start="1043" data-end="1079">
<p data-start="1045" data-end="1079">they need their own {car}</p>
</li>
</ul>', NULL, 'gap_filling', 'null', 'null', 'null', 'null', '[{"content": "<p data-path-to-node=\"2\"><strong data-path-to-node=\"2\" data-index-in-node=\"0\">PART 1</strong></p>\n<p data-path-to-node=\"3\"><strong data-path-to-node=\"3\" data-index-in-node=\"0\">Agent:</strong> Hello Morgan Recruitment Agency. How may I help you?</p>\n<p data-path-to-node=\"4\"><strong data-path-to-node=\"4\" data-index-in-node=\"0\">Peter:</strong> Hello. I need to employ some new staff for my company and I believe your agency can help with that.</p>\n<p data-path-to-node=\"5\"><strong data-path-to-node=\"5\" data-index-in-node=\"0\">Agent:</strong> Yes of course. First I&#8217;ll get some details from you. Can I have your name please?</p>\n<p data-path-to-node=\"6\"><strong data-path-to-node=\"6\" data-index-in-node=\"0\">Peter:</strong> Sure my name is Peter Smith.</p>\n<p data-path-to-node=\"7\"><strong data-path-to-node=\"7\" data-index-in-node=\"0\">Agent:</strong> And can I also get a contact number?</p>\n<p data-path-to-node=\"8\"><strong data-path-to-node=\"8\" data-index-in-node=\"0\">Peter:</strong> Our number here is <span style=\"text-decoration: underline; background-color: #f3db7b;\"><strong data-path-to-node=\"8\" data-index-in-node=\"26\">(1) 0478883925</strong>.</span></p>\n<p data-path-to-node=\"9\"><strong data-path-to-node=\"9\" data-index-in-node=\"0\">Agent:</strong> Thank you. Can I also take down some details about your company? What&#8217;s your company name?</p>\n<p data-path-to-node=\"10\"><strong data-path-to-node=\"10\" data-index-in-node=\"0\">Peter:</strong> It&#8217;s <span style=\"text-decoration: underline; background-color: #f3db7b;\"><strong data-path-to-node=\"10\" data-index-in-node=\"12\">(2) Vander</strong></span> Transport.</p>\n<p data-path-to-node=\"11\"><strong data-path-to-node=\"11\" data-index-in-node=\"0\">Agent:</strong> Is that V-A-N&#8230; that&#8217;s N for November&#8230; D-E-R?</p>\n<p data-path-to-node=\"12\"><strong data-path-to-node=\"12\" data-index-in-node=\"0\">Peter:</strong> That&#8217;s right. We are a large trucking company.</p>\n<p data-path-to-node=\"13\"><strong data-path-to-node=\"13\" data-index-in-node=\"0\">Agent:</strong> The transport industry is really booming, especially for fresh fruit and vegetables, isn&#8217;t it?</p>\n<p data-path-to-node=\"14\"><strong data-path-to-node=\"14\" data-index-in-node=\"0\">Peter:</strong> Yes. We have a fleet of refrigerated trucks though, so we mostly carry <span style=\"text-decoration: underline; background-color: #f3db7b;\"><strong data-path-to-node=\"14\" data-index-in-node=\"78\">(3) frozen</strong></span> goods—fish, vegetables, pizza, all sorts.</p>\n<p data-path-to-node=\"15\"><strong data-path-to-node=\"15\" data-index-in-node=\"0\">Agent:</strong> I see. So you said that you need some new staff members. When would you need them to start?</p>\n<p data-path-to-node=\"16\"><strong data-path-to-node=\"16\" data-index-in-node=\"0\">Peter:</strong> We&#8217;d like them to start around the 27th of August.</p>\n<p data-path-to-node=\"17\"><strong data-path-to-node=\"17\" data-index-in-node=\"0\">Agent:</strong> Just looking at my calendar here&#8230; the 27th is a Sunday, so do you mean the <span style=\"text-decoration: underline; background-color: #f3db7b;\"><strong data-path-to-node=\"17\" data-index-in-node=\"84\">(4) 28th (August)</strong>?</span></p>\n<p data-path-to-node=\"18\"><strong data-path-to-node=\"18\" data-index-in-node=\"0\">Peter:</strong> Aha, yes. That&#8217;s right. We&#8217;re hoping to hold any interviews around July 29th. I&#8217;ll get more details of that later.</p>\n<hr data-path-to-node=\"19\">\n<p data-path-to-node=\"20\"><strong data-path-to-node=\"20\" data-index-in-node=\"0\">Agent:</strong> Okay now, could you tell me about the jobs you have available so we can hopefully find some suitable candidates?</p>\n<p data-path-to-node=\"21\"><strong data-path-to-node=\"21\" data-index-in-node=\"0\">Peter:</strong> Sure. The first position is an office manager.</p>\n<p data-path-to-node=\"22\"><strong data-path-to-node=\"22\" data-index-in-node=\"0\">Agent:</strong> So does the job involve typical management duties?</p>\n<p data-path-to-node=\"23\"><strong data-path-to-node=\"23\" data-index-in-node=\"0\">Peter:</strong> Yes, but they also have to liaise with our main client, which is a large supermarket chain. So a background in a company like that is essential.</p>\n<p data-path-to-node=\"24\"><strong data-path-to-node=\"24\" data-index-in-node=\"0\">Agent:</strong> Okay I&#8217;ll note that down. It sounds like an important role. What are the minimum qualifications? Do they need a university education, like a <span style=\"text-decoration: underline; background-color: #f3db7b;\"><strong data-path-to-node=\"24\" data-index-in-node=\"148\">(5) degree</strong></span>?</p>\n<p data-path-to-node=\"25\"><strong data-path-to-node=\"25\" data-index-in-node=\"0\">Peter:</strong> Yes, candidates would definitely have one.</p>\n<p data-path-to-node=\"26\"><strong data-path-to-node=\"26\" data-index-in-node=\"0\">Agent:</strong> Okay. Can you tell me about the next position?</p>\n<p data-path-to-node=\"27\"><strong data-path-to-node=\"27\" data-index-in-node=\"0\">Peter:</strong> We&#8217;re looking for a full-time mechanic.</p>\n<p data-path-to-node=\"28\"><strong data-path-to-node=\"28\" data-index-in-node=\"0\">Agent:</strong> So I assume the job will involve doing general repairs on trucks?</p>\n<p data-path-to-node=\"29\"><strong data-path-to-node=\"29\" data-index-in-node=\"0\">Peter:</strong> Yes, that&#8217;s right. And one of the other key responsibilities is to produce a written <span style=\"text-decoration: underline; background-color: #f3db7b;\"><strong data-path-to-node=\"29\" data-index-in-node=\"92\">(6) report</strong></span> for each vehicle.</p>\n<p data-path-to-node=\"30\"><strong data-path-to-node=\"30\" data-index-in-node=\"0\">Agent:</strong> I think we have several people on our books that would be suitable. And will the mechanic be doing much travelling?</p>\n<p data-path-to-node=\"31\"><strong data-path-to-node=\"31\" data-index-in-node=\"0\">Peter:</strong> Some yes, but not a great deal. Unlike our next vacancy.</p>\n<p data-path-to-node=\"32\"><strong data-path-to-node=\"32\" data-index-in-node=\"0\">Agent:</strong> That’s for a full-time truck driver, right? What kind of shifts are they expected to work?</p>\n<p data-path-to-node=\"33\"><strong data-path-to-node=\"33\" data-index-in-node=\"0\">Peter:</strong> They usually travel around 1,000 km over a five-day period.</p>\n<p data-path-to-node=\"34\"><strong data-path-to-node=\"34\" data-index-in-node=\"0\">Agent:</strong> I see.</p>\n<p data-path-to-node=\"35\"><strong data-path-to-node=\"35\" data-index-in-node=\"0\">Peter:</strong> This job is different to our usual ones though. It involves moving <span style=\"text-decoration: underline; background-color: #f3db7b;\"><strong data-path-to-node=\"35\" data-index-in-node=\"74\">(7) animals</strong>.</span></p>\n<p data-path-to-node=\"36\"><strong data-path-to-node=\"36\" data-index-in-node=\"0\">Agent:</strong> That sounds interesting.</p>\n<p data-path-to-node=\"37\"><strong data-path-to-node=\"37\" data-index-in-node=\"0\">Peter:</strong> Yes. Our company has just got a new contract, so we&#8217;ve bought new trucks and want a driver with that kind of experience.</p>\n<p data-path-to-node=\"38\"><strong data-path-to-node=\"38\" data-index-in-node=\"0\">Agent:</strong> Great. Is there anything else I should make a note of?</p>\n<p data-path-to-node=\"39\"><strong data-path-to-node=\"39\" data-index-in-node=\"0\">Peter:</strong> Well, we own all of the trucks, but apart from their driving duties, it is up to all our drivers to <span style=\"text-decoration: underline; background-color: #f3db7b;\"><strong data-path-to-node=\"39\" data-index-in-node=\"107\">(8) clean</strong></span> their vehicle between trips. We do give them extra time for that.</p>\n<p data-path-to-node=\"40\"><strong data-path-to-node=\"40\" data-index-in-node=\"0\">Agent:</strong> OK. And are there any other positions available?</p>\n<p data-path-to-node=\"41\"><strong data-path-to-node=\"41\" data-index-in-node=\"0\">Peter:</strong> Yes, we&#8217;re looking for a warehouse supervisor.</p>\n<p data-path-to-node=\"42\"><strong data-path-to-node=\"42\" data-index-in-node=\"0\">Agent:</strong> And what will this involve?</p>\n<p data-path-to-node=\"43\"><strong data-path-to-node=\"43\" data-index-in-node=\"0\">Peter:</strong> They&#8217;ll be in charge of our new warehouse. It&#8217;s located close to the <span style=\"text-decoration: underline; background-color: #f3db7b;\"><strong data-path-to-node=\"43\" data-index-in-node=\"76\">(9) airport</strong></span>. We&#8217;ve recently moved out of the city centre.</p>\n<p data-path-to-node=\"44\"><strong data-path-to-node=\"44\" data-index-in-node=\"0\">Agent:</strong> Oh that must be more convenient. And what are some of the requirements for this role?</p>\n<p data-path-to-node=\"45\"><strong data-path-to-node=\"45\" data-index-in-node=\"0\">Peter:</strong> The successful candidate would be able to work effectively in a busy environment. Sometimes I&#8217;ll be on call 24 hours for our night-time deliveries.</p>\n<p data-path-to-node=\"46\"><strong data-path-to-node=\"46\" data-index-in-node=\"0\">Agent:</strong> So given the hours they&#8217;ll be working, I assume it will be necessary for the candidate to have a <span style=\"text-decoration: underline; background-color: #f3db7b;\"><strong data-path-to-node=\"46\" data-index-in-node=\"104\">(10) car</strong></span>?</p>\n<p data-path-to-node=\"47\"><strong data-path-to-node=\"47\" data-index-in-node=\"0\">Peter:</strong> Yes that&#8217;s right. Buses and trains just don&#8217;t operate at those times unfortunately.</p>\n<p data-path-to-node=\"48\"><strong data-path-to-node=\"48\" data-index-in-node=\"0\">Agent:</strong> Okay Mister Smith, I&#8217;ll have a look at the job seekers we have on our books and see if we have any suitable candidates&#8230;</p>\n"}]', 0);
INSERT INTO public.questions VALUES ('c3c90858-1087-4c7f-b7c1-076c0c00c12b', '39cd4eff-f4dc-4e41-b809-1d697a3edd86', 'matrix', 'Question 11-14', NULL, '<div class="s-block-item s-repeatable-item s-block-sortable-item s-blog-post-section blog-section">
<div class="container">
<div class="sixteen columns">
<div class="s-blog-section-inner">
<div class="s-component s-text ">
<div class="">
<div class="s-component-content s-font-body">
<p>Which type of accommodation includes the following features?</p>
<p>Choose the correct answers</p>
</div>
</div>
</div>
</div>
</div>
</div>
</div>
', 'classification', 'null', 'null', 'null', '{"layoutType": "standard", "legendTitle": null, "matrixItems": [{"itemText": "a garden", "correctCategoryLetter": "A"}, {"itemText": "a garage", "correctCategoryLetter": "A"}, {"itemText": "an alarm system", "correctCategoryLetter": "B"}, {"itemText": "new furniture", "correctCategoryLetter": "B"}], "matrixCategories": [{"categoryText": "the flat", "categoryLetter": "A"}, {"categoryText": "the house", "categoryLetter": "B"}, {"categoryText": "the hostel", "categoryLetter": "C"}]}', '[{"content": "<p data-path-to-node=\"2\"><strong data-path-to-node=\"2\" data-index-in-node=\"0\">SECTION 2</strong></p>\n<p data-path-to-node=\"3\"><strong data-path-to-node=\"3\" data-index-in-node=\"0\">Agent:</strong> Hello, can I help?</p>\n<p data-path-to-node=\"4\"><strong data-path-to-node=\"4\" data-index-in-node=\"0\">Student:</strong> Yes, I&#8217;m looking for accommodation. I&#8217;m a student in my second year at the college and I wanted to rent something from September for myself and a friend.</p>\n<p data-path-to-node=\"5\"><strong data-path-to-node=\"5\" data-index-in-node=\"0\">Agent:</strong> Well, we&#8217;ve got several choices at the moment near the college. We&#8217;ve got a flat, a house or there&#8217;s a student hostel. All at about the same rent, but of course they all have different features and different things included in the rent.</p>\n<p data-path-to-node=\"6\"><strong data-path-to-node=\"6\" data-index-in-node=\"0\">Agent:</strong> The properties don&#8217;t all have gardens, I&#8217;m afraid. The house is quite small, not much space around it. It has got a bit of space at the back, but I wouldn&#8217;t call it a garden.</p>\n<p data-path-to-node=\"7\"><strong data-path-to-node=\"7\" data-index-in-node=\"0\">Agent:</strong> The hostel is part of a city development, so there&#8217;s no space for a garden. But <span style=\"text-decoration: underline; background-color: #f3db7b;\"><strong data-path-to-node=\"7\" data-index-in-node=\"87\">(11) the flat has a communal garden [A]</strong></span> that is shared by all the tenants. I would say that that&#8217;s very good value for the price.</p>\n<p data-path-to-node=\"8\"><strong data-path-to-node=\"8\" data-index-in-node=\"0\">Student:</strong> Have you got a car?</p>\n<p data-path-to-node=\"9\"><strong data-path-to-node=\"9\" data-index-in-node=\"0\">Student:</strong> Yes.</p>\n<p data-path-to-node=\"10\"><strong data-path-to-node=\"10\" data-index-in-node=\"0\">Agent:</strong> Um, there are garages round the corner from the house, but you have to rent those separately and they might not be available.</p>\n<p data-path-to-node=\"11\"><strong data-path-to-node=\"11\" data-index-in-node=\"0\">Agent:</strong> But <span style=\"text-decoration: underline; background-color: #f3db7b;\"><strong data-path-to-node=\"11\" data-index-in-node=\"11\">(12) each flat is allotted a garage [A]</strong> </span>in the grounds as part of the deal. The hostel doesn&#8217;t have the space, I&#8217;m afraid.</p>\n<p data-path-to-node=\"12\"><strong data-path-to-node=\"12\" data-index-in-node=\"0\">Student:</strong> Uh huh.</p>\n<p data-path-to-node=\"13\"><strong data-path-to-node=\"13\" data-index-in-node=\"0\">Agent:</strong> I guess you might also want to know about security as well.<span style=\"text-decoration: underline;\"> <span style=\"background-color: #f3db7b;\"><strong data-path-to-node=\"13\" data-index-in-node=\"67\">(13) The house is the only one which is alarmed [B]</strong>.</span></span></p>\n<p data-path-to-node=\"14\"><strong data-path-to-node=\"14\" data-index-in-node=\"0\">Agent:</strong> The flats and the hostel are accessed through a main door which has an intercom for visitors, so they&#8217;re quite safe.</p>\n<p data-path-to-node=\"15\"><strong data-path-to-node=\"15\" data-index-in-node=\"0\">Agent:</strong> Now they are all furnished. The stuff in the flats is quite modern looking, which most people like, and it&#8217;s in quite good condition considering the use it&#8217;s had.</p>\n<p data-path-to-node=\"16\"><strong data-path-to-node=\"16\" data-index-in-node=\"0\">Agent:</strong> <span style=\"text-decoration: underline; background-color: #f3db7b;\"><strong data-path-to-node=\"16\" data-index-in-node=\"7\">(14) All the furniture and fittings in the house have just been replaced [B]</strong> </span>after the last tenants left, so they&#8217;ll be in excellent condition. And the furniture in the hostel is OK; it&#8217;s about what you&#8217;d expect really.</p>\n<hr>\n<p data-path-to-node=\"19\"><strong data-path-to-node=\"19\" data-index-in-node=\"0\">Student:</strong> Well, I think I&#8217;d better go and look at them all. Uh, where are they?</p>\n<p data-path-to-node=\"20\"><strong data-path-to-node=\"20\" data-index-in-node=\"0\">Agent:</strong> Here, let me show you on the map. Uh, right um, we&#8217;re here in the accommodation agency on the High Street, facing north.</p>\n<p data-path-to-node=\"21\"><strong data-path-to-node=\"21\" data-index-in-node=\"0\">Agent:</strong> Directly opposite us is <span style=\"text-decoration: underline; background-color: #f3db7b;\"><strong data-path-to-node=\"21\" data-index-in-node=\"31\">(15) the bank [E]</strong>.</span></p>\n<p data-path-to-node=\"22\"><strong data-path-to-node=\"22\" data-index-in-node=\"0\">Agent:</strong> If you stay on this side of the road and walk towards West Street, <span style=\"text-decoration: underline; background-color: #f3db7b;\"><strong data-path-to-node=\"22\" data-index-in-node=\"74\">(16) the house [I]</strong> </span>is not that far. It&#8217;s next but one to the swimming pool, just before West Street. It&#8217;s very convenient because it&#8217;s near the shops.</p>\n<p data-path-to-node=\"23\"><strong data-path-to-node=\"23\" data-index-in-node=\"0\">Agent:</strong> <span style=\"text-decoration: underline; background-color: #f3db7b;\"><strong data-path-to-node=\"23\" data-index-in-node=\"7\">(17) The hostel [J]</strong> </span>is on the corner of West Street and Saint Ann&#8217;s Road, near the roundabout. It&#8217;s not a very wonderful building, but it&#8217;s nice and close to the college.</p>\n<p data-path-to-node=\"24\"><strong data-path-to-node=\"24\" data-index-in-node=\"0\">Agent:</strong> <span style=\"text-decoration: underline; background-color: #f3db7b;\"><strong data-path-to-node=\"24\" data-index-in-node=\"7\">(18) The flat [A]</strong> </span>is a bit of a walk, but it&#8217;s in very nice surroundings. To get to the flat, you go down West Street towards the centre of the city, and the building is on the corner, just before the first turning on the left.</p>\n<p data-path-to-node=\"25\"><strong data-path-to-node=\"25\" data-index-in-node=\"0\">Agent:</strong> Although we&#8217;re a bit outside the city centre, the facilities aren&#8217;t bad. There&#8217;s<span style=\"text-decoration: underline;\"> <span style=\"background-color: #f3db7b;\"><strong data-path-to-node=\"25\" data-index-in-node=\"88\">(19) a post office [C]</strong></span></span> just round the corner from here. You go down the High Street and turn right into West Street, and it&#8217;s on your right.</p>\n<p data-path-to-node=\"26\"><strong data-path-to-node=\"26\" data-index-in-node=\"0\">Agent:</strong> Or if you want to go to the city centre, you could get <span style=\"text-decoration: underline; background-color: #f3db7b;\"><strong data-path-to-node=\"26\" data-index-in-node=\"62\">(20) the bus from here [G]</strong></span>. Just a few metres down the road from the agency going east. You don&#8217;t even need to cross the road.</p>\n"}]', 0);
INSERT INTO public.questions VALUES ('a8992dd6-b550-494d-b0a0-1a57e587c66a', '39cd4eff-f4dc-4e41-b809-1d697a3edd86', 'matrix', 'Questions 15-20', NULL, '<div class="s-block-item s-repeatable-item s-block-sortable-item s-blog-post-section blog-section">
