</div>', 'classification', 'null', 'null', 'null', '{"layoutType": "simple", "legendTitle": null, "matrixItems": [{"itemText": "the bank", "correctCategoryLetter": "E"}, {"itemText": "the house", "correctCategoryLetter": "I"}, {"itemText": "the hostel", "correctCategoryLetter": "J"}, {"itemText": "the flat", "correctCategoryLetter": "A"}, {"itemText": "the post office", "correctCategoryLetter": "C"}, {"itemText": "the bus stop", "correctCategoryLetter": "G"}], "matrixCategories": [{"categoryText": "A", "categoryLetter": "A"}, {"categoryText": "B", "categoryLetter": "B"}, {"categoryText": "C", "categoryLetter": "C"}, {"categoryText": "D", "categoryLetter": "D"}, {"categoryText": "E", "categoryLetter": "E"}, {"categoryText": "F", "categoryLetter": "F"}, {"categoryText": "G", "categoryLetter": "G"}, {"categoryText": "H", "categoryLetter": "H"}, {"categoryText": "I", "categoryLetter": "I"}, {"categoryText": "J", "categoryLetter": "J"}]}', '[{"content": "<p>1</p>\n"}]', 1);
INSERT INTO public.questions VALUES ('fa5d7e06-3b42-407d-b841-d013a7a38b59', '045511de-bbc5-40e4-9b2f-38555b652c56', 'radio', 'Questions 21-25', NULL, '<div class="s-block-item s-repeatable-item s-block-sortable-item s-blog-post-section blog-section">
