', 'matching_features', 'null', 'null', '{"layoutType": "summary", "summaryText": "<p data-start=\"269\" data-end=\"293\"><strong>Seminar presentation</strong></p>\n<table style=\"border-collapse: collapse; width: 100%; border: 1px solid rgb(0, 0, 0); margin-left: 0px; margin-right: auto;\" border=\"1\"><colgroup><col style=\"width: 99.8584%;\"></colgroup>\n<tbody>\n<tr>\n<td style=\"border-color: #000000;\">\n<p><strong> Context: need for anti-malarial products</strong></p>\n<p> Figures relating to:</p>\n<ul>\n<li>\n<p>global incidence of the disease</p>\n</li>\n<li>\n<p>impact on {G National economics}</p>\n</li>\n</ul>\n</td>\n</tr>\n</tbody>\n</table>\n<p style=\"text-align: center;\" data-start=\"616\" data-end=\"654\">🔽</p>\n<table style=\"border-collapse: collapse; width: 100%; border: 1px solid rgb(0, 0, 0); margin-left: 0px; margin-right: auto;\" border=\"1\"><colgroup><col style=\"width: 99.8584%;\"></colgroup>\n<tbody>\n<tr>\n<td style=\"border-color: #000000;\">\n<p><strong> Mosquito nets</strong></p>\n<ul>\n<li>\n<p>History</p>\n</li>\n<li>\n<p>{D unique features of the product}</p>\n</li>\n</ul>\n</td>\n</tr>\n</tbody>\n</table>\n<p style=\"text-align: center;\" data-start=\"616\" data-end=\"654\">🔽</p>\n<table style=\"border-collapse: collapse; width: 100%; border: 1px solid rgb(0, 0, 0); margin-left: 0px; margin-right: auto;\" border=\"1\"><colgroup><col style=\"width: 100%;\"></colgroup>\n<tbody>\n<tr>\n<td style=\"border-color: #000000;\">\n<p><strong> Production</strong></p>\n<ul>\n<li>\n<p>information about {B sources of funding}</p>\n</li>\n<li>\n<p>profile of manufacturer with description of {A workforce} </p>\n</li>\n<li>\n<p>{F production figures national economies} (according to website)</p>\n</li>\n</ul>\n</td>\n</tr>\n</tbody>\n</table>", "answerOptions": [{"optionText": "A workforce"}, {"optionText": "B sources of funding"}, {"optionText": "C investment opportunities"}, {"optionText": "D unique features of the product"}, {"optionText": "E future developments"}, {"optionText": "F production figures national economies"}, {"optionText": "G National economics"}], "matchingItems": null}', 'null', '[{"content": "<p>1</p>\n"}]', 1);
INSERT INTO public.questions VALUES ('9eee5f00-9aa8-4d5c-bd28-6c0b89c48d8a', '4c8e37e2-00ef-4d5b-9722-6003f86e673c', 'fillup', 'Questions 31-40', '<div class="s-block-item s-repeatable-item s-block-sortable-item s-blog-post-section blog-section">
<div class="container">
<div class="sixteen columns">
<div class="s-blog-section-inner">
<div class="s-component s-text ">
<div class="">
<div class="s-component-content s-font-body">
<p>Complete the note below</p>
<p>Write <strong>ONE WORD ONLY</strong> for each answer.</p>
</div>
</div>
</div>
</div>
</div>
</div>
</div>
<div class="s-block-item s-repeatable-item s-block-sortable-item s-blog-post-section blog-section">
<div class="container">
<div class="sixteen columns">
<div class="s-blog-section-inner">
<div class="s-component s-text ">
<div class="">
<div class="s-component-content s-font-body">
<p><span style="font-size: 12pt;"><strong>Autonomous Underwater Vehicle (A.U.V.)</strong></span></p>
</div>
</div>
</div>
</div>
</div>
</div>
</div>
<div class="s-block-item s-repeatable-item s-block-sortable-item s-blog-post-section blog-section">
<div class="container">
<div class="sixteen columns">
<div class="s-blog-section-inner">
<div class="s-component s-text ">
<div class="">
<div class="s-component-content s-font-body">
<p><strong>Description</strong></p>
<ul>
<li>
<p>looks like a small {aeroplane}</p>
</li>
<li>
<p>acts like a {robot}</p>
</li>
</ul>
<p><strong>Functions?</strong></p>
<ul>
<li>
<p>Can be used to measure:</p>
<ul>
<li>
<p>water pressure</p>
</li>
<li>
<p>level of {salt} in water</p>
</li>
<li>
<p>water temperature</p>
</li>
<li>
<p>water {quality}</p>
</li>
</ul>
</li>
<li>
<p>Measurements are used to help us understand:</p>
<ul>
<li>
<p>ocean behaves</p>
</li>
<li>
<p>the impact the ocean has on the {climate}</p>
</li>
</ul>
</li>
</ul>
<p><strong>The benefits?</strong></p>
<ul>
<li>
<p>easy to launch</p>
</li>
<li>
<p>isn’t connected to a boat by {cables}</p>
</li>
</ul>
<p><strong>What are the disadvantages?</strong></p>
<ul>
<li>
<p>not fast-moving</p>
</li>
<li>
<p>can’t be used to assess {chemical} levels in water</p>
</li>
</ul>
<p><strong>How does the A.U.V. work?</strong></p>
<ul>
<li>
<p>{oil} is pumped between two bladders.</p>
</li>
<li>
<p>It measures and records data as it moves to the 39 {surface}</p>
</li>
<li>
<p>It sends the data from an antenna in the 40 {right} wing-tip.</p>
</li>
</ul>
</div>
</div>
</div>
</div>
</div>
</div>
</div>', NULL, 'gap_filling', 'null', 'null', 'null', 'null', '[{"content": "<p data-path-to-node=\"2\"><strong data-path-to-node=\"2\" data-index-in-node=\"0\">SECTION 4: AUTONOMOUS UNDERWATER VEHICLE (A.U.V.)</strong></p>\n<p data-path-to-node=\"3\"><strong data-path-to-node=\"3\" data-index-in-node=\"0\">Lecturer:</strong> Welcome class to your final lecture today. We are looking at the Autonomous Underwater Vehicle, or A.U.V.</p>\n<p data-path-to-node=\"4\">It actually resembles a miniature <span style=\"text-decoration: underline; background-color: #f3db7b;\"><strong data-path-to-node=\"4\" data-index-in-node=\"34\">(31) aeroplane</strong></span> that moves deep in the ocean. It’s not large enough to have a human crew aboard, and so its behavior is really that of a <span style=\"text-decoration: underline; background-color: #f3db7b;\"><strong data-path-to-node=\"4\" data-index-in-node=\"170\">(32) robot</strong>.</span></p>\n<p data-path-to-node=\"5\">The A.U.V. is programmed to calculate and record a range of data, depending on the mission it is carrying out at any one time. On previous missions, it has been programmed to record water pressure as well as how much <span style=\"text-decoration: underline; background-color: #f3db7b;\"><strong data-path-to-node=\"5\" data-index-in-node=\"217\">(33) salt</strong> </span>there is in the water.</p>\n<p data-path-to-node=\"6\">On a more recent mission around Bermuda, an A.U.V. was equipped with a special instrument that showed the temperature of the ocean at different depths. It can also assess the <span style=\"text-decoration: underline; background-color: #f3db7b;\"><strong data-path-to-node=\"6\" data-index-in-node=\"175\">(34) quality</strong></span> of the water in general.</p>\n<p data-path-to-node=\"7\">So as you see, it is quite a versatile and useful little piece of equipment. We use its measurements to determine and increase our understanding of ocean behaviors, as well as its role in and influence on our <span style=\"text-decoration: underline; background-color: #f3db7b;\"><strong data-path-to-node=\"7\" data-index-in-node=\"209\">(35) climate</strong>.</span></p>\n<hr data-path-to-node=\"8\">\n<p data-path-to-node=\"9\"><strong data-path-to-node=\"9\" data-index-in-node=\"0\">Lecturer:</strong> This instrument also has many other benefits. It can be launched and used relatively quickly. Also, there’s no need for <span style=\"text-decoration: underline; background-color: #f3db7b;\"><strong data-path-to-node=\"9\" data-index-in-node=\"130\">(36) cables</strong></span> to physically link it to a boat.</p>\n<p data-path-to-node=\"10\">There are disadvantages though. A.U.V.s move at only modest speeds, up to 25 cm per second. In addition, the A.U.V. structure cannot collect water samples, so other equipment must be used to conduct a <span style=\"text-decoration: underline; background-color: #f3db7b;\"><strong data-path-to-node=\"10\" data-index-in-node=\"201\">(37) chemical</strong></span> analysis of the water.</p>\n<hr data-path-to-node=\"11\">\n<p data-path-to-node=\"12\"><strong data-path-to-node=\"12\" data-index-in-node=\"0\">Lecturer:</strong> Now I’m sure you’re all wondering how the A.U.V. actually works. First, let’s see how an A.U.V. actually moves.</p>\n<p data-path-to-node=\"13\">It moves by pumping <span style=\"text-decoration: underline; background-color: #f3db7b;\"><strong data-path-to-node=\"13\" data-index-in-node=\"20\">(38) oil</strong></span> between two bladders. This helps the A.U.V. to sink or float.</p>\n<p data-path-to-node=\"14\">The A.U.V. records the data and measurements that it has been programmed to take while it rises to the <span style=\"text-decoration: underline; background-color: #f3db7b;\"><strong data-path-to-node=\"14\" data-index-in-node=\"103\">(39) surface</strong>.</span></p>\n<p data-path-to-node=\"15\">At the beginning and end of each dive, it obtains records and transmits its position by exposing an antenna embedded within the tip of the <span style=\"text-decoration: underline; background-color: #f3db7b;\"><strong data-path-to-node=\"15\" data-index-in-node=\"139\">(40) right</strong> </span>wing.</p>\n<p data-path-to-node=\"16\">Okay, so that’s the A.U.V.</p>\n"}]', 0);
INSERT INTO public.questions VALUES ('6735e592-6ec0-48a1-b654-25d1683fd0db', '78920030-364b-495e-8dd4-411aab4db460', 'radio', 'Questions 11–16', '', '<p>Choose the correct letter, <strong data-path-to-node="5" data-index-in-node="27">A</strong>, <strong data-path-to-node="5" data-index-in-node="30">B</strong> or <strong data-path-to-node="5" data-index-in-node="35">C</strong>.</p>', 'multiple_choice', '[{"correct": 0, "options": [{"option_text": "A   He was eager to develop a hobby."}, {"option_text": "B   He wanted to work shorter hours."}, {"option_text": "C   He found his job in website design unsatisfying."}], "question": "What made David leave London and move to Northsea?"}, {"correct": 1, "options": [{"option_text": "A   a local organisation."}, {"option_text": "B   a local resident."}, {"option_text": "C   the local council."}], "question": "The Lifeboat Institution in Northsea was built with money provided by"}, {"correct": 0, "options": [{"option_text": "A   might be colour blind."}, {"option_text": "B   was rather short-sighted."}, {"option_text": "C   had undergone eye surgery."}], "question": "In his health assessment, the doctor was concerned about the fact that David"}, {"correct": 1, "options": [{"option_text": "A   five minutes."}, {"option_text": "B   six to eight minutes."}, {"option_text": "C   eight and a half minutes."}], "question": "After arriving at the lifeboat station, they aim to launch the boat within"}, {"correct": 2, "options": [{"option_text": "A   who will be the members of his crew."}, {"option_text": "B   what equipment it will be necessary to take."}, {"option_text": "C   if the lifeboat should be launched."}], "question": "As a ''helmsman'', David has the responsibility of deciding"}, {"correct": 0, "options": [{"option_text": "A   gives talks on safety at sea."}, {"option_text": "B   helps with fundraising."}, {"option_text": "C   recruits new volunteers."}], "question": "As well as going out on the lifeboat, David"}]', 'null', 'null', 'null', '[{"content": "<p>1</p>"}]', 0);
INSERT INTO public.questions VALUES ('ff6338f2-1533-4bc0-be25-bd81e3527595', '78920030-364b-495e-8dd4-411aab4db460', 'checkbox', 'Questions 17 and 18', '', '<p>Choose <strong data-path-to-node="22" data-index-in-node="7">TWO</strong> letters, <strong data-path-to-node="22" data-index-in-node="20">A–E</strong>.</p>', 'multiple_choice', 'null', '[{"correct": false, "option_text": "A   The residential course developed his leadership skills."}, {"correct": false, "option_text": "B   The training in use of ropes and knots was quite brief."}, {"correct": true, "option_text": "C   The training exercises have built up his mental strength."}, {"correct": false, "option_text": "D   The casualty care activities were particularly challenging for him."}, {"correct": true, "option_text": "E   The wave tank activities provided practice in survival techniques."}]', 'null', 'null', '[{"content": "<p>1</p>"}]', 1);
INSERT INTO public.questions VALUES ('06acc488-e37f-44ec-bdc1-ac507eda532a', 'f99f53ba-caa7-413d-bffa-c8c408954ad9', 'radio', 'Questions 11–16', NULL, '<p>Choose the correct answer.</p>
', 'multiple_choice_single', '[{"correct": 0, "options": [{"content": "seen as an opportunity to learn."}, {"content": "predicted and minimised."}, {"content": "avoided at all costs."}], "question": "Arthur feels that when starting a business, mistakes should be"}, {"correct": 0, "options": [{"content": "sometimes reduce people''s chances of success."}, {"content": "be increased by reading self-help books."}, {"content": "ensure good results on business courses."}], "question": "Recent American studies found that confidence will"}, {"correct": 2, "options": [{"content": "listen to their colleagues’ advice."}, {"content": "get professional help when things go wrong."}, {"content": "remain concentrated on their aims."}], "question": "The American studies recommended that new entrepreneurs"}, {"correct": 1, "options": [{"content": "He relied on what he already knew."}, {"content": "He hired an expert to take care of it."}, {"content": "He realised its importance too late."}], "question": "What does Arthur say about his own experience of marketing?"}, {"correct": 2, "options": [{"content": "They are ambitious for their company."}, {"content": "They can deal with difficult people."}, {"content": "They earn the respect of their workforce."}], "question": "What does Arthur think Is an important quality shared by good leaders?"}, {"correct": 0, "options": [{"content": "He advises being cautions."}, {"content": "He favours a long-term view."}, {"content": "He believes it is financially advantageous."}], "question": "What does Arthur say about taking risks?"}]', 'null', 'null', 'null', '[{"content": "<p class=\"MsoNormal\"><strong>SECTION 2</strong></p>\n<p class=\"MsoNormal\"><strong>Arthur:</strong> Good evening, my name is Arthur Jones. I’m very glad to have this opportunity to speak to you over the radio. The host asked me to give a talk about my experience of starting my own business. I can’t say my business is successful, but there are some things that I want to share with you which I think will be helpful if you want to start your own company.</p>\n<p class=\"MsoNormal\">I’ve talked to many young people and they told me that they are afraid of making mistakes when they start their business. What I want to say is that mistakes are very common, especially when you do something new.<span style=\"text-decoration: underline;\"> <span style=\"background-color: #ffe786;\"><strong>(11) Mistakes can actually show you where you need to improve, so you can take actions about them and use the chance to learn new methods (A: seen as an opportunity to learn)</strong>. </span></span>This is a very important attitude you should have. Besides, most mistakes are not that fatal; don’t be too anxious when they occur.</p>\n<p class=\"MsoNormal\">Next, I want to go on to talk about self-confidence, which is quite important in achieving business success. Being self-confident means that you can have faith in yourself and what you do. Self-confidence can be gained through hard work, even playing sports.<span style=\"text-decoration: underline; background-color: #ffe786;\"> However, <strong>(12) sometimes self-confidence may make you ignore problems and even cause failure (A: sometimes reduce people’s chances of success)</strong>.</span> Business leaders should remain calm and not take impulsive actions.</p>\n<p class=\"MsoNormal\">I know that when people start their business, they have confusions. They don’t know how they can be more professional. They read business journals or watch related videos, but these don’t seem to help sometimes. <span style=\"text-decoration: underline; background-color: #ffe786;\">My suggestion is that <strong>(13) instead of aimlessly trying many new things, they should always be committed to their goal (C: remain concentrated on their aims)</strong>. </span>As long as they stick to it, they will not be easily distracted or confused by other things, and they are sure to get better.</p>\n<p class=\"MsoNormal\">We will all meet difficulties, especially at the beginning. We can’t always rely on ourselves to solve all the problems. <span style=\"text-decoration: underline; background-color: #ffe786;\"><strong>(14) I had a problem with marketing earlier this year; luckily I found an expert to help me deal with it (B: hired an expert to take care of it)</strong>. </span>So there’s always a way, but we should know how and when to seek help from these people.</p>\n<p class=\"MsoNormal\">Business leaders have different kinds of styles. Some are very good at public speaking, others are very down-to-earth and have strong executive skills.<span style=\"text-decoration: underline; background-color: #ffe786;\"> But in general, <strong>(15) they should be able to win the respect from their employees (C: earn the respect of their workforce)</strong>, so that they can carry out their orders more easily.</span></p>\n<p class=\"MsoNormal\">There are times when a company might face risks. During such times, leaders will need to take prompt actions and they can’t always plan for the distant future. <span style=\"text-decoration: underline; background-color: #ffe786;\"><strong>(16) Leaders should analyze and deal with the risks with caution (A: advises being cautious)</strong>.</span> If they bear this in mind, there is always a way out.</p>\n<div class=\"MsoNormal\" style=\"text-align: center;\" align=\"center\">\n<hr align=\"center\" size=\"2\" width=\"100%\" />\n</div>\n<p class=\"MsoNormal\"><strong>Arthur:</strong> At the beginning of my business, I experimented with quite a few strategies, hoping to find out the best solution for my business. Here is what I found. At first, my company wanted to work out prices for the products and make them realistic; however, prices are always changing, so they can’t be fixed.</p>\n<p class=\"MsoNormal\"><span style=\"text-decoration: underline; background-color: #ffe786;\">Another thing I always keep in mind is that leaders must <strong>(17/18) stay committed to their jobs (C: being committed to it)</strong>.</span> Without enough commitment, you may easily give up when problems happen. I have some friends whose businesses didn’t survive during difficult times; it wasn’t because they were stupid, it was just a lack of commitment<span style=\"text-decoration: underline; background-color: #ffe786;\">. I can’t always be sure that my products or services are better than my competitors, but I <strong>(17/18) pay attention to details (D: paying attention to detail)</strong> and try to improve all the little things, as they can actually make a big difference.</span></p>\n<p class=\"MsoNormal\">You might worry that you don’t have a very clear and sophisticated business strategy. Personally, I don’t think it’s a problem because you will be changing them all the time anyway. In terms of support at any stage, we do need support from others to back up our business. The support can really make a difference. <span style=\"text-decoration: underline; background-color: #ffe786;\">Before I started my business, <strong>(19/20) my family helped me a lot, both financially and mentally (A: family support)</strong>.</span> There were also people who gave me advice on how to run businesses successfully; however, these advice and ideas were not so practical to me, so I didn’t really use them. Looking back, I felt lucky that I followed my own way of thinking. <span style=\"text-decoration: underline; background-color: #ffe786;\">Also, I was short of funds back then and <strong>(19/20) I loaned money from the bank to start my company (B: getting a loan from a bank)</strong>. I was grateful for that.</span></p>\n<p class=\"MsoNormal\">That’s what I want to share in today’s program. If you have any questions for me, please send it to my email…</p>\n"}]', 0);
INSERT INTO public.questions VALUES ('571c6442-7eba-4936-bd6a-3a09b56d679f', '26bef248-259b-40e6-be03-7937ee6a20d5', 'fillup', ' Questions 1–10', '<div class="quests-inner-desc">
<p class="txt"><em>Complete the notes below. </em><em>Write </em><strong><em>ONE WORD AND/OR A NUMBER </em></strong><em>for each answer.</em></p>
</div>
<div class="quests-des">
<p class="content-write" style="text-align: left;"><strong>SWIMMING LESSONS</strong></p>
<p class="content-write" style="text-align: left;">Classes available</p>
<div class="quill-better-table-wrapper">
<div class="choice-table-wrap">
<table class="quill-better-table choice-table" style="border-collapse: collapse; border: 1px solid rgb(0, 0, 0); width: 100.279%;" border="1"><colgroup> <col style="width: 35.5837%;" width="144"> <col style="width: 64.4163%;" width="524"></colgroup>
<tbody>
<tr data-row="row-7art">
<td style="border-width: 1px; border-color: #000000;" data-row="row-7art">
<p><em> Example</em></p>
<p> </p>
<p> Water</p>
</td>
<td style="border-width: 1px; border-color: #000000;" data-row="row-7art">
<p><em>Answer</em></p>
<p> </p>
<p><strong><em><u>Babies</u></em></strong></p>
</td>
</tr>
</tbody>
</table>
</div>
</div>
<p>For babies of three months upwards</p>
<div class="quill-better-table-wrapper">
<div class="choice-table-wrap">
<table class="quill-better-table choice-table" style="border-collapse: collapse; border-width: 1px; border-color: #000000; width: 100%; height: 122.917px;" border="1"><colgroup> <col style="width: 35.5245%;" width="143"> <col style="width: 64.4755%;" width="522"></colgroup>
<tbody>
<tr style="height: 61.4583px;" data-row="row-mri5">
<td style="border-width: 1px; border-color: #000000;" data-row="row-mri5">
<p> Focus</p>
</td>
<td style="border-width: 1px; border-color: #000000;" data-row="row-mri5">
<p>water familiarisation using {toys}</p>
</td>
</tr>
<tr style="height: 61.4583px;" data-row="row-ctt0">
<td style="border-width: 1px; border-color: #000000;" data-row="row-ctt0">
<p> Cost</p>
</td>
<td style="border-width: 1px; border-color: #000000;" data-row="row-ctt0">
<p>£ 3.80 per lesson</p>
</td>
</tr>
</tbody>
</table>
</div>
</div>
<p><strong>Beginners</strong></p>
<p class="content-write" style="text-align: left;">For people with no experience of swimming</p>
<div class="quill-better-table-wrapper">
<div class="choice-table-wrap">
<table class="quill-better-table choice-table" style="border-collapse: collapse; border-width: 1px; border-color: #000000; width: 99.0223%;" border="1"><colgroup> <col style="width: 36.3861%;" width="147"> <col style="width: 63.6139%;" width="514"></colgroup>
<tbody>
<tr data-row="row-8lhq">
<td style="border-width: 1px; border-color: #000000;" data-row="row-8lhq">
<p> Focus</p>
</td>
<td style="border-width: 1px; border-color: #000000;" data-row="row-8lhq">
<p>– {breathing} techniques</p>
<p> </p>
<p>– opening the eyes underwater</p>
<p>– swimming five metres</p>
</td>
</tr>
</tbody>
</table>
</div>
</div>
<p><strong>Intermediate</strong></p>
<div class="quill-better-table-wrapper">
<div class="choice-table-wrap">
<table class="quill-better-table choice-table" style="border-collapse: collapse; border-width: 1px; border-color: #000000; width: 99.4413%;" border="1"><colgroup> <col style="width: 36.3636%;" width="144"> <col style="width: 63.6364%;" width="504"></colgroup>
<tbody>
<tr data-row="row-72yd">
<td style="border-width: 1px; border-color: #000000;" data-row="row-72yd">
<p> Focus</p>
</td>
<td style="border-width: 1px; border-color: #000000;" data-row="row-72yd">
<p>– learning main swimming strokes</p>
<p> </p>
<p>– introduction to {diving}</p>
<p>– swimming underwater</p>
<p>– {safety} in the water</p>
</td>
</tr>
<tr data-row="row-ro99">
<td style="border-width: 1px; border-color: #000000;" data-row="row-ro99">
<p> Cost</p>
</td>
<td style="border-width: 1px; border-color: #000000;" data-row="row-ro99">
<p>£61 per course</p>
</td>
</tr>
<tr data-row="row-4j9d">
<td style="border-width: 1px; border-color: #000000;" data-row="row-4j9d">
<p> Other information:</p>
</td>
<td style="border-width: 1px; border-color: #000000;" data-row="row-4j9d">
<p>– maximum of 12 pupils per class</p>
<p> </p>
<p>– class is for {adults}</p>
</td>
</tr>
</tbody>
</table>
</div>
</div>
<p><strong>Advances</strong></p>
<div class="quill-better-table-wrapper">
<div class="choice-table-wrap">
<table class="quill-better-table choice-table" style="border-collapse: collapse; border-width: 1px; border-color: #000000; width: 99.581%;" border="1"><colgroup> <col style="width: 36.0795%;" width="142"> <col style="width: 63.9205%;" width="502"></colgroup>
<tbody>
<tr data-row="row-truv">
<td style="border-width: 1px; border-color: #000000;" data-row="row-truv">
<p> Focus:</p>
</td>
<td style="border-width: 1px; border-color: #000000;" data-row="row-truv">
<p>– more efficient techniques</p>
<p> </p>
<p>– improving {speed}</p>
<p>– competitions</p>
</td>
</tr>
</tbody>
</table>
</div>
</div>
<p><strong>Other information</strong></p>
<p class="content-write" style="text-align: left;">– Date when Intermediate course begins: Tuesday {January 13th|January 13|13th January|13 January} (need to register soon)</p>
<p class="content-write" style="text-align: left;">– Time: 7.30 p.m.</p>
<p class="content-write" style="text-align: left;">– Participants will be provided with a swimming {hat}</p>
<p class="content-write" style="text-align: left;">– Bring change for the {locker}</p>
<p class="content-write" style="text-align: left;"><strong>Benefits of swimming</strong></p>
<p class="content-write" style="text-align: left;">– Health benefits</p>
<p class="content-write" style="text-align: left;">– Improvement in {confidence}</p>
<p class="content-write" style="text-align: left;">– Could save a life</p>
</div>', NULL, 'summary_completion', 'null', 'null', 'null', 'null', '[{"content": "<p><strong>Narrator:</strong> You will hear a man telephoning to ask for information about swimming lessons. First you have some time to look at questions 1 to 6 on page two. You will see that there is an example that has been done for you. On this occasion only the conversation relating to this will be played first.</p>\n<p><strong>School:</strong> Hello City Swim School.</p>\n<p><strong>Man:</strong> Oh, Hello. Uh, I wanted to ask about swimming lessons. That’s in a class, not individual, right?</p>\n<p><strong>School:</strong> Well, we do group lessons at various levels. To start off with, we have what we call the Water Babies class.</p>\n<p><strong>(Narrator)</strong> The first class is called Water Babies, so babies has been written in the space. Now we shall begin. You should answer the questions as you listen because you will not hear the recording a second time. Listen carefully and answer questions 1 to six.</p>\n<p><strong>School:</strong> Hello City Swim School.</p>\n<p><strong>Man:</strong> Oh, Hello. Uh, I wanted to ask about swimming lessons. That’s in a class, not individual, right?</p>\n<p><strong>School:</strong> Well, we do group lessons at various levels. To start off with, we have what we call the Water Babies class. That’s for babies of three months and over.</p>\n<p><strong>Man:</strong> Really, as young as that?</p>\n<p><strong>School:</strong> Yes, that’s really the best time to start.</p>\n<p><strong>Man:</strong> Right. Well, we do have a baby so I’ll make a note of that. Um, what do they actually do in the lessons?</p>\n<p><strong>School:</strong> Well, the main aim is just to familiarise them with the water, so they feel at ease there. They get the children to enjoy themselves. They have lots of <span style=\"background-color: #f1c40f;\"><strong>(1) toys</strong> </span>and things they can use to play with in the water.</p>\n<p><strong>Man:</strong> Right. And how much do the lessons cost?</p>\n<p><strong>School:</strong> They’re held on Tuesday mornings and each lesson costs £3 80. It’s not really a course as such.</p>\n<p><strong>Man:</strong> Okay, well, I’ll talk to my wife about that. Uh, but I was actually ringing about lessons for me.</p>\n<p><strong>School:</strong> Okay, so are you a beginner?</p>\n<p><strong>Man:</strong> Not exactly, but I’m not very good. (ha)</p>\n<p><strong>School:</strong> Well, the beginner’s classes are really for people who don’t have any experience of swimming. They aim to teach you techniques for <span style=\"background-color: #f1c40f;\"><strong>(2) breathing</strong></span> in the water, and they get you to do things like put your head underwater and open your eyes.</p>\n<p><strong>Man:</strong> Okay, I can do that.</p>\n<p><strong>School:</strong> And by the end of the course, they aim to have you swimming five metres.</p>\n<p><strong>Man:</strong> I think I can probably just about do that.</p>\n<p><strong>School:</strong> OK, so you’d be better in the intermediate class then. That’s where you learn the main swimming strokes—front stroke, back stroke, and so on.</p>\n<p><strong>Man:</strong> What about <span style=\"background-color: #f1c40f;\"><strong>(3) diving</strong></span>?</p>\n<p><strong>School:</strong> Yes, they’d teach you how to do that, and you’d also do some underwater swimming. Not with a tank or anything.</p>\n<p><strong>Man:</strong> Oh no, not scuba, just ordinary underwater swimming.</p>\n<p><strong>School:</strong> And in the intermediate course, you also look at water <span style=\"background-color: #f1c40f;\"><strong>(4) safety</strong></span>. Both in the pool and when swimming in other places.</p>\n<p><strong>Man:</strong> Okay, well, that sounds the right level for me.</p>\n<p><strong>School:</strong> I think so. How much does that cost?</p>\n<p><strong>School:</strong> <strong>£61</strong> for a course. That’s 10 lessons.</p>\n<p><strong>Man:</strong> Can you tell me a bit more about the class? How many people would there be in it?</p>\n<p><strong>School:</strong> Well, the intermediate class is usually around 8 to 10. That’s what we aim at, though occasionally it might go up to twelve.</p>\n<p><strong>Man:</strong> OK, that sounds quite a reasonable size. Not too many. And the class is for <span style=\"background-color: #f1c40f;\"><strong>(5) adults</strong></span>, is it?</p>\n<p><strong>School:</strong> Yes.</p>\n<p><strong>Man:</strong> OK. And just out of interest, is there an advanced class?</p>\n<p><strong>School:</strong> Yes. They focus on developing more efficient swimming techniques and on working on your <span style=\"background-color: #f1c40f;\"><strong>(6) speed</strong></span>. And they also prepare you for competitive swimming.</p>\n<p><strong>Man:</strong> Okay. Now I think I’d want to start with the intermediate one, really.</p>\n<p><strong>(Narrator)</strong> Before you hear the rest of the conversation, you have some time to look at questions 7 to 10 on page three. Now listen and answer questions 7 to ten.</p>\n<p><strong>Man:</strong> Now, is there anything special I need to know?</p>\n<p><strong>School:</strong> Well, the classes are on Tuesdays, and the first lesson is on <span style=\"background-color: #f1c40f;\"><strong>(7) January the thirteenth</strong></span>. So you need to register before then. January the 8th is the latest, but it’s filling up quickly, so I’d do it straight away. You can pick up a form here or get one off the internet.</p>\n<p><strong>Man:</strong> And classes are at 7:30 PM. Right. Then I just roll up with my swimming trunks. Do I have to bring my own towel?</p>\n<p><strong>School:</strong> That’s right. We provide all participants with a swimming <span style=\"background-color: #f1c40f;\"><strong>(8) hat</strong></span> though.</p>\n<p><strong>Man:</strong> Oh, huh. I don’t usually wear one.</p>\n<p><strong>School:</strong> Well, we do insist on it, actually. It helps the instructor to identify you, apart from anything else. Oh, and don’t forget you need a 20p coin for the <span style=\"background-color: #f1c40f;\"><strong>(9) locker</strong></span>.</p>\n<p><strong>Man:</strong> Oh, okay. Right. Well, I’ve been meaning to do this for ages. I really need to get some more exercise. And everyone says swimming is good for your health.</p>\n<p><strong>School:</strong> Yes, and a lot of people find it improves their <span style=\"background-color: #f1c40f;\"><strong>(10) confidence</strong></span> too. And of course, it could save your life or even someone else’s.</p>\n<p><strong>Man:</strong> That’s right. Okay, well, thanks very much.</p>\n<p><strong>School:</strong> Goodbye.</p>\n<p><strong>(Narrator)</strong> That is the end of Section 1. You now have half a minute to check your answers.</p>"}]', 0);
INSERT INTO public.questions VALUES ('07e9e17a-30d6-437d-8913-9949a9f9e85f', '5f08c0e2-1865-4b67-96c0-8ec0eb35304e', 'radio', 'Questions 11–15', '', '<p style="text-align: left;">Choose the correct answers</p>
<p style="text-align: left;"><strong>Working for Johnson Jones</strong></p>', 'multiple_choice', '[{"correct": 1, "options": [{"option_text": "the pay  "}, {"option_text": "the staff discount"}, {"option_text": "the working hours"}], "question": "What does Mark say first attracts people to working for Johnson Jones?"}, {"correct": 0, "options": [{"option_text": "is focused on long term planning. "}, {"option_text": "provides excellent customer service. "}, {"option_text": "offers value for money."}], "question": "Mark says the company is one of the country s most successful retailers because it"}, {"correct": 2, "options": [{"option_text": "are better trained."}, {"option_text": "have better job security."}, {"option_text": "are given more responsibility."}], "question": "Mark says that because Johnson Jones is a partnership, the staff   "}, {"correct": 1, "options": [{"option_text": "8% "}, {"option_text": "15% "}, {"option_text": "20%"}], "question": "What is the typical annual bonus that partners receive? "}, {"correct": 2, "options": [{"option_text": "one year."}, {"option_text": "six months."}, {"option_text": "three months"}], "question": "To qualify for the leisure and holiday facilities, partners must have worked for the company for   "}]', 'null', 'null', 'null', '[{"content": "<p><strong>Narrator:</strong> You will hear a manager called Mark Bergin who works for a large retailer called Johnson Jones giving a talk at a recruitment fair. First you have some time to look at questions 11 to 15 on page three. Now listen carefully and answer questions 11 to fifteen.</p>\n<p><strong>Mark Bergin:</strong> Good Morning. My name is Mark Bergin, I’m a human resources manager at Johnson Jones, and I’m here to tell you about what it’s like working for one of the country’s best employers. The Company has two hundred and twenty five department stores and owns a further one hundred and fifty supermarkets. At our latest store opening, we had over nine thousand applicants for seven hundred and fifty posts. So why do so many people want to work for us?</p>\n<p><strong>Mark Bergin:</strong> Well, the first thing that attracts them isn’t so much the salary, although that is a little above average. It’s the idea of getting a massive <span style=\"background-color: #f1c40f;\"><strong>(11) twenty five percent off everything</strong></span> from washing machines to designer handbags. People are prepared to put in long hours to get those kinds of perks.</p>\n<p><strong>Mark Bergin:</strong> Johnson Jones has been going strong for nearly one hundred and fifty years and has outlived many of its strongest competitors. Of course, this has something to do with the high quality products that we sell and our motto, “Better for less,” which means customers know they are getting good value for money. But we’re not alone in that. Where we are different is in our approach to making a profit. Other companies think in the short term, whereas we always take a more strategic view, looking three or five years ahead. <span style=\"background-color: #f1c40f;\"><strong>(12) (focused on long term planning)</strong></span></p>\n<p><strong>Mark Bergin:</strong> The company isn’t owned by a family or shareholders, it’s a partnership, which means it’s owned by its full time employees, who are all partners and have a share in the company. In return for the very generous benefits they get, they’re expected to put in extra effort and <span style=\"background-color: #f1c40f;\"><strong>(13) take an active role in running the company</strong>.</span> This means <span style=\"background-color: #f1c40f;\"><strong>(13) they’re involved</strong></span> in things like making decisions about pension contributions, for example.</p>\n<p><strong>Mark Bergin:</strong> Another very attractive reason for working for us is the annual bonus, which we get as a percentage of our salary. Last year it was <span style=\"background-color: #f1c40f;\"><strong>(14) fifteen percent</strong></span>, about two months salary, which is pretty standard. It can go down to eight percent, but that’s unusual, and a couple of times it’s even been above twenty percent.Some people use it to pay off loans; others save it for a deposit on a house.</p>\n<p><strong>Mark Bergin:</strong> The most popular benefit for partners are the subsidized holiday centres, which are owned by the company. Once a year partners can book in for up to two weeks. It’s for anyone from cleaners to directors with a minimum of<span style=\"background-color: #f1c40f;\"> <strong>(15) three months</strong></span> service. After six months service, partners are entitled to a further subsidy on the cost of their stay.</p>\n<p><strong>Narrator:</strong> Before you hear the rest of the talk, you have some time to look at questions 16 to 20 on page four. Now listen and answer questions 16 to twenty.</p>\n<p><strong>Mark Bergin:</strong> Let me just give you an idea of what’s on offer at the holiday centres. The Grange which is the largest of the holiday centres is used for conferences by the company and the board of directors always have their annual meeting there. <span style=\"background-color: #f1c40f;\"><strong>(16) (C: regularly used by senior management)</strong></span>. It’s all very informal, not like a normal conference centre.</p>\n<p><strong>Mark Bergin:</strong> Meadow House is located in Kent, which is famous for its apples and other fruit, and it’s a large country house. What’s unusual about it is that unlike other hotels, you have access to the kitchen, so <span style=\"background-color: #f1c40f;\"><strong>(17) it feels more like staying with a friend (F)</strong>.</span></p>\n<p><strong>Mark Bergin:</strong> Coombe Manor is a working farm. There are loads of cows and sheep, none of which actually end up on our supermarket shelves. It’s a <span style=\"background-color: #f1c40f;\"><strong>(18) paradise for kids (B)</strong> </span>as there’s plenty of space to run wild and also an indoor pool. You can choose to stay in cottages or camp by the lake.</p>\n<p><strong>Mark Bergin:</strong> The Barn is where I recently celebrated my twenty fifth wedding anniversary. <span style=\"background-color: #f1c40f;\"><strong>(19) You can rent the whole place out for a large group of up to forty friends (A)</strong></span>. We got all our food delivered from the nearest Johnson’s Jones supermarket, so there was no cooking to be done. Perfect! All that was missing was the spa, which should be opening next year.</p>\n<p><strong>Mark Bergin:</strong> The Stable is often hard to get into because it’s so popular. That’s partly because it’s right on the beach with beautiful sea views and <span style=\"background-color: #f1c40f;\"><strong>(20) only an hour by train from London (G)</strong></span>, ideal for weekends. The company sailing club is located there, which was started by the company’s founder in 1885. So I’m sure you’ll all agree that there really is…</p>"}]', 0);
INSERT INTO public.questions VALUES ('2c40221b-16f3-484f-a5ca-2f0513b4b684', '5f08c0e2-1865-4b67-96c0-8ec0eb35304e', 'matching', 'Questions 16–20', '', '<p>Choose <strong>FIVE </strong>answers from the box, A-G</p>
<p>What information is given about each of the following staff holiday centres?</p>', 'summary_completion', 'null', 'null', '{"layoutType": "summary", "summaryText": "<p><strong>Staff Holiday Centres</strong></p>\n<p> </p>\n<p>The Grange {C regularly used by senior management}</p>\n<p> </p>\n<p>Meadow House {F similar to being in someone’s home}</p>\n<p> </p>\n<p>Coombe Manor {B suitable for families with children}</p>\n<p> </p>\n<p>The Barn {A available for celebrations and parties}</p>\n<p> </p>\n<p>The Stable {G good for short breaks}</p>", "answerOptions": [{"optionText": "A available for celebrations and parties"}, {"optionText": "B suitable for families with children"}, {"optionText": "C regularly used by senior management"}, {"optionText": "D also supplies food to the company’s supermarkets"}, {"optionText": "E spa facilities available"}, {"optionText": "F similar to being in someone’s home"}, {"optionText": "G good for short breaks"}], "matchingItems": []}', 'null', '[{"content": "<p>1</p>"}]', 1);
INSERT INTO public.questions VALUES ('a7d07747-0a77-4cd6-bb63-3301093f513f', 'f86a05c0-babe-4008-ae26-fd051f9c098f', 'fillup', 'Questions 31–40', '<p>Complete the notes below.</p>
<p>Write <strong>ONE WORD AND/OR A NUMBER</strong> for each answer.</p>
<p style="text-align: left;"><span style="font-size: 12pt;"><strong>The Africa clawed frog (Xenopus laevis)</strong></span></p>
<p><strong>Description</strong></p>
<p>∙ Skin is {smooth} and can vary in colour</p>
<p>∙ Skin is coated with a slippery film for {protection}</p>
<p>∙ Males are {half} the size of females</p>
<p><strong>Habitats</strong></p>
<p>∙ Native to Africa</p>
<p>∙ Live in fresh water – prefered water that is {still}</p>
<p>∙ Can survive high levels of {salt} in water</p>
<p>∙ Cannot survive if there is any metal in water</p>
<p>∙ In drought conditions, may live in {mud} for up to a year</p>
<p><strong>Diet</strong></p>
<p>∙ Eat living or dead water creatures</p>
<p>∙ Find food using their sense of {smell}, their fingers, and their lateral lines</p>
<p>∙ Take food into their mouths using from legs and a {pump} system</p>
<p><strong>Other information</strong></p>
<p>∙ Now popular as a pet in the US</p>
<p>∙ In some US states they are identified as a {pest}</p>
<p>∙ Used in laboratories for developmental research</p>
<p>∙ Mucus from the skin was {antibiotic} properties</p>', NULL, 'summary_completion', 'null', 'null', 'null', 'null', '[{"content": "<p data-path-to-node=\"2\"><strong data-path-to-node=\"2\" data-index-in-node=\"0\">SECTION 4: THE AFRICAN CLAWED FROG (XENOPUS LAEVIS)</strong></p>\n<p data-path-to-node=\"3\"><strong data-path-to-node=\"3\" data-index-in-node=\"0\">Student:</strong> The aim of our study was to look at how naturally occurring substances can be used to treat infections, and we carried out a laboratory study using a frog called the African clawed frog, which has the scientific name <em data-path-to-node=\"3\" data-index-in-node=\"226\">Xenopus laevis</em>.</p>\n<p data-path-to-node=\"4\">So before I describe our study in detail, let me give you a general description about this frog. Like most other frogs, the African clawed frogs have a <span style=\"background-color: #f3db7b;\"><strong data-path-to-node=\"4\" data-index-in-node=\"152\">(31) smooth</strong></span> skin. This is one way you can distinguish them from toads, whose skin is rough, and they can change the colour of their skin to blend in with their surroundings.</p>\n<p data-path-to-node=\"5\">The surface of their skin also has another feature: it’s covered with a layer of mucus. This makes it hard for other creatures to pick them up, and so it provides <span style=\"background-color: #f3db7b;\"><strong data-path-to-node=\"5\" data-index-in-node=\"163\">(32) protection</strong></span> against predators.</p>\n<p data-path-to-node=\"6\">How big are they? Well, it depends on whether they’re male or female, because the females in this case are a whole lot bigger than the males. A large-sized female may be 8 inches long, while the males are about <span style=\"background-color: #f3db7b;\"><strong data-path-to-node=\"6\" data-index-in-node=\"211\">(33) half</strong></span> that size, so they’re pretty small in comparison.</p>\n<hr data-path-to-node=\"7\">\n<p data-path-to-node=\"8\"><strong data-path-to-node=\"8\" data-index-in-node=\"0\">HABITAT</strong></p>\n<p data-path-to-node=\"9\"><strong data-path-to-node=\"9\" data-index-in-node=\"0\">Student:</strong> What about their natural habitat? As their name suggests, these frogs are native to Africa and they’re found in most parts of Africa south of the Sahara Desert. They make their houses in fresh water, but they’re rarely found in running streams; they like <span style=\"background-color: #f3db7b;\"><strong data-path-to-node=\"9\" data-index-in-node=\"264\">(34) still</strong></span> water.</p>\n<p data-path-to-node=\"10\">As far as the temperature of the water goes, they’re not too fussy; it can be warm or cool. They don’t need to be in water where there are plants growing, and they can live in water that has quite a lot of <span style=\"background-color: #f3db7b;\"><strong data-path-to-node=\"10\" data-index-in-node=\"206\">(35) salt</strong></span> in it, so they can live in brackish areas such as marshes and estuaries.</p>\n<p data-path-to-node=\"11\">However, although they can live in a wide range of conditions, one thing that they are unable to tolerate is even very small traces of metal. That’s immediately fatal to them, and that’s important to remember when they’re being kept in captivity. You’ve got to be careful what kind of tank you use and what you put into the water. In their natural habitat, the frogs normally live in water the whole time, but in unfavorable conditions such as drought, they can burrow into the <span style=\"background-color: #f3db7b;\"><strong data-path-to-node=\"11\" data-index-in-node=\"323\">(36) mud</strong></span> and survive there for up to a year until conditions improve.</p>\n<hr data-path-to-node=\"12\">\n<p data-path-to-node=\"13\"><strong data-path-to-node=\"13\" data-index-in-node=\"0\">DIET</strong></p>\n<p data-path-to-node=\"14\"><strong data-path-to-node=\"14\" data-index-in-node=\"0\">Student:</strong> As far as their diet is concerned, they’re carnivorous. They eat other creatures they find in the water, and they’re scavengers, which means they’ll eat almost anything living or dead. They’ve got huge appetites.</p>\n<p data-path-to-node=\"15\">Because the water they live in is often quite dirty and visibility is limited, they can’t locate their food using their sense of sight. Instead, they use <span style=\"background-color: #f3db7b;\"><strong data-path-to-node=\"15\" data-index-in-node=\"154\">(37) smell</strong></span>, and also the sensitive fingers on their front legs, and they also have what’s called a lateral line system on the sides of their bodies which is sensitive to vibrations in the water.</p>\n<p data-path-to-node=\"16\">They use their front legs to get the food into their mouths, together with a type of <span style=\"background-color: #f3db7b;\"><strong data-path-to-node=\"16\" data-index-in-node=\"85\">(38) pump</strong></span> arrangement that sucks the food into the mouth and down into their stomach. They don’t have any teeth, so everything just goes straight down.</p>\n<hr data-path-to-node=\"17\">\n<p data-path-to-node=\"18\"><strong data-path-to-node=\"18\" data-index-in-node=\"0\">OTHER INFORMATION</strong></p>\n<p data-path-to-node=\"19\"><strong data-path-to-node=\"19\" data-index-in-node=\"0\">Student:</strong> Okay well, although Xenopus started off in Africa, they’re now quite widespread. One of the reasons for this is that a lot of people in the US like keeping them at home as a pet. They’re quite easy to look after and they can live for up to 20 years.</p>\n<p data-path-to-node=\"20\">But in some states of the US, such as California and Virginia, they have escaped from captivity and are reproducing in the wild and threatening native species there. So they’ve been classified as a <span style=\"background-color: #f3db7b;\"><strong data-path-to-node=\"20\" data-index-in-node=\"198\">(39) pest</strong></span> in these areas.</p>\n<p data-path-to-node=\"21\">But another very important use for the frogs is for research in laboratories. Because the females lay large numbers of eggs and the embryos are transparent, it’s easy to see how they are developing, and so they’re used for research into genetics and development. Also, the slippery mucus that covers their skin acts as an<span style=\"background-color: #f3db7b;\"> <strong data-path-to-node=\"21\" data-index-in-node=\"258\">(40) antibiotic</strong></span>, killing parasites and bacteria. And this is why we chose this frog for our research.So let me describe the aim of our study. We wanted…</p>"}]', 0);
INSERT INTO public.questions VALUES ('809a1d65-5fa8-4e54-b907-54ff1980286d', '234d19f9-86e3-41c8-82cc-8bf540e6d52d', 'radio', 'Questions 27-30', '', '<p>Choose the correct letter <strong>A</strong>, <strong>C, B </strong>or <strong>D</strong>.</p>', 'multiple_choice', '[{"correct": 2, "options": [{"option_text": " who is aware of being set apart from other people."}, {"option_text": "whose brain structure is unlike that of other people."}, {"option_text": "who can perform extremely well in early childhood."}, {"option_text": "whose essential skills are more varied than those of ordinary people."}], "question": "In the first paragraph, the writer suggests that a musician who is ‘talented’ is someone"}, {"correct": 2, "options": [{"option_text": "Which part of the brain is linked to a particular musical skill,"}, {"option_text": " Which type of musical skill leads to the greatest change in the brain"}, {"option_text": "Whether a feature of the brain is a cause or an effect of a musical skill"}, {"option_text": "Whether the acquisition of a musical skill is easier for some people than others"}], "question": "According to the winter, what is unclear about the findings of Gottfried Schlaug?"}, {"correct": 0, "options": [{"option_text": "Changes may occur in the brain following violin practice."}, {"option_text": "Left-handed violinists have a different brain structure from other people."}, {"option_text": "A violinist’s hand size is not due to practice but to genetic factors."}, {"option_text": "Violinists are born with brains that have a particular structure."}], "question": "According to the writer, what has been established by studies of violin players?"}, {"correct": 0, "options": [{"option_text": "talent may have little to do with expertise."}, {"option_text": "practice may actually prevent the development of talent."}, {"option_text": " talent may not be recognised by teachers."}, {"option_text": "expertise may be related to quality of instruction. "}], "question": "According to the writer, findings on the amount of practice done by expert musicians suggest that"}]', 'null', 'null', 'null', '[{"content": "<p data-path-to-node=\"3\"><strong data-path-to-node=\"3\" data-index-in-node=\"0\">27. In the first paragraph, the writer suggests that a musician who is ‘talented’ is someone — {C} who can perform extremely well in early childhood.</strong></p>\n<ul data-path-to-node=\"4\">\n<li>\n<p data-path-to-node=\"4,0,0\"><strong data-path-to-node=\"4,0,0\" data-index-in-node=\"0\">Trích dẫn:</strong> “The emphasis on <strong data-path-to-node=\"4,0,0\" data-index-in-node=\"28\">early identification</strong> means that to investigate it, we study the <strong data-path-to-node=\"4,0,0\" data-index-in-node=\"92\">development of skills in children</strong>.” (Đoạn 1)</p>\n</li>\n<li>\n<p data-path-to-node=\"4,1,0\"><strong data-path-to-node=\"4,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Định nghĩa về tài năng trong bài nhấn mạnh vào việc nhận diện sớm ở trẻ em trước khi đạt trình độ xuất sắc, tức là có biểu hiện vượt trội ngay từ nhỏ.</p>\n</li>\n</ul>\n<p data-path-to-node=\"5\"><strong data-path-to-node=\"5\" data-index-in-node=\"0\">28. According to the writer, what is unclear about the findings of Gottfried Schlaug? — {C} Whether a feature of the brain is a cause or an effect of a musical skill.</strong></p>\n<ul data-path-to-node=\"6\">\n<li>\n<p data-path-to-node=\"6,0,0\"><strong data-path-to-node=\"6,0,0\" data-index-in-node=\"0\">Trích dẫn:</strong> “…it’s <strong data-path-to-node=\"6,0,0\" data-index-in-node=\"20\">not clear if it starts out larger</strong> in people who eventually acquire AP, or if the <strong data-path-to-node=\"6,0,0\" data-index-in-node=\"101\">acquisition of AP makes the planum increase in size</strong>.” (Đoạn 3)</p>\n</li>\n<li>\n<p data-path-to-node=\"6,1,0\"><strong data-path-to-node=\"6,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Nghiên cứu thấy vùng <em data-path-to-node=\"6,1,0\" data-index-in-node=\"33\">planum temporale</em> lớn hơn ở người có cao độ tuyệt đối (AP), nhưng không rõ đó là do bẩm sinh (nguyên nhân – cause) hay do luyện tập mà thành (kết quả – effect).</p>\n</li>\n</ul>\n<p data-path-to-node=\"7\"><strong data-path-to-node=\"7\" data-index-in-node=\"0\">29. According to the writer, what has been established by studies of violin players? — {A} Changes may occur in the brain following violin practice.</strong></p>\n<ul data-path-to-node=\"8\">\n<li>\n<p data-path-to-node=\"8,0,0\"><strong data-path-to-node=\"8,0,0\" data-index-in-node=\"0\">Trích dẫn:</strong> “…the region of the brain… <strong data-path-to-node=\"8,0,0\" data-index-in-node=\"42\">increases in size as a result of practice</strong>.” (Đoạn 4)</p>\n</li>\n<li>\n<p data-path-to-node=\"8,1,0\"><strong data-path-to-node=\"8,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Nghiên cứu khẳng định vùng não điều khiển tay trái của người chơi violin to lên nhờ quá trình luyện tập.</p>\n</li>\n</ul>\n<p data-path-to-node=\"9\"><strong data-path-to-node=\"9\" data-index-in-node=\"0\">30. According to the writer, findings on the amount of practice done by expert musicians suggest that — {A} talent may have little to do with expertise.</strong></p>\n<ul data-path-to-node=\"10\">\n<li>\n<p data-path-to-node=\"10,0,0\"><strong data-path-to-node=\"10,0,0\" data-index-in-node=\"0\">Trích dẫn:</strong> “…students who achieved the highest performance ratings had practiced the most, <strong data-path-to-node=\"10,0,0\" data-index-in-node=\"93\">irrespective of which ‘talent’ group</strong> they had been assigned to…” (Đoạn 5)</p>\n</li>\n<li>\n<p data-path-to-node=\"10,1,0\"><strong data-path-to-node=\"10,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Kết quả cho thấy những người giỏi nhất là những người tập nhiều nhất, bất kể ban đầu họ được đánh giá là có “tài năng” hay không. Điều này ngụ ý tài năng ít có mối liên hệ với trình độ chuyên gia so với nỗ lực.</p>\n</li>\n</ul>"}]', 0);
INSERT INTO public.questions VALUES ('e827996b-aade-4f8c-ba8b-a523c726aa76', '234d19f9-86e3-41c8-82cc-8bf540e6d52d', 'radio', 'Question 31-36', '', '<p>Choose <strong>YES</strong> if the statement agrees with the claims of the writer, <strong>NO </strong>if the statement contradicts the claims of the writer, <strong>NOT GIVEN </strong>if it is impossible to say what the writer thinks about this</p>', 'yes_no_not_given', '[{"correct": 2, "options": [{"option_text": "YES"}, {"option_text": "NO"}, {"option_text": "NOT GIVEN"}], "question": "Anders Ericsson''s work with cognitive psychology has influenced other researchers."}, {"correct": 0, "options": [{"option_text": "YES"}, {"option_text": "NO"}, {"option_text": "NOT GIVEN"}], "question": "Different areas of expertise seem to have one specific thing in common."}, {"correct": 2, "options": [{"option_text": "YES"}, {"option_text": "NO"}, {"option_text": "NOT GIVEN"}], "question": " In order to be useful, practice must be carried out regularly every day."}, {"correct": 1, "options": [{"option_text": "YES"}, {"option_text": "NO"}, {"option_text": "NOT GIVEN"}], "question": "Anyone who practices for long enough can reach the level of a world-class expert."}, {"correct": 1, "options": [{"option_text": "YES"}, {"option_text": "NO"}, {"option_text": "NOT GIVEN"}], "question": "Occasionally, someone can become an expert at global level with fewer than 10,000 hours’ practice."}, {"correct": 0, "options": [{"option_text": "YES"}, {"option_text": "NO"}, {"option_text": "NOT GIVEN"}], "question": "Existing knowledge of learning and cognitive skills supports the importance of practice."}]', 'null', 'null', 'null', '[{"content": "<p data-path-to-node=\"13\"><strong data-path-to-node=\"13\" data-index-in-node=\"0\">31. Anders Ericsson’s work… has influenced other researchers. — {NOT GIVEN}</strong></p>\n<ul data-path-to-node=\"14\">\n<li>\n<p data-path-to-node=\"14,0,0\"><strong data-path-to-node=\"14,0,0\" data-index-in-node=\"0\">Giải thích:</strong> Bài đọc nhắc đến lý thuyết và cách tiếp cận của Ericsson, nhưng <strong data-path-to-node=\"14,0,0\" data-index-in-node=\"76\">không đề cập</strong> đến việc ông có ảnh hưởng đến các nhà nghiên cứu khác hay không.</p>\n</li>\n</ul>\n<p data-path-to-node=\"15\"><strong data-path-to-node=\"15\" data-index-in-node=\"0\">32. Different areas of expertise seem to have one specific thing in common. — {YES}</strong></p>\n<ul data-path-to-node=\"16\">\n<li>\n<p data-path-to-node=\"16,0,0\"><strong data-path-to-node=\"16,0,0\" data-index-in-node=\"0\">Trích dẫn:</strong> “…ten thousand hours of practice is required to achieve the level of mastery… in <strong data-path-to-node=\"16,0,0\" data-index-in-node=\"96\">anything</strong>.” (Đoạn 6)</p>\n</li>\n<li>\n<p data-path-to-node=\"16,1,0\"><strong data-path-to-node=\"16,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Điểm chung duy nhất của mọi lĩnh vực chuyên gia (cờ vua, thể thao, âm nhạc…) chính là con số 10.000 giờ luyện tập.</p>\n</li>\n</ul>\n<p data-path-to-node=\"17\"><strong data-path-to-node=\"17\" data-index-in-node=\"0\">33. In order to be useful, practice must be carried out regularly every day. — {NOT GIVEN}</strong></p>\n<ul data-path-to-node=\"18\">\n<li>\n<p data-path-to-node=\"18,0,0\"><strong data-path-to-node=\"18,0,0\" data-index-in-node=\"0\">Trích dẫn:</strong> “…roughly 20 hours a week for ten years.” (Đoạn 6)</p>\n</li>\n<li>\n<p data-path-to-node=\"18,1,0\"><strong data-path-to-node=\"18,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Bài đọc đưa ra con số trung bình theo tuần, nhưng <strong data-path-to-node=\"18,1,0\" data-index-in-node=\"62\">không bắt buộc</strong> là phải tập luyện đều đặn “mọi ngày” (every day).</p>\n</li>\n</ul>\n<p data-path-to-node=\"19\"><strong data-path-to-node=\"19\" data-index-in-node=\"0\">34. Anyone who practices for long enough can reach the level of a world-class expert. — {NO}</strong></p>\n<ul data-path-to-node=\"20\">\n<li>\n<p data-path-to-node=\"20,0,0\"><strong data-path-to-node=\"20,0,0\" data-index-in-node=\"0\">Trích dẫn:</strong> “…this does not address why <strong data-path-to-node=\"20,0,0\" data-index-in-node=\"41\">some people do not seem to get anywhere when they practice</strong>…” (Đoạn 6)</p>\n</li>\n<li>\n<p data-path-to-node=\"20,1,0\"><strong data-path-to-node=\"20,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Tác giả thừa nhận có những người tập mãi mà không đi đến đâu, nên việc nói “bất cứ ai” (anyone) tập đủ lâu cũng thành chuyên gia là sai so với quan điểm bài viết.</p>\n</li>\n</ul>\n<p data-path-to-node=\"21\"><strong data-path-to-node=\"21\" data-index-in-node=\"0\">35. Occasionally, someone can become an expert… with fewer than 10,000 hours’ practice. — {NO}</strong></p>\n<ul data-path-to-node=\"22\">\n<li>\n<p data-path-to-node=\"22,0,0\"><strong data-path-to-node=\"22,0,0\" data-index-in-node=\"0\">Trích dẫn:</strong> “But <strong data-path-to-node=\"22,0,0\" data-index-in-node=\"16\">no-one has yet found a case</strong> in which true world-class expertise was accomplished in less time.” (Đoạn 6)</p>\n</li>\n<li>\n<p data-path-to-node=\"22,1,0\"><strong data-path-to-node=\"22,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Chưa có trường hợp nào được tìm thấy mà thành chuyên gia thế giới với ít thời gian hơn 10.000 giờ.</p>\n</li>\n</ul>\n<p data-path-to-node=\"23\"><strong data-path-to-node=\"23\" data-index-in-node=\"0\">36. Existing knowledge of learning and cognitive skills supports the importance of practice. — {YES}</strong></p>\n<ul data-path-to-node=\"24\">\n<li>\n<p data-path-to-node=\"24,0,0\"><strong data-path-to-node=\"24,0,0\" data-index-in-node=\"0\">Trích dẫn:</strong> “The ten-thousand-hour theory is <strong data-path-to-node=\"24,0,0\" data-index-in-node=\"44\">consistent with what we know about how the brain learns</strong>.” (Đoạn 7)</p>\n</li>\n<li>\n<p data-path-to-node=\"24,1,0\"><strong data-path-to-node=\"24,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Lý thuyết này nhất quán (consistent) với những hiểu biết hiện tại về cách não bộ học tập.</p>\n</li>\n</ul>"}]', 1);
INSERT INTO public.questions VALUES ('aa0356e3-34f6-4dae-beeb-013517fd9ce6', '234d19f9-86e3-41c8-82cc-8bf540e6d52d', 'matching', 'Question 37-40', '', '<p>Complete the summary using the list of words, <strong>A-J</strong> below</p>', 'summary_completion', 'null', 'null', '{"layoutType": "summary", "summaryText": "<p style=\"text-align: center;\"><span style=\"font-size: 12pt;\"><strong>Mozart</strong></span></p>\n<p>The case of Mozart could be quoted as evidence against the 10,000-hour-practice theory. However, the writer points out that the young Mozart received a lot of {tuition} from his father, and that the symphony he wrote at the age of {eight} was not {popular} and may be of only academic interest. The case therefore supports the view that expertise is not solely the result of {inherited} characteristics.</p>", "answerOptions": [{"optionText": "popular"}, {"optionText": "artistic"}, {"optionText": "completed"}, {"optionText": "eight"}, {"optionText": "tuition"}, {"optionText": "encouragement"}, {"optionText": "inherited"}, {"optionText": "four "}, {"optionText": "practice"}, {"optionText": "two"}], "matchingItems": []}', 'null', '[{"content": "<p data-path-to-node=\"27\"><strong data-path-to-node=\"27\" data-index-in-node=\"0\">37. Mozart received a lot of {tuition} from his father.</strong></p>\n<ul data-path-to-node=\"28\">\n<li>\n<p data-path-to-node=\"28,0,0\"><strong data-path-to-node=\"28,0,0\" data-index-in-node=\"0\">Trích dẫn:</strong> “…Mozart had an <strong data-path-to-node=\"28,0,0\" data-index-in-node=\"29\">expert teacher</strong> in his father…” (Đoạn cuối)</p>\n</li>\n<li>\n<p data-path-to-node=\"28,1,0\"><strong data-path-to-node=\"28,1,0\" data-index-in-node=\"0\">Giải thích:</strong> <em data-path-to-node=\"28,1,0\" data-index-in-node=\"12\">Tuition</em> (sự giảng dạy) tương ứng với việc có một người thầy giỏi dạy dỗ.</p>\n</li>\n</ul>\n<p data-path-to-node=\"29\"><strong data-path-to-node=\"29\" data-index-in-node=\"0\">38. …the symphony he wrote at the age of {eight}…</strong></p>\n<ul data-path-to-node=\"30\">\n<li>\n<p data-path-to-node=\"30,0,0\"><strong data-path-to-node=\"30,0,0\" data-index-in-node=\"0\">Trích dẫn:</strong> “Mozart did not write it until he was <strong data-path-to-node=\"30,0,0\" data-index-in-node=\"49\">eight</strong>…” (Đoạn cuối)</p>\n</li>\n</ul>\n<p data-path-to-node=\"31\"><strong data-path-to-node=\"31\" data-index-in-node=\"0\">39. …was not {popular} and may be of only academic interest.</strong></p>\n<ul data-path-to-node=\"32\">\n<li>\n<p data-path-to-node=\"32,0,0\"><strong data-path-to-node=\"32,0,0\" data-index-in-node=\"0\">Trích dẫn:</strong> “…this early work <strong data-path-to-node=\"32,0,0\" data-index-in-node=\"31\">received little acclaim and was not performed very often</strong>.” (Đoạn cuối)</p>\n</li>\n<li>\n<p data-path-to-node=\"32,1,0\"><strong data-path-to-node=\"32,1,0\" data-index-in-node=\"0\">Giải thích:</strong> “Little acclaim” (ít được hoan nghênh) đồng nghĩa với việc nó không hề phổ biến hay nổi tiếng.</p>\n</li>\n</ul>\n<p data-path-to-node=\"33\"><strong data-path-to-node=\"33\" data-index-in-node=\"0\">40. …expertise is not solely the result of {inherited} characteristics.</strong></p>\n<ul data-path-to-node=\"34\">\n<li>\n<p data-path-to-node=\"34,0,0\"><strong data-path-to-node=\"34,0,0\" data-index-in-node=\"0\">Trích dẫn:</strong> “…inborn traits may not be the only cause.” (Đoạn cuối)</p>\n</li>\n<li>\n<p data-path-to-node=\"34,1,0\"><strong data-path-to-node=\"34,1,0\" data-index-in-node=\"0\">Giải thích:</strong> “Inherited characteristics” (đặc điểm di truyền) tương ứng với “inborn traits” (phẩm chất bẩm sinh).</p>\n</li>\n</ul>"}]', 2);
INSERT INTO public.questions VALUES ('d22025eb-7e3d-4eba-a520-1f81adc51a18', '78627bc8-8d64-4564-bdc7-ef39933d398f', 'matrix', 'Questions 27–31', '', '<p><span class="citation-8681">Which paragraph contains the following information?</span></p>
<p><span class="citation-8681">Write the correct letter, </span><strong data-path-to-node="8" data-index-in-node="139"><span class="citation-8681">A–H</span></strong><span class="citation-8681 citation-end-8681">, in boxes 27–31 on your answer sheet.</span></p>', 'choose_a_title', 'null', 'null', 'null', '{"layoutType": "simple", "matrixItems": [{"itemText": "The fact that there may be too much information to cope with", "correctCategoryLetter": "F"}, {"itemText": "The relevance of generating repeat business", "correctCategoryLetter": "A"}, {"itemText": "An example of personalised marketing", "correctCategoryLetter": "B"}, {"itemText": "An illustration of a situation where commissioning new information research might not be advisable", "correctCategoryLetter": "H"}, {"itemText": "How the greater wealth of customers enables them to select from a broader range of products", "correctCategoryLetter": "D"}], "matrixCategories": [{"categoryText": "A", "categoryLetter": "A"}, {"categoryText": "B", "categoryLetter": "B"}, {"categoryText": "C", "categoryLetter": "C"}, {"categoryText": "D", "categoryLetter": "D"}, {"categoryText": "E", "categoryLetter": "E"}, {"categoryText": "F", "categoryLetter": "F"}, {"categoryText": "G", "categoryLetter": "G"}, {"categoryText": "H", "categoryLetter": "H"}]}', '[{"content": "<p data-path-to-node=\"4\"><strong class=\"\" data-path-to-node=\"4\" data-index-in-node=\"0\">27. The fact that there may be too much information to cope with — {F}</strong></p>\n<ul data-path-to-node=\"5\">\n<li>\n<p data-path-to-node=\"5,0,0\"><strong class=\"\" data-path-to-node=\"5,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong><span class=\"\"> “…</span><span class=\"\">a packaged-goods product controller is </span><strong class=\"\" data-path-to-node=\"5,0,0\" data-index-in-node=\"54\">bombarded with one million to one billion new numbers</strong><span class=\"\"> each week.</span><span class=\"\"> …</span><span class=\"\">‘Running out of information is not a problem,</span><span class=\"\"> but </span><strong class=\"\" data-path-to-node=\"5,0,0\" data-index-in-node=\"172\">drowning in it</strong><span class=\"\"> is.</span><span class=\"\">‘”</span></p>\n</li>\n<li>\n<p data-path-to-node=\"5,1,0\"><strong class=\"\" data-path-to-node=\"5,1,0\" data-index-in-node=\"0\">Giải thích:</strong><span class=\"\"> Đoạn F mô tả tình trạng quá tải thông tin (too much information),</span><span class=\"\"> nơi người quản lý bị “tấn công” bởi hàng tỷ con số.</span></p>\n</li>\n</ul>\n<p data-path-to-node=\"6\"><strong class=\"\" data-path-to-node=\"6\" data-index-in-node=\"0\">28. The relevance of generating repeat business — {A}</strong></p>\n<ul data-path-to-node=\"7\">\n<li>\n<p data-path-to-node=\"7,0,0\"><strong class=\"\" data-path-to-node=\"7,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong><span class=\"\"> “…</span><span class=\"\">customers must see value in </span><strong class=\"\" data-path-to-node=\"7,0,0\" data-index-in-node=\"43\">returning continually to the stores</strong><span class=\"\"> where they shop…</span><span class=\"\">“</span></p>\n</li>\n<li>\n<p data-path-to-node=\"7,1,0\"><strong class=\"\" data-path-to-node=\"7,1,0\" data-index-in-node=\"0\">Giải thích:</strong><span class=\"\"> “Returning continually” (quay lại liên tục) chính là việc tạo ra các giao dịch lặp lại (repeat business),</span><span class=\"\"> thay vì chỉ bán được một lần duy nhất.</span></p>\n</li>\n</ul>\n<p data-path-to-node=\"8\"><strong class=\"\" data-path-to-node=\"8\" data-index-in-node=\"0\">29. An example of personalised marketing — {B}</strong></p>\n<ul data-path-to-node=\"9\">\n<li>\n<p data-path-to-node=\"9,0,0\"><strong class=\"\" data-path-to-node=\"9,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong><span class=\"\"> “…</span><span class=\"\">Channel [V] encourages its viewers to sign up for text messages and email alerts that tell them when </span><strong class=\"\" data-path-to-node=\"9,0,0\" data-index-in-node=\"116\">their favourite artists and songs</strong><span class=\"\"> are about to be broadcast.</span><span class=\"\">“</span></p>\n</li>\n<li>\n<p data-path-to-node=\"9,1,0\"><strong class=\"\" data-path-to-node=\"9,1,0\" data-index-in-node=\"0\">Giải thích:</strong><span class=\"\"> Đây là ví dụ về marketing cá nhân hóa (personalized),</span><span class=\"\"> dựa trên sở thích cụ thể của từng khách hàng để gửi thông báo.</span></p>\n</li>\n</ul>\n<p data-path-to-node=\"10\"><strong class=\"\" data-path-to-node=\"10\" data-index-in-node=\"0\">30. An illustration of a situation where commissioning new research might not be advisable — {H}</strong></p>\n<ul data-path-to-node=\"11\">\n<li>\n<p data-path-to-node=\"11,0,0\"><strong class=\"\" data-path-to-node=\"11,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong><span class=\"\"> “…</span><span class=\"\">it would be </span><strong class=\"\" data-path-to-node=\"11,0,0\" data-index-in-node=\"27\">foolish to spend $30,000</strong><span class=\"\"> for additional information that would increase the profit to only $525,</span><span class=\"\">000 [from $500,</span><span class=\"\">000].</span><span class=\"\">“</span></p>\n</li>\n<li>\n<p data-path-to-node=\"11,1,0\"><strong class=\"\" data-path-to-node=\"11,1,0\" data-index-in-node=\"0\">Giải thích:</strong><span class=\"\"> Đoạn H đưa ra ví dụ về chi phí nghiên cứu ($30k) cao hơn lợi nhuận tăng thêm ($25k),</span><span class=\"\"> do đó việc thực hiện nghiên cứu là không nên (not advisable).</span></p>\n</li>\n</ul>\n<p data-path-to-node=\"12\"><strong class=\"\" data-path-to-node=\"12\" data-index-in-node=\"0\">31. How the greater wealth of customers enables them to select from a broader range — {D}</strong></p>\n<ul data-path-to-node=\"13\">\n<li>\n<p data-path-to-node=\"13,0,0\"><strong class=\"\" data-path-to-node=\"13,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong><span class=\"\"> “As </span><strong class=\"\" data-path-to-node=\"13,0,0\" data-index-in-node=\"15\">household incomes increase</strong><span class=\"\">,</span> <strong class=\"\" data-path-to-node=\"13,0,0\" data-index-in-node=\"43\">choice widens</strong><span class=\"\"> and buyers become better at discriminating…</span><span class=\"\">“</span></p>\n</li>\n<li>\n<p data-path-to-node=\"13,1,0\"><strong data-path-to-node=\"13,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Thu nhập hộ gia đình tăng (greater wealth) dẫn đến sự lựa chọn mở rộng (broader range/choice widens).</p>\n</li>\n</ul>"}]', 0);
INSERT INTO public.questions VALUES ('25a8caca-c4ce-4c63-8561-99c98f23f646', '78627bc8-8d64-4564-bdc7-ef39933d398f', 'radio', 'Questions 32–36', '', '<p id="p-rc_c04c5eb7f956289a-175" data-path-to-node="13,0,0"><span class="citation-8676">Choose </span><strong data-path-to-node="13,0,0" data-index-in-node="0"><span class="citation-8676">YES</span></strong><span class="citation-8676 citation-end-8676"> if the statement agrees with the claims of the writer,</span><strong data-path-to-node="13,1,0" data-index-in-node="0"><span class="citation-8675">NO</span></strong><span class="citation-8675 citation-end-8675"> if the statement contradic</span>ts the claims of the writer,<strong data-path-to-node="13,2,0" data-index-in-node="0">NOT GIVEN</strong> if it is impossible to say what the writer thinks about this</p>', 'yes_no_not_given', '[{"correct": 1, "options": [{"option_text": "YES"}, {"option_text": "NO"}, {"option_text": "NOT GIVEN"}], "question": "The majority of marketing statistics are gathered by government agencies."}, {"correct": 2, "options": [{"option_text": "YES"}, {"option_text": "NO"}, {"option_text": "NOT GIVEN"}], "question": "The move from an industrial to an information-based economy has happened more quickly in New Zealand than in Australia."}, {"correct": 0, "options": [{"option_text": "YES"}, {"option_text": "NO"}, {"option_text": "NOT GIVEN"}], "question": "Employees sometimes hide information that gives a poor impression of them."}, {"correct": 0, "options": [{"option_text": "YES"}, {"option_text": "NO"}, {"option_text": "NOT GIVEN"}], "question": "Managers frequently fail to make good use of the information they receive."}, {"correct": 0, "options": [{"option_text": "YES"}, {"option_text": "NO"}, {"option_text": "NOT GIVEN"}], "question": "Marketing information has to be used to be valuable."}]', 'null', 'null', 'null', '[{"content": "<p data-path-to-node=\"16\"><strong data-path-to-node=\"16\" data-index-in-node=\"0\">32. The majority of marketing statistics are gathered by government agencies. — {NO}</strong></p>\n<ul data-path-to-node=\"17\">\n<li>\n<p data-path-to-node=\"17,0,0\"><strong data-path-to-node=\"17,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “While some of the information… is gathered by government bodies… <strong data-path-to-node=\"17,0,0\" data-index-in-node=\"81\">most of it is purposefully gathered by marketing organisations</strong>…” (Đoạn C)</p>\n</li>\n<li>\n<p data-path-to-node=\"17,1,0\"><strong data-path-to-node=\"17,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Bài đọc nói “phần lớn” (most) do các tổ chức marketing thu thập, không phải do cơ quan chính phủ.</p>\n</li>\n</ul>\n<p data-path-to-node=\"18\"><strong data-path-to-node=\"18\" data-index-in-node=\"0\">33. The move to an information economy happened more quickly in NZ than in Australia. — {NOT GIVEN}</strong></p>\n<ul data-path-to-node=\"19\">\n<li>\n<p data-path-to-node=\"19,0,0\"><strong data-path-to-node=\"19,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “the United States and, by observation, developed countries such as <strong data-path-to-node=\"19,0,0\" data-index-in-node=\"79\">Australia, New Zealand and Singapore</strong> are moving from industrial to information-based economies.” (Đoạn E)</p>\n</li>\n<li>\n<p data-path-to-node=\"19,1,0\"><strong data-path-to-node=\"19,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Bài đọc liệt kê cả hai nước đang chuyển đổi, nhưng <strong data-path-to-node=\"19,1,0\" data-index-in-node=\"63\">không có sự so sánh</strong> nào về tốc độ nhanh hay chậm giữa chúng.</p>\n</li>\n</ul>\n<p data-path-to-node=\"20\"><strong data-path-to-node=\"20\" data-index-in-node=\"0\">34. Employees sometimes hide information that gives a poor impression of them. — {YES}</strong></p>\n<ul data-path-to-node=\"21\">\n<li>\n<p data-path-to-node=\"21,0,0\"><strong data-path-to-node=\"21,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “…subordinates may <strong data-path-to-node=\"21,0,0\" data-index-in-node=\"32\">withhold information</strong> they believe will <strong data-path-to-node=\"21,0,0\" data-index-in-node=\"71\">reflect badly on their performance</strong>…” (Đoạn F)</p>\n</li>\n<li>\n<p data-path-to-node=\"21,1,0\"><strong data-path-to-node=\"21,1,0\" data-index-in-node=\"0\">Giải thích:</strong> “Subordinates” (cấp dưới/nhân viên) giấu thông tin ảnh hưởng xấu đến thành tích của họ.</p>\n</li>\n</ul>\n<p data-path-to-node=\"22\"><strong data-path-to-node=\"22\" data-index-in-node=\"0\">35. Managers frequently fail to make good use of the information they receive. — {YES}</strong></p>\n<ul data-path-to-node=\"23\">\n<li>\n<p data-path-to-node=\"23,0,0\"><strong data-path-to-node=\"23,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “Although marketing organisations have greater capacity… they <strong data-path-to-node=\"23,0,0\" data-index-in-node=\"75\">often do not use it well</strong>.” (Đoạn F)</p>\n</li>\n<li>\n<p data-path-to-node=\"23,1,0\"><strong data-path-to-node=\"23,1,0\" data-index-in-node=\"0\">Giải thích:</strong> “Often do not use it well” khớp với “frequently fail to make good use”.</p>\n</li>\n</ul>\n<p data-path-to-node=\"24\"><strong data-path-to-node=\"24\" data-index-in-node=\"0\">36. Marketing information has to be used to be valuable. — {YES}</strong></p>\n<ul data-path-to-node=\"25\">\n<li>\n<p data-path-to-node=\"25,0,0\"><strong data-path-to-node=\"25,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “By itself, information is valueless – <strong data-path-to-node=\"25,0,0\" data-index-in-node=\"50\">its value comes from its use</strong>.” (Đoạn H)</p>\n</li>\n<li>\n<p data-path-to-node=\"25,1,0\"><strong data-path-to-node=\"25,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Thông tin chỉ có giá trị khi được sử dụng.</p>\n</li>\n</ul>"}]', 1);
INSERT INTO public.questions VALUES ('8da477ec-54eb-468a-bb0f-677174302627', '929cd6dc-04b3-4d88-9449-80b14b938201', 'checkbox', 'Questions 27 and 28', '', '<p data-start="1293" data-end="1321">Choose <strong>TWO </strong>letters, <strong>A</strong>–<strong>E</strong>.</p>
<p data-start="1323" data-end="1391">Which <strong>TWO </strong>additions will Terence make to the section on history?</p>', 'multiple_choice', 'null', '[{"correct": false, "option_text": "A. data about the kings in the Ife area"}, {"correct": true, "option_text": "B. extra information about the surrounding region"}, {"correct": true, "option_text": "C. examination of the beliefs of the Ife people"}, {"correct": false, "option_text": "D. an explanation of the development of modern Ife"}, {"correct": false, "option_text": "E. more details of past activities of the Ife people"}]', 'null', 'null', 'null', 2);
INSERT INTO public.questions VALUES ('06b7caa2-2812-400a-ab2c-ce1a42863975', '929cd6dc-04b3-4d88-9449-80b14b938201', 'checkbox', 'Questions 29 and 30', '', '<p data-start="1712" data-end="1740">Choose <strong>TWO </strong>letters, <strong>A</strong>–<strong>E</strong>.</p>
<p data-start="1742" data-end="1833">Which <strong>TWO </strong>features of his research in Nigeria will Terence discuss in his presentation?</p>', 'multiple_choice', 'null', '[{"correct": false, "option_text": "A. the influence of the sculptures on Western artists"}, {"correct": true, "option_text": "B. the uncertainty over who made the sculptures"}, {"correct": false, "option_text": "C. the sources of the materials used for the sculptures"}, {"correct": false, "option_text": "D. the problems he faced in collecting information"}, {"correct": true, "option_text": "E. the original discovery of the sculptures"}]', 'null', 'null', 'null', 3);
INSERT INTO public.questions VALUES ('8e9d0755-eccd-4675-abad-1753d8de0d6e', '55211eed-bbd5-4477-8e33-9bf11ef08a8b', 'radio', 'Questions 27 – 30', '', '<p><em data-path-to-node="2" data-index-in-node="0">Choose the correct letter, <strong data-path-to-node="2" data-index-in-node="27">A, B, C</strong> or <strong data-path-to-node="2" data-index-in-node="38">D</strong>.</em></p>', 'multiple_choice', '[{"correct": 1, "options": [{"option_text": "fear and stress are different feelings."}, {"option_text": "most humans develop strategies for dealing with fear."}, {"option_text": "business situations cause more fear than others."}, {"option_text": "some people never experience fear."}], "question": " In the first paragraph, the writer points out that"}, {"correct": 2, "options": [{"option_text": "they react more quickly to fear than humans."}, {"option_text": "they are more influenced by fear than humans."}, {"option_text": "their mental growth resembles that of humans."}, {"option_text": "their brains work more slowly than those of humans."}], "question": "When discussing the use of rhesus monkeys as experimental subjects, the writer notes that"}, {"correct": 3, "options": [{"option_text": "the identification of expressions of anxiety in monkeys"}, {"option_text": "the identification of situations that arouse stress in monkeys"}, {"option_text": "an analysis of brain development in monkeys"}, {"option_text": "the study of reactions to fear in monkeys of different ages"}], "question": "Which of the following did Kalin and Shelton outline as the second stage in their research project?"}, {"correct": 0, "options": [{"option_text": "reflect common experiences for infant humans and monkeys."}, {"option_text": "highlight the similarities between monkey and human infant care."}, {"option_text": "were predicted to cause monkeys more distress than human infants."}, {"option_text": "were graded in terms of their potential effect on young monkeys."}], "question": "In the fourth paragraph, the writer notes that the three related situations"}]', 'null', 'null', 'null', '[{"content": "<p data-path-to-node=\"3\"><strong data-path-to-node=\"3\" data-index-in-node=\"0\">27. In the first paragraph, the writer points out that — {B} most humans develop strategies for dealing with fear.</strong></p>\n<ul data-path-to-node=\"4\">\n<li>\n<p data-path-to-node=\"4,0,0\"><strong data-path-to-node=\"4,0,0\" data-index-in-node=\"0\">Trích dẫn:</strong> “Over the years, the majority of people acquire a <strong data-path-to-node=\"4,0,0\" data-index-in-node=\"61\">range of skills for coping with frightening situations</strong>.” (Đoạn 1)</p>\n</li>\n<li>\n<p data-path-to-node=\"4,1,0\"><strong data-path-to-node=\"4,1,0\" data-index-in-node=\"0\">Giải thích:</strong> “Acquire a range of skills for coping with” tương ứng với “develop strategies for dealing with”.</p>\n</li>\n</ul>\n<p data-path-to-node=\"5\"><strong data-path-to-node=\"5\" data-index-in-node=\"0\">28. When discussing the use of rhesus monkeys… — {C} their mental growth resembles that of humans.</strong></p>\n<ul data-path-to-node=\"6\">\n<li>\n<p data-path-to-node=\"6,0,0\"><strong data-path-to-node=\"6,0,0\" data-index-in-node=\"0\">Trích dẫn:</strong> “These animals undergo many of the <strong data-path-to-node=\"6,0,0\" data-index-in-node=\"46\">same physiological and psychological developmental stages</strong> that humans do…” (Đoạn 2)</p>\n</li>\n<li>\n<p data-path-to-node=\"6,1,0\"><strong data-path-to-node=\"6,1,0\" data-index-in-node=\"0\">Giải thích:</strong> “Psychological developmental stages” chính là sự phát triển về tâm thần/trí tuệ (<em data-path-to-node=\"6,1,0\" data-index-in-node=\"93\">mental growth</em>).</p>\n</li>\n</ul>\n<p data-path-to-node=\"7\"><strong data-path-to-node=\"7\" data-index-in-node=\"0\">29. Which of the following did Kalin and Shelton outline as the second stage…? — {D} the study of reactions to fear in monkeys of different ages.</strong></p>\n<ul data-path-to-node=\"8\">\n<li>\n<p data-path-to-node=\"8,0,0\"><strong data-path-to-node=\"8,0,0\" data-index-in-node=\"0\">Trích dẫn:</strong> “…they could then proceed to <strong data-path-to-node=\"8,0,0\" data-index-in-node=\"42\">determine the age</strong> at which monkeys begin to match defensive behaviors selectively to specific cues.” (Đoạn 3)</p>\n</li>\n<li>\n<p data-path-to-node=\"8,1,0\"><strong data-path-to-node=\"8,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Bước thứ hai là xác định độ tuổi mà khỉ bắt đầu có phản ứng phòng vệ có chọn lọc.</p>\n</li>\n</ul>\n<p data-path-to-node=\"9\"><strong data-path-to-node=\"9\" data-index-in-node=\"0\">30. In the fourth paragraph, the writer notes that the three related situations — {A} reflect common experiences for infant humans and monkeys.</strong></p>\n<ul data-path-to-node=\"10\">\n<li>\n<p data-path-to-node=\"10,0,0\"><strong data-path-to-node=\"10,0,0\" data-index-in-node=\"0\">Trích dẫn:</strong> “These positions are <strong data-path-to-node=\"10,0,0\" data-index-in-node=\"32\">no more frightening than those that primates encounter frequently in the wild, or those that human infants meet</strong> whenever they are left at a day-care centre.” (Đoạn 4)</p>\n</li>\n<li>\n<p data-path-to-node=\"10,1,0\"><strong data-path-to-node=\"10,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Tác giả so sánh 3 tình huống thí nghiệm với những trải nghiệm đời thường của khỉ ngoài tự nhiên và trẻ em ở nhà trẻ.</p>\n</li>\n</ul>"}]', 0);
INSERT INTO public.questions VALUES ('5243ea16-787c-4567-a355-856d3469f173', '55211eed-bbd5-4477-8e33-9bf11ef08a8b', 'matrix', 'Questions 31 – 35', '', '<p>Look at the following responses of monkeys and the list of conditions below.</p>
<p>Match each response with the correct condition, <strong data-path-to-node="13" data-index-in-node="125">A, B</strong> or <strong data-path-to-node="13" data-index-in-node="133">C</strong>.</p>', 'choose_a_title', 'null', 'null', 'null', '{"layoutType": "standard", "matrixItems": [{"itemText": "Aggressive facial expressions", "correctCategoryLetter": "C"}, {"itemText": "prolonged stillness", "correctCategoryLetter": "B"}, {"itemText": "a combination of contradictory signals", "correctCategoryLetter": "C"}, {"itemText": "appeals for maternal protection", "correctCategoryLetter": "A"}, {"itemText": "the production of soft sounds", "correctCategoryLetter": "A"}], "matrixCategories": [{"categoryText": "the alone condition", "categoryLetter": "A"}, {"categoryText": "the no-eye-contact condition", "categoryLetter": "B"}, {"categoryText": "the stare condition", "categoryLetter": "C"}]}', '[{"content": "<p data-path-to-node=\"13\"><strong data-path-to-node=\"13\" data-index-in-node=\"0\">31. Aggressive facial expressions — {C: The stare condition}</strong></p>\n<ul data-path-to-node=\"14\">\n<li>\n<p data-path-to-node=\"14,0,0\"><strong data-path-to-node=\"14,0,0\" data-index-in-node=\"0\">Trích dẫn:</strong> “The monkeys made several <strong data-path-to-node=\"14,0,0\" data-index-in-node=\"37\">hostile gestures</strong>: barking… and <strong data-path-to-node=\"14,0,0\" data-index-in-node=\"70\">staring back</strong>.” (Đoạn 5)</p>\n</li>\n<li>\n<p data-path-to-node=\"14,1,0\"><strong data-path-to-node=\"14,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Hành động nhìn chằm chằm lại và sủa là biểu cảm hung dữ/tấn công.</p>\n</li>\n</ul>\n<p data-path-to-node=\"15\"><strong data-path-to-node=\"15\" data-index-in-node=\"0\">32. Prolonged stillness — {B: The no-eye-contact condition}</strong></p>\n<ul data-path-to-node=\"16\">\n<li>\n<p data-path-to-node=\"16,0,0\"><strong data-path-to-node=\"16,0,0\" data-index-in-node=\"0\">Trích dẫn:</strong> “…the monkeys reduced their activity greatly and sometimes <strong data-path-to-node=\"16,0,0\" data-index-in-node=\"72\">froze for extended periods of time</strong>.” (Đoạn 5)</p>\n</li>\n<li>\n<p data-path-to-node=\"16,1,0\"><strong data-path-to-node=\"16,1,0\" data-index-in-node=\"0\">Giải thích:</strong> “Froze” (đứng hình/đông cứng) tương ứng với “stillness”.</p>\n</li>\n</ul>\n<p data-path-to-node=\"17\"><strong data-path-to-node=\"17\" data-index-in-node=\"0\">33. A combination of contradictory signals — {C: The stare condition}</strong></p>\n<ul data-path-to-node=\"18\">\n<li>\n<p data-path-to-node=\"18,0,0\"><strong data-path-to-node=\"18,0,0\" data-index-in-node=\"0\">Trích dẫn:</strong> “Sometimes the animals <strong data-path-to-node=\"18,0,0\" data-index-in-node=\"34\">mixed the threatening displays with submissive ones</strong>…” (Đoạn 5)</p>\n</li>\n<li>\n<p data-path-to-node=\"18,1,0\"><strong data-path-to-node=\"18,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Việc kết hợp giữa đe dọa (<em data-path-to-node=\"18,1,0\" data-index-in-node=\"38\">threatening</em>) và phục tùng (<em data-path-to-node=\"18,1,0\" data-index-in-node=\"65\">submissive</em>) chính là các tín hiệu mâu thuẫn/trái ngược nhau.</p>\n</li>\n</ul>\n<p data-path-to-node=\"19\"><strong data-path-to-node=\"19\" data-index-in-node=\"0\">34. Appeals for maternal protection — {A: The alone condition}</strong></p>\n<ul data-path-to-node=\"20\">\n<li>\n<p data-path-to-node=\"20,0,0\"><strong data-path-to-node=\"20,0,0\" data-index-in-node=\"0\">Trích dẫn:</strong> “…it <strong data-path-to-node=\"20,0,0\" data-index-in-node=\"18\">yearns to regain the closeness and security</strong> provided by nearness to the parent. These responses help to <strong data-path-to-node=\"20,0,0\" data-index-in-node=\"122\">draw the mother’s attention</strong>.” (Đoạn 5)</p>\n</li>\n</ul>\n<p data-path-to-node=\"21\"><strong data-path-to-node=\"21\" data-index-in-node=\"0\">35. The production of soft sounds — {A: The alone condition}</strong></p>\n<ul data-path-to-node=\"22\">\n<li>\n<p data-path-to-node=\"22,0,0\"><strong data-path-to-node=\"22,0,0\" data-index-in-node=\"0\">Trích dẫn:</strong> “…emitted frequent <strong data-path-to-node=\"22,0,0\" data-index-in-node=\"32\">gentle “coo” calls</strong>…” (Đoạn 5)</p>\n</li>\n<li>\n<p data-path-to-node=\"22,1,0\"><strong data-path-to-node=\"22,1,0\" data-index-in-node=\"0\">Giải thích:</strong> “Gentle calls” tương ứng với “soft sounds”.</p>\n</li>\n</ul>"}]', 1);
INSERT INTO public.questions VALUES ('ae3228d5-9ec1-40d3-b2e8-63372b69ba0d', '55211eed-bbd5-4477-8e33-9bf11ef08a8b', 'fillup', 'Questions 36 – 40', '<p data-path-to-node="19">Choose<strong> NO MORE THAN THREE WORDS AND / OR A NUMBER </strong>from the passage for each answer.</p>
<p data-path-to-node="19">Once they had identified three types of defensive behaviour, Kalin and Shelton grouped the monkeys according to their {age}, in order to discover precisely when they were able to respond appropriately to different fear-related cues. They videotaped their results and found that monkeys as young as {two weeks old}<span class="citation-623"> reacted to the cues but in a haphazard fashion. The researchers noted that they seemed to be unaware of the {human beings}</span><span class="citation-623"> who were around them. Despite demonstrating {good motor control}</span><span class="citation-623 citation-end-623">, the monkeys in the middle groups fai</span>led to react in ways corresponding to the experimental situation. The oldest group, however, reacted in the same way as {mature monkeys} and the researchers concluded that monkeys are capable of selective responding between nine and 12 weeks old.</p>', NULL, 'summary_completion', 'null', 'null', 'null', 'null', '[{"content": "<p data-path-to-node=\"25\"><strong data-path-to-node=\"25\" data-index-in-node=\"0\">36. …grouped the monkeys according to their {age}…</strong></p>\n<ul data-path-to-node=\"26\">\n<li>\n<p data-path-to-node=\"26,0,0\"><strong data-path-to-node=\"26,0,0\" data-index-in-node=\"0\">Trích dẫn:</strong> “…they examined four groups of infant monkeys <strong data-path-to-node=\"26,0,0\" data-index-in-node=\"59\">ranging in age</strong> up to 12 weeks old.” (Đoạn 6)</p>\n</li>\n</ul>\n<p data-path-to-node=\"27\"><strong data-path-to-node=\"27\" data-index-in-node=\"0\">37. …monkeys as young as {two weeks old} reacted to the cues…</strong></p>\n<ul data-path-to-node=\"28\">\n<li>\n<p data-path-to-node=\"28,0,0\"><strong data-path-to-node=\"28,0,0\" data-index-in-node=\"0\">Trích dẫn:</strong> “They found that the infants in the youngest group (<strong data-path-to-node=\"28,0,0\" data-index-in-node=\"63\">no more than two weeks old</strong>) engaged in defensive behaviours…” (Đoạn 6)</p>\n</li>\n</ul>\n<p data-path-to-node=\"29\"><strong data-path-to-node=\"29\" data-index-in-node=\"0\">38. …they seemed to be unaware of the {human beings} who were around them.</strong></p>\n<ul data-path-to-node=\"30\">\n<li>\n<p data-path-to-node=\"30,0,0\"><strong data-path-to-node=\"30,0,0\" data-index-in-node=\"0\">Trích dẫn:</strong> “…as if they had not noticed the <strong data-path-to-node=\"30,0,0\" data-index-in-node=\"46\">human beings</strong> that were present.” (Đoạn 6)</p>\n</li>\n<li>\n<p data-path-to-node=\"30,1,0\"><strong data-path-to-node=\"30,1,0\" data-index-in-node=\"0\">Giải thích:</strong> “Had not noticed” tương ứng với “unaware of”.</p>\n</li>\n</ul>\n<p data-path-to-node=\"31\"><strong data-path-to-node=\"31\" data-index-in-node=\"0\">39. Despite demonstrating {good motor control}…</strong></p>\n<ul data-path-to-node=\"32\">\n<li>\n<p data-path-to-node=\"32,0,0\"><strong data-path-to-node=\"32,0,0\" data-index-in-node=\"0\">Trích dẫn:</strong> “Babies in the two intermediate-age groups had <strong data-path-to-node=\"32,0,0\" data-index-in-node=\"58\">good motor control</strong>…” (Đoạn 6)</p>\n</li>\n</ul>\n<p data-path-to-node=\"33\"><strong data-path-to-node=\"33\" data-index-in-node=\"0\">40. …reacted in the same way as {mature monkeys}…</strong></p>\n<ul data-path-to-node=\"34\">\n<li>\n<p data-path-to-node=\"34,0,0\"><strong data-path-to-node=\"34,0,0\" data-index-in-node=\"0\">Trích dẫn:</strong> “…their reactions were both appropriate and identical to those of <strong data-path-to-node=\"34,0,0\" data-index-in-node=\"79\">mature monkeys</strong>.” (Đoạn 6)</p>\n</li>\n</ul>"}]', 2);
INSERT INTO public.questions VALUES ('c38b13c8-7cf4-482d-83ba-e423ab8d4d39', '993f24cf-058f-41b3-ba6e-d8e7174171d3', 'fillup', 'Questions 8–13', '<p><strong>Complete the notes below.</strong></p>
<p>Write <strong>NO MORE THAN TWO WORDS </strong>from the passage for each answer.</p>
<p><span style="font-size: 12pt;"><strong>American Southwest: 1860s to present day</strong></span></p>
<p>1862 – American Homestead Act was passed to encourage settlement in the West.</p>
<p>1930s – Laws were passed to control the size of {cattle herds}</p>
<p>Today Jayne Belnap believes:</p>
<p>○     soil was not affected by high {winds}</p>
<p>○     soil was seriously affected by cattle hooves.</p>
<p>Jason Neff:</p>
<p>○     found that {lake sediments}in the Colorado region contained dust</p>
<p>○     examined the dust for its chemical content as well as its {size}</p>
<p>○     concluded that the dust was from the American Southwest</p>
<p>○     found that dust affects mountain environments by</p>
<p>bringing in {nutrients} that are not normally found there</p>
<p>causing faster seasonal snowmelt</p>
<p>○     argues that dust is partly to blame for the gradual disappearance of some {glaciers} and snow.</p>
', NULL, 'gap_filling', 'null', 'null', 'null', 'null', '[{"content": "<h3>8.</h3>\n<ul>\n<li><strong>Đáp án: cattle herds</strong></li>\n<li><strong>Dẫn chứng:</strong> (Đoạn F) “…It was only in the 1930s, with the passage of the Taylor Grazing Act, that federal authorities finally sought to limit <strong>cattle herds</strong>.”</li>\n</ul>\n<h3>9.</h3>\n<ul>\n<li><strong>Đáp án: winds</strong></li>\n<li><strong>Dẫn chứng:</strong> (Đoạn G) “These crusts can survive <strong>winds</strong> of up to a hundred miles an hour…”</li>\n<li><strong>Giải thích:</strong> Jayne Belnap nói rằng lớp vỏ cứng của đất có thể chịu được gió rất mạnh (“up to a hundred miles an hour”), ngụ ý rằng đất không dễ bị ảnh hưởng bởi gió (high winds) nếu lớp vỏ này còn nguyên vẹn.</li>\n</ul>\n<h3>10.</h3>\n<ul>\n<li><strong>Đáp án: lake sediments</strong></li>\n<li><strong>Dẫn chứng:</strong> (Đoạn G) “When Neff first discovered dust in Colorado <strong>lake sediments</strong> laid down in the 19th century…”</li>\n</ul>\n<h3>11.</h3>\n<ul>\n<li><strong>Đáp án: size</strong></li>\n<li><strong>Dẫn chứng:</strong> (Đoạn H) “But after investigating the <strong>size</strong> and chemical composition of the dust, Neff was clear…”</li>\n</ul>\n<h3>12.</h3>\n<ul>\n<li><strong>Đáp án: nutrients</strong></li>\n<li><strong>Dẫn chứng:</strong> (Đoạn H) “They carry <strong>nutrients</strong> with them into areas which previously evolved and survived without them.”</li>\n</ul>\n<h3>13.</h3>\n<ul>\n<li><strong>Đáp án: glaciers</strong></li>\n<li><strong>Dẫn chứng:</strong> (Đoạn I) “The loss of snow and the shrinking of <strong>glaciers</strong> across the American West in the past century has been dramatic.” (Glaciers là danh từ được nhắc đến trước “and snow” trong đoạn cuối.)</li>\n</ul>\n"}]', 1);
INSERT INTO public.questions VALUES ('a249dd8d-324a-4b76-ba32-c76c3d11d332', 'a29854fb-7043-4f77-8cf0-3d9f433dd4e5', 'fillup', 'Questions 1-10', '<p>Write <strong>ONE WORD AND/OR A NUMBER</strong> for each answer.</p>
<table style="border-collapse: collapse; width: 99.9592%; border-spacing: 2px; border: 1px solid #000000;" border="1"><colgroup><col style="width: 99.8776%;"></colgroup>
<tbody>
<tr>
<td style="padding: 2px; border-color: #000000;">
<p data-path-to-node="2"><span style="font-size: 14pt;"><strong data-path-to-node="2" data-index-in-node="0">Film Club</strong></span></p>
<p data-path-to-node="3"><strong data-path-to-node="3" data-index-in-node="0">Membership information</strong></p>
<p data-path-to-node="4">Club meets every 2 weeks</p>
<p data-path-to-node="5">No {age} limit</p>
<p data-path-to-node="6">Student membership costs £{21.50} per season</p>
<p data-path-to-node="7">Members get:</p>
<ul data-path-to-node="8">
<li>
<p data-path-to-node="8,0,0">free entry to club films</p>
</li>
<li>
<p data-path-to-node="8,1,0">£{2} reduction on other films at cinema</p>
</li>
</ul>
<p data-path-to-node="9">Members are entitled to 3 hours'' free {parking}</p>
<p data-path-to-node="10"><strong data-path-to-node="10" data-index-in-node="0">Films to be shown:</strong></p>
<p data-path-to-node="11"><strong data-path-to-node="11" data-index-in-node="0">Oct 14: <em data-path-to-node="11" data-index-in-node="8">Pablo</em></strong></p>
<ul data-path-to-node="12">
<li>
<p data-path-to-node="12,0,0">about a child in {Argentina} who runs away from home and wins a {singing} competition on TV</p>
</li>
</ul>
<p data-path-to-node="13"><strong data-path-to-node="13" data-index-in-node="0">Oct 28: <em data-path-to-node="13" data-index-in-node="8">The Soldier</em></strong></p>
<ul data-path-to-node="14">
<li>
<p data-path-to-node="14,0,0">with live {piano} accompaniment</p>
</li>
<li>
<p data-path-to-node="14,1,0">made in the year {1922}</p>
</li>
<li>
<p data-path-to-node="14,2,0">type of film: a {comedy}</p>
</li>
</ul>
<p data-path-to-node="15"><strong data-path-to-node="15" data-index-in-node="0">Nov 11: <em data-path-to-node="15" data-index-in-node="8">Tiger</em></strong></p>
<ul data-path-to-node="16">
<li>
<p data-path-to-node="16,0,0">cartoon aimed at adults</p>
</li>
<li>
<p data-path-to-node="16,1,0">followed by a {talk}<strong> </strong>by the director</p>
</li>
</ul>
</td>
</tr>
</tbody>
</table>
<p> </p>', NULL, 'summary_completion', 'null', 'null', 'null', 'null', 'null', 0);
INSERT INTO public.questions VALUES ('9217079a-16e0-48fd-8778-dac553eb519f', '5f6e998c-dd8c-403f-bacb-8db12bae449d', 'radio', 'Questions 1-5', '', '<p>Choose<strong> TRUE</strong> if the statement agrees with the information,<strong>FALSE</strong> if the statement contradicts the information,<strong>NOT GIVEN</strong> there is no information on this</p>', 'true_false_not_given', '[{"correct": 0, "options": [{"option_text": "TRUE"}, {"option_text": "FALSE"}, {"option_text": "NOT GIVEN"}], "question": "The Burgess Shale became widely known to the public because of Gould’s book."}, {"correct": 2, "options": [{"option_text": "TRUE"}, {"option_text": "FALSE"}, {"option_text": "NOT GIVEN"}], "question": "Charles Walcott had to get permission from Canadian authorities to gain access to the fossil site."}, {"correct": 0, "options": [{"option_text": "TRUE"}, {"option_text": "FALSE"}, {"option_text": "NOT GIVEN"}], "question": "The Burgess Shale includes impressions of soft and hard body parts."}, {"correct": 1, "options": [{"option_text": "TRUE"}, {"option_text": "FALSE"}, {"option_text": "NOT GIVEN"}], "question": "The Burgess Shale creatures were land animals."}, {"correct": 1, "options": [{"option_text": "TRUE"}, {"option_text": "FALSE"}, {"option_text": "NOT GIVEN"}], "question": "Researchers now believe that Hallucigenia is unrelated to any modern creature."}]', 'null', 'null', 'null', '[{"content": "<p data-path-to-node=\"7\"><strong data-path-to-node=\"7\" data-index-in-node=\"0\">1. The Burgess Shale became widely known to the public because of Gould’s book. — {TRUE}</strong></p>\n<ul data-path-to-node=\"8\">\n<li>\n<p data-path-to-node=\"8,0,0\"><strong data-path-to-node=\"8,0,0\" data-index-in-node=\"0\">Dẫn chứng (Đoạn 1):</strong> <em data-path-to-node=\"8,0,0\" data-index-in-node=\"20\">“…and was <strong data-path-to-node=\"8,0,0\" data-index-in-node=\"32\">popularised</strong> in 1989 in a <strong data-path-to-node=\"8,0,0\" data-index-in-node=\"57\">book, Wonderful Life, by Stephen Jay Gould</strong>…”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"8,1,0\"><strong data-path-to-node=\"8,1,0\" data-index-in-node=\"0\">Giải thích:</strong> “Popularised” (trở nên phổ biến/được nhiều người biết đến) khớp hoàn toàn với cụm “widely known to the public”. Cuốn sách của Gould chính là lý do khiến nó nổi tiếng.</p>\n</li>\n</ul>\n<p data-path-to-node=\"9\"><strong data-path-to-node=\"9\" data-index-in-node=\"0\">2. Charles Walcott had to get permission from Canadian authorities to gain access to the fossil site. — {NOT GIVEN}</strong></p>\n<ul data-path-to-node=\"10\">\n<li>\n<p data-path-to-node=\"10,0,0\"><strong data-path-to-node=\"10,0,0\" data-index-in-node=\"0\">Dẫn chứng (Đoạn 2):</strong> Chỉ nói Walcott đi theo báo cáo của công nhân đường sắt và “vấp phải” (tripped over) khối đá phiến chứa hóa thạch.</p>\n</li>\n<li>\n<p data-path-to-node=\"10,1,0\"><strong data-path-to-node=\"10,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Bài đọc <strong data-path-to-node=\"10,1,0\" data-index-in-node=\"20\">không hề nhắc đến</strong> việc ông có phải xin phép (permission) chính quyền Canada hay không.</p>\n</li>\n</ul>\n<p data-path-to-node=\"11\"><strong data-path-to-node=\"11\" data-index-in-node=\"0\">3. The Burgess Shale includes impressions of soft and hard body parts. — {TRUE}</strong></p>\n<ul data-path-to-node=\"12\">\n<li>\n<p data-path-to-node=\"12,0,0\"><strong data-path-to-node=\"12,0,0\" data-index-in-node=\"0\">Dẫn chứng (Đoạn 3):</strong> <em data-path-to-node=\"12,0,0\" data-index-in-node=\"20\">“An unusual feature of the Burgess Shale is that it… contain impressions of the <strong data-path-to-node=\"12,0,0\" data-index-in-node=\"102\">soft body parts alongside the remains of bones and shells</strong> [hard parts]…”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"12,1,0\"><strong data-path-to-node=\"12,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Bài viết khẳng định hóa thạch ở đây chứa cả dấu vết phần mềm lẫn xương và vỏ (phần cứng).</p>\n</li>\n</ul>\n<p data-path-to-node=\"13\"><strong data-path-to-node=\"13\" data-index-in-node=\"0\">4. The Burgess Shale creatures were land animals. — {FALSE}</strong></p>\n<ul data-path-to-node=\"14\">\n<li>\n<p data-path-to-node=\"14,0,0\"><strong data-path-to-node=\"14,0,0\" data-index-in-node=\"0\">Dẫn chứng (Đoạn 2 &amp; 4):</strong> <em data-path-to-node=\"14,0,0\" data-index-in-node=\"24\">“…when an entire <strong data-path-to-node=\"14,0,0\" data-index-in-node=\"43\">marine ecosystem</strong> was buried in mud…”</em> và <em data-path-to-node=\"14,0,0\" data-index-in-node=\"85\">“Although the fossil bed was discovered on a mountain, these <strong data-path-to-node=\"14,0,0\" data-index-in-node=\"146\">animals originally existed below an ocean</strong>…”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"14,1,0\"><strong data-path-to-node=\"14,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Bài đọc khẳng định đây là hệ sinh thái biển (marine) và các sinh vật sống dưới đại dương (below an ocean), chứ không phải động vật trên cạn (land animals).</p>\n</li>\n</ul>\n<p data-path-to-node=\"15\"><strong data-path-to-node=\"15\" data-index-in-node=\"0\">5. Researchers now believe that Hallucigenia is unrelated to any modern creature. — {FALSE}</strong></p>\n<ul data-path-to-node=\"16\">\n<li>\n<p data-path-to-node=\"16,0,0\"><strong data-path-to-node=\"16,0,0\" data-index-in-node=\"0\">Dẫn chứng (Đoạn 7):</strong> <em data-path-to-node=\"16,0,0\" data-index-in-node=\"20\">“It [Hallucigenia] is now thought to be an <strong data-path-to-node=\"16,0,0\" data-index-in-node=\"63\">ancestor of the modern group of arthropods</strong>, which includes everything from flies and butterflies to centipedes and crabs.”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"16,1,0\"><strong data-path-to-node=\"16,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Trái với câu hỏi nói là “không liên quan” (unrelated), các nhà nghiên cứu hiện nay tin rằng nó là <strong data-path-to-node=\"16,1,0\" data-index-in-node=\"110\">tổ tiên</strong> (ancestor) của các loài chân đốt hiện đại (ruồi, bướm, cua…).</p>\n</li>\n</ul>"}]', 0);
INSERT INTO public.questions VALUES ('df9a9e53-ca1a-42e3-bef4-5599ea940427', '7e23f2bf-3fdd-43ff-8618-7880c74514d0', 'matching', 'Questions 14-20', NULL, '<p>Reading Passage 2 has seven paragraphs.<br>Choose the correct heading for each paragraph from the list of headings below.<br>Choose the correct number, i-ix, in boxes 14-20.</p>', 'matching_features', 'null', 'null', '{"layoutType": "heading", "summaryText": null, "answerOptions": [{"optionText": "i The theory linking capacity for tool use in birds and survival"}, {"optionText": "ii The influence of humans on tool use"}, {"optionText": "iii The theory linking cognitive ability and living in a society"}, {"optionText": "iv Reviewing long-held beliefs"}, {"optionText": "v Intelligence helps birds to remember"}, {"optionText": "vi How some birds trick each other"}, {"optionText": "vii Physiological evidence of birds’ intelligence"}, {"optionText": "viii Several examples of birds who use tools"}, {"optionText": "ix One species’ multiple tool-using techniques"}], "matchingItems": null}', 'null', '[{"content": "<p data-path-to-node=\"4\"><strong data-path-to-node=\"4\" data-index-in-node=\"0\">14. Paragraph 1 — {iv. Reviewing long-held beliefs}</strong></p>\n<ul data-path-to-node=\"5\">\n<li>\n<p data-path-to-node=\"5,0,0\"><strong data-path-to-node=\"5,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> <em data-path-to-node=\"5,0,0\" data-index-in-node=\"11\">\"For centuries, many scholars maintained that <strong data-path-to-node=\"5,0,0\" data-index-in-node=\"57\">humans were the only intelligent organism</strong>... However, exciting new research... has <strong data-path-to-node=\"5,0,0\" data-index-in-node=\"140\">called into question</strong> using uniqueness of these traits, <strong data-path-to-node=\"5,0,0\" data-index-in-node=\"195\">forcing us to reconsider this opinion</strong>.\"</em></p>\n</li>\n<li>\n<p data-path-to-node=\"5,1,0\"><strong data-path-to-node=\"5,1,0\" data-index-in-node=\"0\">Giải thích:</strong> \"Long-held beliefs\" chính là quan niệm cho rằng chỉ con người mới có trí thông minh. Việc nghiên cứu mới \"gọi tên\" và \"buộc chúng ta xem xét lại\" (reconsider) chính là hành động \"Reviewing\" (xem xét/đánh giá lại).</p>\n</li>\n</ul>\n<p data-path-to-node=\"6\"><strong data-path-to-node=\"6\" data-index-in-node=\"0\">15. Paragraph 2 — {viii. Several examples of birds who use tools}</strong></p>\n<ul data-path-to-node=\"7\">\n<li>\n<p data-path-to-node=\"7,0,0\"><strong data-path-to-node=\"7,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> <em data-path-to-node=\"7,0,0\" data-index-in-node=\"11\">\"At least <strong data-path-to-node=\"7,0,0\" data-index-in-node=\"21\">three Australian bird species</strong> make tools... <strong data-path-to-node=\"7,0,0\" data-index-in-node=\"65\">white-winged choughs</strong>... use rocks as hammers... <strong data-path-to-node=\"7,0,0\" data-index-in-node=\"113\">black kites</strong> have been reported dropping bait...\"</em></p>\n</li>\n<li>\n<p data-path-to-node=\"7,1,0\"><strong data-path-to-node=\"7,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Đoạn này liệt kê một loạt các ví dụ cụ thể về nhiều loài chim khác nhau (chim ở Úc, chough, diều hâu đen) sử dụng các loại công cụ khác nhau (đá, mồi nhử, cành củi đang cháy).</p>\n</li>\n</ul>\n<p data-path-to-node=\"8\"><strong data-path-to-node=\"8\" data-index-in-node=\"0\">16. Paragraph 3 — {i. The theory linking capacity for tool use in birds and survival}</strong></p>\n<ul data-path-to-node=\"9\">\n<li>\n<p data-path-to-node=\"9,0,0\"><strong data-path-to-node=\"9,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> <em data-path-to-node=\"9,0,0\" data-index-in-node=\"11\">\"...food... provide a clue as to how the mental abilities needed for tool use evolved... animals should have evolved only the necessary intellectual capabilities <strong data-path-to-node=\"9,0,0\" data-index-in-node=\"173\">required to overcome the challenges</strong> they face... only the <strong data-path-to-node=\"9,0,0\" data-index-in-node=\"231\">smartest in each generation will live and reproduce</strong>.\"</em></p>\n</li>\n<li>\n<p data-path-to-node=\"9,1,0\"><strong data-path-to-node=\"9,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Đoạn này giải thích mối liên hệ giữa trí thông minh và sự sinh tồn (survival). Những loài sống trong môi trường thách thức cần thông minh để tìm thức ăn, từ đó mới có thể sống sót và duy trì nòi giống.</p>\n</li>\n</ul>\n<p data-path-to-node=\"10\"><strong data-path-to-node=\"10\" data-index-in-node=\"0\">17. Paragraph 4 — {ix. One species’ multiple tool-using techniques}</strong></p>\n<ul data-path-to-node=\"11\">\n<li>\n<p data-path-to-node=\"11,0,0\"><strong data-path-to-node=\"11,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> <em data-path-to-node=\"11,0,0\" data-index-in-node=\"11\">\"<strong data-path-to-node=\"11,0,0\" data-index-in-node=\"12\">New Caledonian crows</strong> boast <strong data-path-to-node=\"11,0,0\" data-index-in-node=\"39\">many different tools</strong> in their tool kit. They use a <strong data-path-to-node=\"11,0,0\" data-index-in-node=\"90\">hooked tool</strong>... fashion <strong data-path-to-node=\"11,0,0\" data-index-in-node=\"113\">serrated rakes</strong>... also make <strong data-path-to-node=\"11,0,0\" data-index-in-node=\"141\">probes</strong>...\"</em></p>\n</li>\n<li>\n<p data-path-to-node=\"11,1,0\"><strong data-path-to-node=\"11,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Trái với đoạn 2 nói về nhiều loài, đoạn 4 chỉ tập trung vào <strong data-path-to-node=\"11,1,0\" data-index-in-node=\"72\">duy nhất một loài</strong> (New Caledonian crows) nhưng loài này lại có <strong data-path-to-node=\"11,1,0\" data-index-in-node=\"135\">nhiều kỹ thuật</strong> sử dụng công cụ khác nhau (móc, cào, que dò).</p>\n</li>\n</ul>\n<p data-path-to-node=\"12\"><strong data-path-to-node=\"12\" data-index-in-node=\"0\">18. Paragraph 5 — {vii. Physiological evidence of birds’ intelligence}</strong></p>\n<ul data-path-to-node=\"13\">\n<li>\n<p data-path-to-node=\"13,0,0\"><strong data-path-to-node=\"13,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> <em data-path-to-node=\"13,0,0\" data-index-in-node=\"11\">\"...compared the frequency and size of innovations with the <strong data-path-to-node=\"13,0,0\" data-index-in-node=\"71\">size of the birds’ forebrain</strong>... relative to the hindbrain. The team uncovered a clear relationship: birds with <strong data-path-to-node=\"13,0,0\" data-index-in-node=\"182\">relatively large forebrains</strong> are able to invent fresh solutions...\"</em></p>\n</li>\n<li>\n<p data-path-to-node=\"13,1,0\"><strong data-path-to-node=\"13,1,0\" data-index-in-node=\"0\">Giải thích:</strong> \"Physiological evidence\" (bằng chứng sinh lý) ở đây chính là cấu trúc và kích thước của não bộ (forebrain). Nghiên cứu chứng minh kích thước não có liên quan trực tiếp đến khả năng sáng tạo của chim.</p>\n</li>\n</ul>\n<p data-path-to-node=\"14\"><strong data-path-to-node=\"14\" data-index-in-node=\"0\">19. Paragraph 6 — {iii. The theory linking cognitive ability and living in a society}</strong></p>\n<ul data-path-to-node=\"15\">\n<li>\n<p data-path-to-node=\"15,0,0\"><strong data-path-to-node=\"15,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> <em data-path-to-node=\"15,0,0\" data-index-in-node=\"11\">\"Intelligence in birds may also arise as a result of selection to overcome the dynamic <strong data-path-to-node=\"15,0,0\" data-index-in-node=\"98\">challenges of communal living</strong>. Since this involves competition between <strong data-path-to-node=\"15,0,0\" data-index-in-node=\"169\">group members</strong>... the evolution of a distinctly <strong data-path-to-node=\"15,0,0\" data-index-in-node=\"216\">‘political’ brain</strong>.\"</em></p>\n</li>\n<li>\n<p data-path-to-node=\"15,1,0\"><strong data-path-to-node=\"15,1,0\" data-index-in-node=\"0\">Giải thích:</strong> \"Living in a society\" tương ứng với \"communal living\" hoặc \"group members\". Đoạn này giải thích trí thông minh tiến hóa để chim có thể tương tác và cạnh tranh trong đời sống bầy đàn.</p>\n</li>\n</ul>\n<p data-path-to-node=\"16\"><strong data-path-to-node=\"16\" data-index-in-node=\"0\">20. Paragraph 7 — {vi. How some birds trick each other}</strong></p>\n<ul data-path-to-node=\"17\">\n<li>\n<p data-path-to-node=\"17,0,0\"><strong data-path-to-node=\"17,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> <em data-path-to-node=\"17,0,0\" data-index-in-node=\"11\">\"What better way to exercise a political brain than to be <strong data-path-to-node=\"17,0,0\" data-index-in-node=\"69\">deceitful</strong>! ...young choughs often <strong data-path-to-node=\"17,0,0\" data-index-in-node=\"103\">act deceptively</strong>... place some food in the mouth of a hungry chick – but it <strong data-path-to-node=\"17,0,0\" data-index-in-node=\"178\">does not release the food</strong>... frantically start to preen the chicks as soon as some of its group members <strong data-path-to-node=\"17,0,0\" data-index-in-node=\"282\">come into view</strong>.\"</em></p>\n</li>\n<li>\n<p data-path-to-node=\"17,1,0\"><strong data-path-to-node=\"17,1,0\" data-index-in-node=\"0\">Giải thích:</strong> \"Trick each other\" (lừa dối nhau) chính là hành vi \"deceitful / deceptively\". Đoạn này mô tả cách chim chough giả vờ cho ăn hoặc giả vờ chăm sóc chim non để lấy lòng \"xã hội\" khi có kẻ khác đang quan sát.</p>\n</li>\n</ul>"}]', 0);
INSERT INTO public.questions VALUES ('cf23c5c5-f342-4da8-b96d-2776185dcfec', '7e23f2bf-3fdd-43ff-8618-7880c74514d0', 'matrix', 'Questions 21-26', NULL, '<p>Look at the following characteristics (Questions 21-26) and the list of birds below.</p>
<p>Match each characteristic with the correct bird, A, B, or C. Choose the correct letter, A, B, or C</p>
<p><em><strong>NB </strong>You may use any letter more than once.</em></p>', 'other', 'null', 'null', 'null', '{"layoutType": "standard", "legendTitle": "List off birds", "matrixItems": [{"itemText": "keeping tools that they like to use", "correctCategoryLetter": "C"}, {"itemText": "drawing out their prey by frightening it", "correctCategoryLetter": "B"}, {"itemText": "the use of tools to remove the outer covering from food", "correctCategoryLetter": "A"}, {"itemText": "using food to attract their prey", "correctCategoryLetter": "B"}, {"itemText": "the use of unfamiliar materials to make tools", "correctCategoryLetter": "C"}, {"itemText": "engaging in certain activities for the benefit of observers", "correctCategoryLetter": "A"}], "matrixCategories": [{"categoryText": "white-winged choughs", "categoryLetter": "A"}, {"categoryText": "black kites", "categoryLetter": "B"}, {"categoryText": "New Caledonian crows", "categoryLetter": "C"}]}', '[{"content": "<p data-path-to-node=\"4\"><strong data-path-to-node=\"4\" data-index-in-node=\"0\">21. Keeping tools that they like to use — {C. New Caledonian crows}</strong></p>\n<ul data-path-to-node=\"5\">\n<li>\n<p data-path-to-node=\"5,0,0\"><strong data-path-to-node=\"5,0,0\" data-index-in-node=\"0\">Dẫn chứng (Đoạn 4):</strong> <em data-path-to-node=\"5,0,0\" data-index-in-node=\"20\">\"The <strong data-path-to-node=\"5,0,0\" data-index-in-node=\"25\">crows carry their favourite tool</strong> from one foraging site to the next. They also <strong data-path-to-node=\"5,0,0\" data-index-in-node=\"104\">store their tools for later re-use</strong> in a secure place...\"</em></p>\n</li>\n<li>\n<p data-path-to-node=\"5,1,0\"><strong data-path-to-node=\"5,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Việc mang theo công cụ yêu thích và cất giữ chúng để dùng lại chính là hành động giữ lại công cụ (<strong data-path-to-node=\"5,1,0\" data-index-in-node=\"110\">keeping tools</strong>).</p>\n</li>\n</ul>\n<p data-path-to-node=\"6\"><strong data-path-to-node=\"6\" data-index-in-node=\"0\">22. Drawing out their prey by frightening it — {B. Black kites}</strong></p>\n<ul data-path-to-node=\"7\">\n<li>\n<p data-path-to-node=\"7,0,0\"><strong data-path-to-node=\"7,0,0\" data-index-in-node=\"0\">Dẫn chứng (Đoạn 2):</strong> <em data-path-to-node=\"7,0,0\" data-index-in-node=\"20\">\"A kite may also pick up a <strong data-path-to-node=\"7,0,0\" data-index-in-node=\"47\">smouldering stick</strong>... and drop the stick on a patch of unburned grass. The bird then feasts on the <strong data-path-to-node=\"7,0,0\" data-index-in-node=\"145\">small animals that flee from the subsequent fire</strong>.\"</em></p>\n</li>\n<li>\n<p data-path-to-node=\"7,1,0\"><strong data-path-to-node=\"7,1,0\" data-index-in-node=\"0\">Giải thích:</strong> \"Flee\" (tháo chạy/chạy trốn) đồng nghĩa với việc bị hoảng sợ (<strong data-path-to-node=\"7,1,0\" data-index-in-node=\"74\">frightening</strong>). Con diều hâu dùng lửa để làm con mồi sợ hãi và phải chạy ra khỏi chỗ ẩn nấp (drawing out).</p>\n</li>\n</ul>\n<p data-path-to-node=\"8\"><strong data-path-to-node=\"8\" data-index-in-node=\"0\">23. The use of tools to remove the outer covering from food — {A. Woodpecker finches}</strong></p>\n<ul data-path-to-node=\"9\">\n<li>\n<p data-path-to-node=\"9,0,0\"><strong data-path-to-node=\"9,0,0\" data-index-in-node=\"0\">Dẫn chứng (Đoạn 1):</strong> <em data-path-to-node=\"9,0,0\" data-index-in-node=\"20\">\"These tiny birds [woodpecker finches] routinely used <strong data-path-to-node=\"9,0,0\" data-index-in-node=\"74\">twigs to extract grubs from under bark</strong>.\"</em></p>\n</li>\n<li>\n<p data-path-to-node=\"9,1,0\"><strong data-path-to-node=\"9,1,0\" data-index-in-node=\"0\">Giải thích:</strong> \"Bark\" (vỏ cây) chính là lớp bao phủ bên ngoài (<strong data-path-to-node=\"9,1,0\" data-index-in-node=\"60\">outer covering</strong>) của nguồn thức ăn (con ấu trùng).</p>\n</li>\n</ul>\n<p data-path-to-node=\"10\"><strong data-path-to-node=\"10\" data-index-in-node=\"0\">24. Using food to attract their prey — {B. Black kites}</strong></p>\n<ul data-path-to-node=\"11\">\n<li>\n<p data-path-to-node=\"11,0,0\"><strong data-path-to-node=\"11,0,0\" data-index-in-node=\"0\">Dẫn chứng (Đoạn 2):</strong> <em data-path-to-node=\"11,0,0\" data-index-in-node=\"20\">\"For example, <strong data-path-to-node=\"11,0,0\" data-index-in-node=\"34\">black kites</strong> have been reported <strong data-path-to-node=\"11,0,0\" data-index-in-node=\"65\">dropping bait</strong> into lakes to bring fish to the surface of the water...\"</em></p>\n</li>\n<li>\n<p data-path-to-node=\"11,1,0\"><strong data-path-to-node=\"11,1,0\" data-index-in-node=\"0\">Giải thích:</strong> \"Bait\" (mồi nhử - thường là thức ăn) được dùng để thu hút (<strong data-path-to-node=\"11,1,0\" data-index-in-node=\"71\">attract</strong>) con mồi (cá) nổi lên mặt nước.</p>\n</li>\n</ul>\n<p data-path-to-node=\"12\"><strong data-path-to-node=\"12\" data-index-in-node=\"0\">25. The use of unfamiliar materials to make tools — {C. New Caledonian crows}</strong></p>\n<ul data-path-to-node=\"13\">\n<li>\n<p data-path-to-node=\"13,0,0\"><strong data-path-to-node=\"13,0,0\" data-index-in-node=\"0\">Dẫn chứng (Đoạn 4):</strong> <em data-path-to-node=\"13,0,0\" data-index-in-node=\"20\">\"Recently, <strong data-path-to-node=\"13,0,0\" data-index-in-node=\"31\">New Caledonian crows</strong> were observed moulding a <strong data-path-to-node=\"13,0,0\" data-index-in-node=\"77\">piece of wire</strong>, something they had <strong data-path-to-node=\"13,0,0\" data-index-in-node=\"111\">never seen before</strong>, into a hook...\"</em></p>\n</li>\n<li>\n<p data-path-to-node=\"13,1,0\"><strong data-path-to-node=\"13,1,0\" data-index-in-node=\"0\">Giải thích:</strong> \"Unfamiliar materials\" (nguyên liệu lạ) chính là đoạn dây thép (wire) mà loài chim này chưa từng nhìn thấy trước đó.</p>\n</li>\n</ul>\n<p data-path-to-node=\"14\"><strong data-path-to-node=\"14\" data-index-in-node=\"0\">26. Engaging in certain activities for the benefit of observers — {A White-winged choughs}</strong></p>\n<ul data-path-to-node=\"16\">\n<li>\n<p data-path-to-node=\"16,0,0\"><strong data-path-to-node=\"16,0,0\" data-index-in-node=\"0\">Dẫn chứng (Đoạn 7):</strong> <em data-path-to-node=\"16,0,0\" data-index-in-node=\"20\">\"Interestingly, it is <strong data-path-to-node=\"16,0,0\" data-index-in-node=\"42\">more likely to preen the chicks if another bird can see it do so</strong>... frantically start to preen the chicks as soon as some of its <strong data-path-to-node=\"16,0,0\" data-index-in-node=\"171\">group members come into view</strong>.\"</em></p>\n</li>\n<li>\n<p data-path-to-node=\"16,1,0\"><strong data-path-to-node=\"16,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Loài chim này chỉ nhiệt tình rỉa lông cho chim non khi có thành viên khác trong đàn quan sát (<strong data-path-to-node=\"16,1,0\" data-index-in-node=\"106\">observers</strong>), nhằm mục đích giữ gìn vị thế xã hội.</p>\n</li>\n</ul>"}]', 1);
